-- Poems batch 236
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('48047f79-62be-4589-9584-4c065d2afecc','月窗','釋妙倫','宋','宋诗','song-poetry','','[]','曲曲彎彎地，明明白白中。',24,'全唐诗/poet.song.215000.json','["曲曲彎彎地，明明白白中。", "當軒開闔處，一隔爲誰通。"]'),
('184a6134-60eb-453b-9e94-d38244e28839','寄人','釋妙倫','宋','宋诗','song-poetry','','[]','去年共遶澗濱行，話盡山雲海月情。',32,'全唐诗/poet.song.215000.json','["去年共遶澗濱行，話盡山雲海月情。", "芳樹幽禽尤記得，風前時作兩三聲。"]'),
('fa6f1469-a881-4af4-a7b2-e126773fcc8a','示舜上人','釋妙倫','宋','宋诗','song-poetry','','[]','古鏡未磨黑似漆，及乎磨後也模糊。',32,'全唐诗/poet.song.215000.json','["古鏡未磨黑似漆，及乎磨後也模糊。", "忽然打作百雜碎，笑倒當年舜老夫。"]'),
('eec29944-8fe8-46b1-a06d-50f38a950592','斷溪','釋妙倫','宋','宋诗','song-poetry','','[]','絕消息時消息，不流通處流通。',28,'全唐诗/poet.song.215000.json','["絕消息時消息，不流通處流通。", "未達曹源淵奧，依然兩段不同。"]'),
('555f66b4-1c7b-4de6-b272-d80bb7655462','夢菴相士','釋妙倫','宋','宋诗','song-poetry','','[]','煙霞影裏蒼苔面，山水光埋古柏身。',32,'全唐诗/poet.song.215000.json','["煙霞影裏蒼苔面，山水光埋古柏身。", "爲報夢菴休諸夢，老僧不是夢中人。"]'),
('0359854a-cbc1-4494-b1ea-6c3ad8e37892','頌古五首  其一','釋妙倫','宋','宋诗','song-poetry','','[]','狗走抖擻口，猴愁摟搜頭。',24,'全唐诗/poet.song.215000.json','["狗走抖擻口，猴愁摟搜頭。", "瑞巖門外水，自古向西流。"]'),
('c8aadd16-5af4-438e-aeb4-0853a39a7d4c','頌古五首  其二','釋妙倫','宋','宋诗','song-poetry','','[]','趙老七斤衫，提來用恰好。',24,'全唐诗/poet.song.215000.json','["趙老七斤衫，提來用恰好。", "若更問如何，且去青州討。"]'),
('56163ac7-1697-4a33-8349-2e7185b96d71','頌古五首  其三','釋妙倫','宋','宋诗','song-poetry','','[]','草舍柴門僻更幽，何期過客也經由。',32,'全唐诗/poet.song.215000.json','["草舍柴門僻更幽，何期過客也經由。", "蒿湯備禮不知愧，猶對傍人賣口頭。"]'),
('fdc3e8f1-e39a-41ea-93f7-c73dd9894bdc','頌古五首  其四','釋妙倫','宋','宋诗','song-poetry','','[]','前頭計較既不成，後面安排亦不是。',32,'全唐诗/poet.song.215000.json','["前頭計較既不成，後面安排亦不是。", "古時若有今時人，不落他家圈裏。"]'),
('1d223ba0-6b1c-4e31-a0aa-088c547a6e55','頌古五首  其五','釋妙倫','宋','宋诗','song-poetry','','[]','樹動風摇，塵生雲起。',20,'全唐诗/poet.song.215000.json','["樹動風摇，塵生雲起。", "太上老君，何曾姓李。"]'),
('9ce9d911-a22a-484f-a18e-c5fcc9c3cda1','疏山  其一','趙時煥','宋','宋诗','song-poetry','','[]','兩到臨川愧罔功，只憑心事對蒼穹。',32,'全唐诗/poet.song.215000.json','["兩到臨川愧罔功，只憑心事對蒼穹。", "江鄉又喜今年熟，一笑歸田作好冬。"]'),
('7a7e3afa-db33-4d77-bcdc-4be189509318','疏山  其二','趙時煥','宋','宋诗','song-poetry','','[]','重訪招提恰六年，松風蘿月故依然。',32,'全唐诗/poet.song.215000.json','["重訪招提恰六年，松風蘿月故依然。", "世間萬事都休問，燕坐看山是好禪。"]'),
('4c65ccd3-5af3-426b-917b-6c54dc7ba1f8','梅','趙時煥','宋','宋诗','song-poetry','','[]','梅龍閲世今幾春，皮毛剝破生蒼鱗。',64,'全唐诗/poet.song.215000.json','["梅龍閲世今幾春，皮毛剝破生蒼鱗。", "通身苔蘚雲氣濕，恰如初蛻離海濱。", "蜿蜒恍惚露半腹，花光補之難貌真。", "祇恐天上行雨去，呼吸風雷驚世人。"]'),
('1aaabbaf-5fbb-470f-bf94-5d0f7884b1ad','九日山送客','趙時煥','宋','宋诗','song-poetry','','[]','頻來因送客，携酒訪仙靈。',48,'全唐诗/poet.song.215000.json','["頻來因送客，携酒訪仙靈。", "歸去成何事，重來媿此亭。", "天寬野水白，松潤石崖青。", "倚杖思今古，寒鷗落遠汀。"]'),
('e193d2f6-e44c-4699-990c-01c8fabb16fb','題汪水雲詩卷','葉福孫','宋','宋诗','song-poetry','','[]','今雨水雲來訪我，西窗剪燭話遼東。',64,'全唐诗/poet.song.215000.json','["今雨水雲來訪我，西窗剪燭話遼東。", "百千萬事擲天外，一十四年如夢中。", "琴到拙時方得趣，酒於愁處恰收功。", "明朝又掛孤帆去，江海茫茫正北風。"]'),
('43a0e558-51cc-490d-b856-9fa7457fb9f0','金雞石','楊起莘','宋','宋诗','song-poetry','','[]','千年古石號金雞，化雨霏霏長羽儀。',64,'全唐诗/poet.song.215000.json','["千年古石號金雞，化雨霏霏長羽儀。", "不把稻粱爲食啄，且將天地作籠棲。", "祥雲架上非孤立，入曉聲中豈亂啼。", "過客莫同凡鳥看，等閒飛到鳳凰池。"]'),
('ce48bb4b-1043-4477-a23d-840c711aa3b2','惠政橋','孫應鳳','宋','宋诗','song-poetry','','[]','百仞崖邊有此橋，地平路穩玉驄驕。',32,'全唐诗/poet.song.215000.json','["百仞崖邊有此橋，地平路穩玉驄驕。", "惠而知政今如此，拈起橋名問國僑。"]'),
('088f5e08-159c-4d97-815e-2a14e91eb0c1','雙桂橋','孫應鳳','宋','宋诗','song-poetry','','[]','橋前巧匠剪春羅，橋上亭亭景物和。',32,'全唐诗/poet.song.215000.json','["橋前巧匠剪春羅，橋上亭亭景物和。", "明夜元宵一團玉，連波還解似金波。"]'),
('ecd14e0f-c57e-4439-836e-d076bd5abc86','奬溪橋','孫應鳳','宋','宋诗','song-poetry','','[]','夕照斜陽柳外鴉，杏園衰謝野人家。',32,'全唐诗/poet.song.215000.json','["夕照斜陽柳外鴉，杏園衰謝野人家。", "欲尋春色無尋處，盡在橋邊野草花。"]'),
('df5a5cb5-2f85-4330-9dee-efc13adc98a4','虎巖紀遊','孫應鳳','宋','宋诗','song-poetry','','[]','月出山越高，雲行月益忙。',168,'全唐诗/poet.song.215000.json','["月出山越高，雲行月益忙。", "樹影遍空白，疎星避月光。", "總非往者見，不從意內量。", "聰明此一進，境界因久忘。", "深坐庭露淹，山僧促迴廊。", "鼓鐘奏天樂，經行重山堂。", "暮楫動朝梵，初日升屋梁。", "佛心光見日，林暉洞八方。", "細雨霏日中，飛煙青逐黄。", "出門遶山逕，兩道夾修篁。", "茗根千百个，却於山隈藏。", "徑深見奇巘，云與戴雲望。", "因之曳竹杖，集伴凌高岡。", "他年記此際，風花带天香。"]'),
('5b6bcade-5e73-4270-9c6e-8c8f16d58541','西塔','孫應鳳','宋','宋诗','song-poetry','','[]','憶昨慈恩登絕頂，今朝眼界更分明。',64,'全唐诗/poet.song.215000.json','["憶昨慈恩登絕頂，今朝眼界更分明。", "飛簷高瀉銀河水，隔岸遥傳寶鐸聲。", "翥鳳呈輝看欲下，潯龍露角望尤勍。", "凌風好向蓬萊去，一片香雲繞足生。"]'),
('66afb5e1-7d6d-4efb-976e-9981b6417824','寶藏寺洪鐘','孫應鳳','宋','宋诗','song-poetry','','[]','枕畔鍧然寶藏鐘，聲從何處入高墉。',32,'全唐诗/poet.song.215000.json','["枕畔鍧然寶藏鐘，聲從何處入高墉。", "蜀顱衰臂今如許，喚起穹廬一卧龍。"]'),
('e710af38-9798-4f06-80a0-75623b9f9f1a','玉虛宮隠真堂','趙瑞','宋','宋诗','song-poetry','','[]','劉公到處留遺跡，奇絕惟茲獨擅名。',64,'全唐诗/poet.song.215000.json','["劉公到處留遺跡，奇絕惟茲獨擅名。", "禪石無塵床穩卧，神丹有驗井還清。", "岡巒四合如環繞，石笋孤高類削成。", "瑶草常春鶴不駐，松風猶似步虛聲。"]'),
('6b9ef88a-e0a3-413f-9f5f-131c0ade03eb','游黄龍寺','趙瑞','宋','宋诗','song-poetry','','[]','一到黄龍萬慮灰，豪吟勝賞喜追陪。',64,'全唐诗/poet.song.215000.json','["一到黄龍萬慮灰，豪吟勝賞喜追陪。", "幽蘭獨秀花香襲，宿雨初收霧氣開。", "湛湛冰池藏世界，悠悠梵唄隔塵埃。", "清風明月無人管，付與縱橫石上苔。"]'),
('8b604d35-1843-43ee-96f4-504d5447a1f2','贈儒僧空谷二首  其一','汪立信','宋','宋诗','song-poetry','','[]','三十年前一秀才，而今面目現如來。',64,'全唐诗/poet.song.215000.json','["三十年前一秀才，而今面目現如來。", "元知三教本無異，走入千山喚不回。", "僧衲西風囊有錦，禪心明月鏡無臺。", "我聞空谷脊梁硬，多得名流青眼開。"]'),
('4ad608a6-075e-4fc5-a829-80dbad15590d','贈儒僧空谷二首  其二','汪立信','宋','宋诗','song-poetry','','[]','當今天子尊儒宿，何事幽人在空谷。',112,'全唐诗/poet.song.215000.json','["當今天子尊儒宿，何事幽人在空谷。", "子衿不復戀黌宮，禪衲惟其老巖屋。", "菜根脫粟供其飱，野鶴孤猿爲之侶。", "衣冠當代多英賢，羽翮皆欲摩蒼天。", "名韁利鎖祗自役，蕭散何似林中仙。", "榘山詩卷仁齋書，知音僂指皆名儒。", "千峰頂上牢立脚，清風端可廉頑夫。"]'),
('2c523926-9b3d-4634-997f-2ebded71936c','金陵懷古','汪立信','宋','宋诗','song-poetry','','[]','勝地尚存龍虎氣，荒臺已失鳳凰蹤。',32,'全唐诗/poet.song.215000.json','["勝地尚存龍虎氣，荒臺已失鳳凰蹤。", "六朝文物山川古，霸氣終歸指顧中。"]'),
('6d50f365-4d35-4584-87bd-5a7d68d53082','朝宗門','石祖文','宋','宋诗','song-poetry','','[]','樓閣崢嶸古壘門，日隨潮汐謹晨昏。',64,'全唐诗/poet.song.215000.json','["樓閣崢嶸古壘門，日隨潮汐謹晨昏。", "奠川禹績勤溝洫，學海雄詞識本源。", "演迆衆流唯北拱，委蛇萬折肯西奔。", "時人有問朝宗義，落筆詩成不待言。"]'),
('6789cd2c-af89-41d3-b28f-46525f3079cc','季子廟','石祖文','宋','宋诗','song-poetry','','[]','夫子南遊不到吳，殷勤題識寄嗟吁。',32,'全唐诗/poet.song.215000.json','["夫子南遊不到吳，殷勤題識寄嗟吁。", "干戈擾擾憐諸夏，季子流風過耳無。"]'),
('3abb2f9f-9c20-431b-8377-40d64476ac25','君山','石祖文','宋','宋诗','song-poetry','','[]','遠邇朝宗勢拱辰，名高豈特爲春申。',64,'全唐诗/poet.song.215000.json','["遠邇朝宗勢拱辰，名高豈特爲春申。", "孤峰堆阜無多地，一水仙凡隔幾塵。", "簪履三千誰念楚，山河百二漫誇秦。", "雲烟勝概無今古，俯仰休悲迹已陳。"]'),
('1fcc2a09-0d0b-49be-9a87-73b5d1027527','春波亭','陳旼','宋','宋诗','song-poetry','','[]','翼然溪滸一亭新，瀲灧波光巧樣春。',64,'全唐诗/poet.song.215000.json','["翼然溪滸一亭新，瀲灧波光巧樣春。", "一舸月明魚射宿，數帆風飽客知津。", "沙侵鶩磧猶含潤，花點魚叉不受塵。", "莫聽陽關始拚醉，好將酩酊付芳辰。"]'),
('e918acbf-faf9-4c59-aa85-0a0cc20fc3bb','淳祐甲辰三月中澣奉詔經略同客張景東馮雲從男公闡公閶游乳洞紀事','謝逵','宋','宋诗','song-poetry','','[]','尋幽天氣得晴酣，小小籃輿勝繡鞍。',64,'全唐诗/poet.song.215000.json','["尋幽天氣得晴酣，小小籃輿勝繡鞍。", "洞以乳名雲液湧，泉紆石出水晶寒。", "山容染翠開油幕，竹韻鳴竽立玉竿。", "孰謂地靈鍾秀異，美哉風物見興安。"]'),
('4cf8e6ff-aa13-4447-8434-5840e9c22f6d','海鹽鹿苑寺','聞人宇','宋','宋诗','song-poetry','','[]','郡邑相望路半停，屹然香剎聳林坰。',64,'全唐诗/poet.song.215000.json','["郡邑相望路半停，屹然香剎聳林坰。", "罷參釋子忘情久，應供胡僧入夢靈。", "東去無情波繚繞，西來有意柏葱青。", "定知俗駕經過少，月上松扉不用扃。"]'),
('8b637b74-2914-4bca-95a1-29f992d62521','遊澹巖偶得二絕  其一','袁鎮','宋','宋诗','song-poetry','','[]','誰道靈仙擘不開，天然瓊室與瑶臺。',32,'全唐诗/poet.song.215000.json','["誰道靈仙擘不開，天然瓊室與瑶臺。", "涪翁句重曾相識，料想烟霞許我來。"]'),
('25fdacfe-3699-4314-8d17-463219be4217','遊澹巖偶得二絕  其二','袁鎮','宋','宋诗','song-poetry','','[]','石門定與玉京連，曾著方壺不老仙。',32,'全唐诗/poet.song.215000.json','["石門定與玉京連，曾著方壺不老仙。", "猶有當年丹竈在，空岩寂寂鎖寒烟。"]'),
('597904d8-65b4-4cc4-91eb-c6baba7b404a','春暮','趙希逢','宋','宋诗','song-poetry','','[]','路入清溪一带橋，滿汀紅紫半零凋。',64,'全唐诗/poet.song.215000.json','["路入清溪一带橋，滿汀紅紫半零凋。", "數峰髧鬌山堆髻，百態妖嬈柳颭腰。", "聯轡踏花嘶寶馬，當壚換酒解金貂。", "堂堂無計留春住，望斷天涯去路迢。"]'),
('6d8ad766-615c-464c-8c3e-6394bb7834e3','初夏','趙希逢','宋','宋诗','song-poetry','','[]','綠暗紅稀四月天，榆錢鋪徑撒青氈。',64,'全唐诗/poet.song.215000.json','["綠暗紅稀四月天，榆錢鋪徑撒青氈。", "雨肥渴動羹梅興，風暖香傳餠麥鮮。", "解慍更無琴可續，納凉徒有句堪聯。", "看看河朔相追逐，避暑忘形到酒邊。"]'),
('2064af71-c418-4f8d-a05e-661c0c030355','秋','趙希逢','宋','宋诗','song-poetry','','[]','千林摇落竅號風，怒激秋濤氣勢雄。',32,'全唐诗/poet.song.215000.json','["千林摇落竅號風，怒激秋濤氣勢雄。", "遠水兼天拖練白，曉風委地染丹紅。"]'),
('4904e15e-5e25-4319-a757-a26bc5aa6d52','九日舟中','趙希逢','宋','宋诗','song-poetry','','[]','倦客逢萸節，生涯寄葉舟。',48,'全唐诗/poet.song.215000.json','["倦客逢萸節，生涯寄葉舟。", "窮途危不顧，飛棹去難留。", "舊菊重陽日，寒蘆兩岸秋。", "多情惟破帽，猶戀老人頭。"]'),
('2af953e4-6683-486e-bd9c-21e6806edcb3','暑','趙希逢','宋','宋诗','song-poetry','','[]','强學劉叉賦雪車，更陪河朔飲流霞。',32,'全唐诗/poet.song.215000.json','["强學劉叉賦雪車，更陪河朔飲流霞。", "漱泉枕石閑終日，滿口水晶寒嚼瓜。"]'),
('71293faa-467b-4af4-bd1e-09f16f7cdc2b','書堂遇雨','趙希逢','宋','宋诗','song-poetry','','[]','急風吹不散，膚寸起雲層。',48,'全唐诗/poet.song.215000.json','["急風吹不散，膚寸起雲層。", "覆手檐如瀉，寒心霤莫承。", "雷轟天上鼓，電掣眼前燈。", "掩卷興深省，書聲息口滕。"]'),
('af962634-a9c8-483f-9833-5b0d89738d32','雪','趙希逢','宋','宋诗','song-poetry','','[]','雲雪商量未了天，模糊遠近色相兼。',64,'全唐诗/poet.song.215000.json','["雲雪商量未了天，模糊遠近色相兼。", "白呵凍手拈詩筆，青向誰家認酒帘。", "散亂飛花刀旋剪，須臾平地尺誰添。", "也知表沴並呈瑞，深淺階前自可占。"]'),
('e6481d51-fc68-48fd-aac7-03aede7a8068','江樓','趙希逢','宋','宋诗','song-poetry','','[]','一带江流接太虛，危樓特地幻荒蕪。',64,'全唐诗/poet.song.215000.json','["一带江流接太虛，危樓特地幻荒蕪。", "移來瀛丈三山勝，畫出瀟湘八景圖。", "何處歸帆隨倦鳥，滿汀落日照晴鳬。", "須臾得月添佳致，萬頃寒冰浸玉壺。"]'),
('c1b1dbab-3f95-47e4-b4e2-e7caa83d0ab1','子規','趙希逢','宋','宋诗','song-poetry','','[]','鶑聲日沸笙歌奏，富貴春光別一家。',32,'全唐诗/poet.song.215000.json','["鶑聲日沸笙歌奏，富貴春光別一家。", "惟有不如歸去好，夜深和月在梨花。"]'),
('51514b09-7aa8-47b2-8503-89fb7e17451d','和容膝','趙希逢','宋','宋诗','song-poetry','','[]','□□□常裕，看書日易消。',48,'全唐诗/poet.song.215000.json','["□□□常裕，看書日易消。", "乾坤同廣大，風雨任飄摇。", "坐□□穿榻，安然免折腰。", "奴顔羞俗輩，華屋插雲遥。"]'),
('d15b3d98-3f4b-4213-94da-72b96b4debc3','和頭巾','趙希逢','宋','宋诗','song-poetry','','[]','休言抱道更懷才，大叫天門雲欲排。',32,'全唐诗/poet.song.215000.json','["休言抱道更懷才，大叫天門雲欲排。", "獨自一冠猶屢變，事幾何以禦方來。"]'),
('b61ade1d-d6f6-45e7-98ac-42adb2227ce2','和紙帳','趙希逢','宋','宋诗','song-poetry','','[]','擬回暖律到寒襟，落價休論直幾緡。',64,'全唐诗/poet.song.215000.json','["擬回暖律到寒襟，落價休論直幾緡。", "已喚楮生同一榻，肯容小女動纖塵。", "窗橫梅影眠和月，路入梨雲夢著人。", "欲效負暄獻天子，暖烘烘地一籠春。"]'),
('0c894dae-0502-461b-b2dc-d11e40369ea4','和紙衾','趙希逢','宋','宋诗','song-poetry','','[]','楮縑瀉出穀紋花，全幅如拋織女梭。',64,'全唐诗/poet.song.215000.json','["楮縑瀉出穀紋花，全幅如拋織女梭。", "春向臘前回孟季，寒催暑往任羲娥。", "洛中曾記紙增價，枕上想無詩作魔。", "任待凍雲天欲雪，蒙頭不信得知麽。"]'),
('829fe201-def4-4a2f-b0e9-ac0581750fe1','和早春楮衾','趙希逢','宋','宋诗','song-poetry','','[]','楮衾重蓋得春多，貴習都忘紈與羅。',32,'全唐诗/poet.song.215000.json','["楮衾重蓋得春多，貴習都忘紈與羅。", "一枕雷聲齁鼻息，想應夢不到嬌娥。"]'),
('01e36301-ed73-4147-ae12-a5cde7697da0','和鄰女搔綿吟','趙希逢','宋','宋诗','song-poetry','','[]','門外數聲風動竹，知是客來憇輿輻。',160,'全唐诗/poet.song.215000.json','["門外數聲風動竹，知是客來憇輿輻。", "嫣然一笑爲誰開，眼前喜見人如玉。", "奚奴側背□錦囊，共看嬌容理蟹筐。", "可堪清曉正凝霜，冰筯入手生寒芒。", "襪塵微動繅車索，三尺龍孫橫左握。", "初方一縷漸如綸，衮衮不斷巧綿絡。", "沿淮土曠人更稀，未冬寒風已透幃。", "閑田不種木棉樹，卒歲可憐無褐衣。", "嶺南彌望無處著，堪與梨雲同寞寞。", "收來比屋機杼鳴，誰復號寒嘆落魄。"]'),
('4f4bc94b-be0a-4c72-9c5f-6c5933bcec28','和酒歌','趙希逢','宋','宋诗','song-poetry','','[]','安得鏡湖分一曲，寧可不受千鍾祿。',192,'全唐诗/poet.song.215000.json','["安得鏡湖分一曲，寧可不受千鍾祿。", "百年三萬六千場，認取醉鄉去路熟。", "猖狂莫學少年時，身心早已偃鼓旗。", "速營糟丘防老境，無行不與酒相隨。", "忘形孰主又孰客，江上清風山間月。", "把杯對影又即吾，我與風月難一闕。", "興來更涉小小園，壺中勝賞真有天。", "酒池不怕深似海，探春日日掉𦨻舡。", "愁腸任待紛千縷，一醉不知手欲舞。", "轉悲成歡瞬息間，功用神聖捷如許。", "困來不管玉頹山，只恐朝酲欲析難。", "憑虛直向崑崙上，坐看驚濤飛去帆。"]'),
('a2ad6a3c-f70a-47c9-8ea6-d69421b26a57','和謝仵判院惠米','趙希逢','宋','宋诗','song-poetry','','[]','憂辱都非言行招，孤忠自莫勝群囂。',64,'全唐诗/poet.song.215000.json','["憂辱都非言行招，孤忠自莫勝群囂。", "已甘逆旅長糊口，無復有言能副腰。", "一士豈無關國論，九重亦合採民謠。", "莫教流落江湖上，笑酌天漿獨舉瓢。"]'),
('484b5ab3-eb78-4793-a971-c8219c76fa79','和酒禁','趙希逢','宋','宋诗','song-poetry','','[]','井田未壞軍民一，去古堪嗟此意衰。',32,'全唐诗/poet.song.215000.json','["井田未壞軍民一，去古堪嗟此意衰。", "守望扶持無復有，一杯也自立藩籬。"]'),
('2e2996f3-6ea1-433e-b644-ff0b40bebb4e','和酒醒','趙希逢','宋','宋诗','song-poetry','','[]','溫柔鄉裏喚春回，低唱樽前肉作臺。',32,'全唐诗/poet.song.215000.json','["溫柔鄉裏喚春回，低唱樽前肉作臺。", "判取明朝都醉殺，解酲一笑有人開。"]'),
('b12e119f-924a-4726-bd5c-11d7dbb91f74','和拜茶','趙希逢','宋','宋诗','song-poetry','','[]','地靈分異産，人力果何功。',48,'全唐诗/poet.song.215000.json','["地靈分異産，人力果何功。", "護想森神物，餘應處下風。", "葉初緘嫩綠，色敢带昏紅。", "珍重春前雪，殷勤奉帝宮。"]'),
('9067bf8e-0d3d-4b3e-bbbb-b6375dd1fa1f','和思故人  其一','趙希逢','宋','宋诗','song-poetry','','[]','蹤跡江湖任所之，雄文到處寫明璣。',64,'全唐诗/poet.song.215000.json','["蹤跡江湖任所之，雄文到處寫明璣。", "詩書未得一兒用，豪傑空令衆譽歸。", "千里雲山飛不到，寸心日夜𢛼如饑。", "幾番清夢隨蝴蝶，一覺回來又已非。"]'),
('55399395-32e5-4ce8-ab2c-726f17df8c99','和思故人  其二','趙希逢','宋','宋诗','song-poetry','','[]','握手論懷屢合并，自居謫籍玷時名。',64,'全唐诗/poet.song.215000.json','["握手論懷屢合并，自居謫籍玷時名。", "剡溪無路訪安道，北海何人知子卿。", "千里憑詩馳意馬，一樽頼酒破愁城。", "秋風若有南來鴈，未忘故人煩寄聲。"]'),
('c86d8593-e4f5-4a0d-ad1f-ee7f23982281','和憶弟妹','趙希逢','宋','宋诗','song-poetry','','[]','行行吊影建溪南，舉眼何人共急難。',64,'全唐诗/poet.song.215000.json','["行行吊影建溪南，舉眼何人共急難。", "同氣蜂飛緣蜜剖，群姦蚋聚爲醯酸。", "荆山那得枝長合，豆泣堪傷肉自剜。", "杜老固知懷弟妹，醉愁想更憶長安。"]'),
('aae8737a-ad24-4b23-836c-1638af45f6cd','和不禱','趙希逢','宋','宋诗','song-poetry','','[]','艱難險阻謾曾經，有惠終輸有福人。',64,'全唐诗/poet.song.215000.json','["艱難險阻謾曾經，有惠終輸有福人。", "邈爾大鈞休致問，澹然方寸自能神。", "早知造物難僥倖，何似虛懷任屈伸。", "但看四時周復始，幾曾雪後不回春。"]'),
('66673bb9-2807-4c9c-b88b-5221a6608d2b','和青樓贈別','趙希逢','宋','宋诗','song-poetry','','[]','憑高座久漸生寒，遠水明樓夜正殘。',32,'全唐诗/poet.song.215000.json','["憑高座久漸生寒，遠水明樓夜正殘。", "月色照人人似月，倚欄一曲爲誰彈。"]'),
('5695f3b5-74f8-45b4-a66c-bc0b50dceb1e','和寄盧進士','趙希逢','宋','宋诗','song-poetry','','[]','珊瑚文采爛銀鈎，挾策相期汗漫遊。',64,'全唐诗/poet.song.215000.json','["珊瑚文采爛銀鈎，挾策相期汗漫遊。", "世路商盤更周誥，旅亭楚尾望吳頭。", "新詩聊寫別來况，過鴈俄驚客裏秋。", "魂夢也知飛不到，夜長贏得數更籌。"]'),
('6e192728-57da-4f42-a90f-a922e18f1b75','和寄大庚郭縣尉','趙希逢','宋','宋诗','song-poetry','','[]','纏腰跨飛鶴，不須上揚州。',288,'全唐诗/poet.song.215000.json','["纏腰跨飛鶴，不須上揚州。", "直欲摶扶摇，相從汗漫遊。", "得意廣寒宮，闊步玉京樓。", "迤邐叫閶闔，借階獻前籌。", "騏驥千里志，縻首成淹留。", "少年燈火眼，眵昏歲幾周。", "漢庭賒策對，唐匭空書投。", "抗言不畏避，視死等嬉遊。", "想應初墮地，早已氣食牛。", "慨然大勇聞，肯以小怯羞。", "一第真分內，談笑期封侯。", "可惜剛比鐵，不能曲如鈎。", "轉喉成觸諱，身作治世囚。", "禍福若自取，行止非人由。", "飄零靡底定，蹤跡萍梗猶。", "雖然遇坎止，未始隨波流。", "相看得同志，有酒共解憂。", "議論發耿耿，正誼不利謀。", "仕路幾閲人，來往一置郵。", "直須早回首，誰能沉復浮。", "管見頗自是，君其首肯不。", "江上與山間，風月無人收。", "不妨爲管領，巾車更孤舟。", "但得免憂辱，外此復何求。"]'),
('006e75d0-3804-4668-b084-1212e0f43053','和寄仵判院八首  其一','趙希逢','宋','宋诗','song-poetry','','[]','望君如在碧雲間，逸駕飄飄不可攀。',32,'全唐诗/poet.song.215000.json','["望君如在碧雲間，逸駕飄飄不可攀。", "何日得陪雞犬去，仙泉好共飲丹蠻。"]'),
('b250b165-f7ef-436d-95ee-0b07a742791a','和寄仵判院八首  其二','趙希逢','宋','宋诗','song-poetry','','[]','便教老眼怎昏花，書債如何也不賒。',32,'全唐诗/poet.song.215000.json','["便教老眼怎昏花，書債如何也不賒。", "更有一般春枕夢，合眸便到故人家。"]'),
('d44795ac-2c75-4581-94c0-7a5ddff55e0e','和寄仵判院八首  其三','趙希逢','宋','宋诗','song-poetry','','[]','寶笈瓊函世不傳，感君重諾訂金千。',32,'全唐诗/poet.song.215000.json','["寶笈瓊函世不傳，感君重諾訂金千。", "相應未值南來鴈，謂戲前言斷不然。"]'),
('0dbb1b3f-51e9-4300-bc47-e312c4460b08','和寄仵判院八首  其四','趙希逢','宋','宋诗','song-poetry','','[]','古壁傷情憶舊題，連天芳草望空迷。',32,'全唐诗/poet.song.215000.json','["古壁傷情憶舊題，連天芳草望空迷。", "沉吟此意向誰說，合盡碧雲日又西。"]'),
('2bc39d6a-24f7-4a85-90ef-4eaf6269d350','和寄仵判院八首  其五','趙希逢','宋','宋诗','song-poetry','','[]','發於事業見於詞，君昔相期舍我誰。',32,'全唐诗/poet.song.215000.json','["發於事業見於詞，君昔相期舍我誰。", "何事至今猶一旅，幾回無語發深思。"]'),
('ee13c2df-f403-4313-a4df-cc5d9e35256d','和寄仵判院八首  其六','趙希逢','宋','宋诗','song-poetry','','[]','琴樽疇昔記追隨，富貴休教貧賤離。',32,'全唐诗/poet.song.215000.json','["琴樽疇昔記追隨，富貴休教貧賤離。", "一日相思時十二，無書獨可可無詩。"]'),
('94431808-1af0-41e9-a0b5-822de2f5ca2b','和寄仵判院八首  其七','趙希逢','宋','宋诗','song-poetry','','[]','好問君王覓鏡湖，含丹照白伴瀟疎。',32,'全唐诗/poet.song.215000.json','["好問君王覓鏡湖，含丹照白伴瀟疎。", "玄中得趣渾閑事，只恐故人難得書。"]'),
('fbcd3f1e-d0d5-45f9-8201-1df94b241a68','和寄仵判院八首  其八','趙希逢','宋','宋诗','song-poetry','','[]','囷躓真成失水螭，震雷驚起在何時。',32,'全唐诗/poet.song.215000.json','["囷躓真成失水螭，震雷驚起在何時。", "而今且向書窗下，夜對寒燈讀楚詞。"]'),
('16d19fa6-aed5-40eb-a23e-e80e092a0dd8','和寄宗上人','趙希逢','宋','宋诗','song-poetry','','[]','早欲投閑林下坐，苦無度牒與袈裟。',32,'全唐诗/poet.song.215000.json','["早欲投閑林下坐，苦無度牒與袈裟。", "在家儻若謝靈運，薄酒須知也勝茶。"]'),
('f4777b33-6778-4921-bc79-30f9cff5dee7','和寄王清之','趙希逢','宋','宋诗','song-poetry','','[]','奔馳造物實爲之，何日連鑣共賦歸。',64,'全唐诗/poet.song.215000.json','["奔馳造物實爲之，何日連鑣共賦歸。", "有夢憑誰爲遞到，舉頭恨肉不能飛。", "公門胡靳栽桃李，治世誰甘采蕨薇。", "忍死初心終不負，願驅風鶴捷淮淝。"]'),
('c92d1270-1e62-4376-a759-3d9cb70b2f6c','和寄陳士元','趙希逢','宋','宋诗','song-poetry','','[]','開禧一失晚方收，在位諸公似拙謀。',64,'全唐诗/poet.song.215000.json','["開禧一失晚方收，在位諸公似拙謀。", "逞志真成窮鴨綠，憫寒誰識遣貂裘。", "王恢首事徒開釁，廣利邀功要覓侯。", "多少英雄窗下坐，沉吟無語暗搔頭。"]'),
('e9462994-f72c-49e1-9243-bc881bf31ac6','和寄范茂卿','趙希逢','宋','宋诗','song-poetry','','[]','揀芽雀舌乍辭枝，小杓分江欲試時。',64,'全唐诗/poet.song.215000.json','["揀芽雀舌乍辭枝，小杓分江欲試時。", "孤悶不知消幾椀，睡魔立使豎降旗。", "何人紫色分金餠，入口清泉生玉池。", "搜攪胸中書傳起，誰能捫腹不吟詩。"]'),
('47b0cb95-c512-4f1c-8ca3-c1ac7fde864a','和寄兩庠同舍','趙希逢','宋','宋诗','song-poetry','','[]','早欲排雲扣帝閽，可憐駒隙過青春。',64,'全唐诗/poet.song.215000.json','["早欲排雲扣帝閽，可憐駒隙過青春。", "文章未必劣班馬，人物直疑分廣閩。", "夜對短檠空抱恨，日愁破甑暗生塵。", "山間江上風和月，令眼傍觀却笑人。"]'),
('002cf70e-90b1-41fc-8de0-535785aa49c0','和寄江子崗','趙希逢','宋','宋诗','song-poetry','','[]','間關踏盡幾重崗，去國悠悠路更長。',64,'全唐诗/poet.song.215000.json','["間關踏盡幾重崗，去國悠悠路更長。", "別後三秋驚歲月，瀟然一旅慣風霜。", "屬厭茶味能消悶，搜攪書腸覺有香。", "過鴈懷人空矯首，草書未暇事應忙。"]'),
('175679fc-2272-40f5-823c-c18dcd4d0c15','和寄王士貴','趙希逢','宋','宋诗','song-poetry','','[]','又逢南浦草生春，獨詠江東日暮雲。',64,'全唐诗/poet.song.215000.json','["又逢南浦草生春，獨詠江東日暮雲。", "樽俎從容成感舊，鼎茵安否莫知君。", "寸心終夕馳千里，一見他時勝百聞。", "欲到小峰身不羽，此情脈脈倩詩云。"]'),
('24697fd4-d37a-4e3c-b1f0-ddee00492925','和寄王五四將仕  其一','趙希逢','宋','宋诗','song-poetry','','[]','書詐誰知誣子孟，奏陳直欲動山濤。',32,'全唐诗/poet.song.215000.json','["書詐誰知誣子孟，奏陳直欲動山濤。", "下機終不疑曾子，二主其明真察毫。"]'),
('3c8cc762-cbad-4b2d-9288-87121482c5a3','和寄王五四將仕  其二','趙希逢','宋','宋诗','song-poetry','','[]','帝業未成三尺劍，老人先授一編書。',32,'全唐诗/poet.song.215000.json','["帝業未成三尺劍，老人先授一編書。", "遭時若與留侯異，簑笠江湖亦可漁。"]'),
('e9ed9683-034a-4391-bf95-bfcb361e0002','和寄敬甫葉兄','趙希逢','宋','宋诗','song-poetry','','[]','讀史感忠義，掩卷暗奪魄。',288,'全唐诗/poet.song.215000.json','["讀史感忠義，掩卷暗奪魄。", "痛哭治安書，骨梗賢良策。", "表表漢唐間，相望繼履舄。", "古今立人朝，委質幾千百。", "誰能抗切直，反或事便僻。", "居然習成風，未易一二責。", "間氣萃賈劉，言可行蠻貊。", "首足歎倒懸，夷夏正疆埸。", "建侯選左右，一一爲區畫。", "耻欲洗元和，長鳴奮羽翮。", "懼稔蕭牆禍，抗論不容釋。", "迨今忠讜言，日星輝簡冊。", "不間加奬納，方且被放謫。", "身或死異土，霧雨暗孤驛。", "時君聽未洪，天公眼亦白。", "三歎動耿耿，一笑空啞啞。", "慷慨士豈無，君門九重隔。", "自惟幼所學，早已聲猷藉。", "幾載事辛勤，半生困行役。", "楊朱正泣歧，宣室未前席。", "抑鬰嘆不平，擬吊湘水碧。", "堪嘆失東隅，誰能走南陌。", "只恐搜遺賢，詔且下旦夕。", "看看辭霧隠，廩廩升雲圛。"]'),
('16a30284-3810-4032-9f2d-987f50b5e31d','和寄趙及父','趙希逢','宋','宋诗','song-poetry','','[]','德裕南征基奉冊，淮陰晚節北登壇。',32,'全唐诗/poet.song.215000.json','["德裕南征基奉冊，淮陰晚節北登壇。", "何如流落長沙後，猶自拳拳策治安。"]'),
('dd46d1b3-eab1-445d-9f7f-5b02717c8ef4','和寄小王徐子晉','趙希逢','宋','宋诗','song-poetry','','[]','南溟未擊水三千，涸轍心難一息安。',64,'全唐诗/poet.song.215000.json','["南溟未擊水三千，涸轍心難一息安。", "擬向伊吾馳馬武，併於易水吊燕丹。", "拳拳空自鼓齊瑟，落落真成適越冠。", "半世辛勤成底事，星星鬢髮漸成皤。"]'),
('e23fd14b-b9ed-4a89-acf8-b04072422a60','和寄王謂夫','趙希逢','宋','宋诗','song-poetry','','[]','才智當於緩急觀，孤忠豈願效逢干。',64,'全唐诗/poet.song.215000.json','["才智當於緩急觀，孤忠豈願效逢干。", "幾多長技當施錯，千萬和謀莫主韓。", "便好多方收俊傑，忍教左衽溷衣冠。", "直須掃穴犁庭後，放馬山陽脚始酸。"]'),
('36cfc613-05ae-49cd-bb04-1f9e3f3df966','和寄劉浩然','趙希逢','宋','宋诗','song-poetry','','[]','緣空寶鏡一輪新，何處纖雲更敢侵。',64,'全唐诗/poet.song.215000.json','["緣空寶鏡一輪新，何處纖雲更敢侵。", "四望孤城連遠塞，幾聲哀杵間寒砧。", "月明飛鵲無依地，夜靜征鴻有過音。", "報國寸心空耿耿，可憐鬢髮已侵尋。"]'),
('6f521900-263b-4b55-8a86-c308a375a2cb','和寄苕溪故人','趙希逢','宋','宋诗','song-poetry','','[]','摶砂聚散易西東，覽鏡顔非舊日紅。',64,'全唐诗/poet.song.215000.json','["摶砂聚散易西東，覽鏡顔非舊日紅。", "千里鴈郵成杳杳，百年駒隙去匆匆。", "暮雲杜憶謫仙子，夜雪王思安道公。", "蠶室史遷非有罪，從來文士例多窮。"]'),
('2e64a76b-0b8a-499b-b2d8-74803881e831','和寄西山  其一','趙希逢','宋','宋诗','song-poetry','','[]','寥寥千古一西山，望著令人脚便酸。',64,'全唐诗/poet.song.215000.json','["寥寥千古一西山，望著令人脚便酸。", "充腹野薇當日事，照人清節至今寒。", "未聞治世饑而死，留與凌烟畫出看。", "厚衛生經非浪語，欲安家國在身安。"]'),
('50581380-140f-4cff-89e8-9a600eb5449b','和寄西山  其二','趙希逢','宋','宋诗','song-poetry','','[]','殘胡妄欲肆穿窬，憤激英雄起草廬。',64,'全唐诗/poet.song.215000.json','["殘胡妄欲肆穿窬，憤激英雄起草廬。", "廣也數奇窮亦命，括之一敗罪非書。", "夢魂北闕常傾霍，餓死西山未分蔬。", "奮志鷹揚正吾事，誰能閑立作舂鋤。"]'),
('9cc4a7a7-9311-40b6-8595-a606422e0b99','和寄趙德夫','趙希逢','宋','宋诗','song-poetry','','[]','學行何必過邯鄲，匍匐歸來指謾彈。',32,'全唐诗/poet.song.215000.json','["學行何必過邯鄲，匍匐歸來指謾彈。", "萬事不如安分好，人心何事險於灘。"]'),
('a57e99df-967a-4e51-87fb-6b8224cfbc5d','和憂世寄清溪友人','趙希逢','宋','宋诗','song-poetry','','[]','少年奮筆若揮戈，兵甲胸中數萬羅。',64,'全唐诗/poet.song.215000.json','["少年奮筆若揮戈，兵甲胸中數萬羅。", "一片忠肝明貫日，十分辯口勢懸河。", "肯同郭璞遞投策，莫學楚輿狂作歌。", "四海蒼生望霖雨，看看離畢致滂沱。"]'),
('a55755f0-8db9-4201-9640-c8892e40cfb3','和巧松  其一','趙希逢','宋','宋诗','song-poetry','','[]','肯將生意待春回，尺寸靈根破雪栽。',32,'全唐诗/poet.song.215000.json','["肯將生意待春回，尺寸靈根破雪栽。", "愛護成陰十年後，漫山彷彿魯祖來。"]'),
('e59acf47-f8df-4301-bef4-5139d6cee809','和巧松  其二','趙希逢','宋','宋诗','song-poetry','','[]','何人厦屋詫渠渠，路入松關陰滿衢。',32,'全唐诗/poet.song.215000.json','["何人厦屋詫渠渠，路入松關陰滿衢。", "都把萬間庇寒士，又分餘蔭憇征夫。"]'),
('cef309ad-8896-4a6f-acb2-e7cbc32d73a2','和巧松  其三','趙希逢','宋','宋诗','song-poetry','','[]','秦人無故起阿房，赤立千林赭衆岡。',32,'全唐诗/poet.song.215000.json','["秦人無故起阿房，赤立千林赭衆岡。", "更覓長生遊海上，不將松實作津梁。"]'),
('492c2eda-4ea0-4615-926b-db0a03dd2709','和楊花  其一','趙希逢','宋','宋诗','song-poetry','','[]','枝頭的皪耀珠光，蝶使蜂媒未許忙。',64,'全唐诗/poet.song.215000.json','["枝頭的皪耀珠光，蝶使蜂媒未許忙。", "識賞何人曾眼白，形容無語可雌黄。", "溪橋月下疎橫影，玉壟風前暗度香。", "今古騷人吟不盡，奚奴空背錦爲囊。"]'),
('60b4b39e-1ed8-4abe-8b2f-4b8fc095ec17','和楊花  其二','趙希逢','宋','宋诗','song-poetry','','[]','稟受天香兼國色，一枝漏却春信息。',96,'全唐诗/poet.song.215000.json','["稟受天香兼國色，一枝漏却春信息。", "斷橋寂莫黄昏時，何人前村雪裏歸。", "五出六出誇兩樣，只將一眼爲識賞。", "相看如昨不世情，超然風度不與京。", "有時冷浸月華白，不學壽陽點宮額。", "四時留得伴眼前，不妨長作隴頭客。"]'),
('a2c907af-d758-4e52-9c99-63a4b715a6ae','和桃花  其一','趙希逢','宋','宋诗','song-poetry','','[]','一抹殘紅散綺霞，因風吹恨落誰家。',32,'全唐诗/poet.song.215000.json','["一抹殘紅散綺霞，因風吹恨落誰家。", "那堪移向瑶池種，留得千年看實花。"]'),
('8e92e6c1-1b94-4a8d-a196-bd7f3d6f5f58','和桃花  其二','趙希逢','宋','宋诗','song-poetry','','[]','萬鍾莫動孟軻喜，簞食難生顔子愁。',32,'全唐诗/poet.song.215000.json','["萬鍾莫動孟軻喜，簞食難生顔子愁。", "醴酒當年如□□，□□□□□□□。"]'),
('fe5c1b86-715e-4c55-85f5-bda940152a09','和桃花  其三','趙希逢','宋','宋诗','song-poetry','','[]','紅雨隨風散落霞，行人幾誤武陵家。',32,'全唐诗/poet.song.215000.json','["紅雨隨風散落霞，行人幾誤武陵家。", "牧童若向青帘見，應認枝頭作杏花。"]'),
('6cde1f39-d86e-41cb-adcc-6db8e1159d6d','和藕花','趙希逢','宋','宋诗','song-poetry','','[]','小池清曉試芒鞋，水國真仙簇仗來。',64,'全唐诗/poet.song.215000.json','["小池清曉試芒鞋，水國真仙簇仗來。", "微動襪塵移穩步，半酣卯酒暈嬌腮。", "千重倚蓋隨風漾，一笑傾城特地開。", "口不能言猶可詠，那堪解語肯心灰。"]'),
('c06227a0-aff8-41cf-b1c3-892dfc796c14','和琴','趙希逢','宋','宋诗','song-poetry','','[]','四時那得如秋清，夜靜無人琴有聲。',32,'全唐诗/poet.song.215000.json','["四時那得如秋清，夜靜無人琴有聲。", "月華如水不動塵，無端耳畔寒蛩鳴。"]'),
('a045d3ba-a8d0-4f8a-ac3e-9babdaff8726','和套筒','趙希逢','宋','宋诗','song-poetry','','[]','長鳴誰敢扼吾咽，掉臂天門不受牽。',64,'全唐诗/poet.song.215000.json','["長鳴誰敢扼吾咽，掉臂天門不受牽。", "豈是轉喉能觸諱，自緣賊柳欲爲圈。", "幾回怒起橫長劍，何日歸來老數椽。", "林下也休驚曲木，一般安分賽當錢。"]'),
('888bc3e1-e55d-40f4-bbda-8352e15f70fa','和車制','趙希逢','宋','宋诗','song-poetry','','[]','木牛新意出南陽，萬里飛芻不絕糧。',32,'全唐诗/poet.song.215000.json','["木牛新意出南陽，萬里飛芻不絕糧。", "故智莫能遵此日，却將獨輻獻岩廊。"]'),
('a8ef38e9-7e4a-4521-a0ef-cf9c821913ee','和午枕  其一','趙希逢','宋','宋诗','song-poetry','','[]','遣懷無日不持盃，何事愁腸未肯開。',32,'全唐诗/poet.song.215000.json','["遣懷無日不持盃，何事愁腸未肯開。", "堪嘆人生真似夢，黄粱不夢又蒿萊。"]'),
('3eae3d36-5fd3-4d04-a6a3-cf8401471081','和午枕  其二','趙希逢','宋','宋诗','song-poetry','','[]','春酲未析眼慵開，困卧藤床隠腹雷。',32,'全唐诗/poet.song.215000.json','["春酲未析眼慵開，困卧藤床隠腹雷。", "陪笑不容掀幌問，一雞啼午自驚回。"]'),
('aa6a8e55-7359-4620-af69-26f9ad040017','和浦城買舟  其一','趙希逢','宋','宋诗','song-poetry','','[]','倦客逢萸節，生涯寄葉舟。',48,'全唐诗/poet.song.215000.json','["倦客逢萸節，生涯寄葉舟。", "窮途危不顧，飛棹去難留。", "舊菊重陽日，寒蘆兩岸秋。", "多情惟破帽，猶恐老人頭。"]'),
('55b17b9e-9beb-4b37-8a12-ff657646f0ae','和浦城買舟  其二','趙希逢','宋','宋诗','song-poetry','','[]','丈夫儻知命，身肯委虛舟。',48,'全唐诗/poet.song.215000.json','["丈夫儻知命，身肯委虛舟。", "不爲君親重，徙知道路憂。", "危機甘失脚，苦海莫回頭。", "接跡巖牆下，滔滔皆若流。"]'),
('a1bc8beb-d850-4c1b-ac1c-39d05b7ee212','和武興解舟','趙希逢','宋','宋诗','song-poetry','','[]','寂寞黄昏古渡頭，凄然秋思滿汀洲。',64,'全唐诗/poet.song.215000.json','["寂寞黄昏古渡頭，凄然秋思滿汀洲。", "卧薪要復中原地，載荻先燒强虜舟。", "席勝長驅如朽拉，老師何苦更迍留。", "義旗直指兵無血，剩活千人世世侯。"]'),
('416f21cc-e11f-4f58-9c2e-fd3591fd1e50','和江上雙舟催發','趙希逢','宋','宋诗','song-poetry','','[]','滄茫萬頃不計闊，仙槎曾泛天宮闕。',96,'全唐诗/poet.song.215000.json','["滄茫萬頃不計闊，仙槎曾泛天宮闕。", "至今風浪卷長空，破浪飛帆何處發。", "落鷹飛兔注急湍，千丈皚皚湧雪山。", "相忘鷗鷺慣舟楫，蕩漾隨流下小灘。", "晚來兩兩帆相續，牙檣拄定孤輪玉。", "寒冰冷浸一江秋，分明寫出瀟湘軸。"]'),
('feb309c7-9df9-4ca2-a428-c1c82f05009b','和枕上吟','趙希逢','宋','宋诗','song-poetry','','[]','夢回客枕覺衾寒，展轉憂思不一端。',32,'全唐诗/poet.song.215000.json','["夢回客枕覺衾寒，展轉憂思不一端。", "嗚咽數聲傳曉角，便教鐵石也心酸。"]'),
('bfa70963-635d-477b-a226-07b7b601a8f1','和飲仙閣','趙希逢','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','滄波萬頃涵秋綠，麯和泰山釀醽醁。',112,'全唐诗/poet.song.215000.json','["滄波萬頃涵秋綠，麯和泰山釀醽醁。", "相逢一醉誰能辭，紛紛麈談霏屑玉。", "主人名閣意寓言，不飲俗客只飲仙。", "眼前具足吞雲夢，氣象豁達無頗偏。", "一時價高洛陽紙，迭唱更酬萃朱紫。", "好風吹月入酒巵，志氣飄逸神爽飛。", "悠然清興正未艾，晨光峰頭忽熹微。"]'),
('8e3100e8-b6e9-4749-9427-7d71d1ff1fdd','和倪尚書生祠','趙希逢','宋','宋诗','song-poetry','','[]','風流醖藉絕絢都，鍊得身形似鶴癯。',64,'全唐诗/poet.song.215000.json','["風流醖藉絕絢都，鍊得身形似鶴癯。", "要爲閻閭伸鬰抑，促教松菊就荒蕪。", "貪殘安得市中虎，恩愛由遺屋上烏。", "不識在朝共爾位，用心皆似若人無。"]'),
('6b5e4980-1a31-4e28-b30a-23ea530b45a2','和感應王祠','趙希逢','宋','宋诗','song-poetry','','[]','無端治世苦幽囚，千古空貽善類羞。',64,'全唐诗/poet.song.215000.json','["無端治世苦幽囚，千古空貽善類羞。", "格是愛君身敢恤，勢須苦口疾方瘳。", "明祠儻鑒長非罪，異日焉知廣不侯。", "一片忠肝明白甚，可憐無計徹凝旒。"]'),
('b6410079-74bd-4a27-af54-60dcd502457d','和題富沙廟','趙希逢','宋','宋诗','song-poetry','','[]','瞬息鱗鱗萬瓦空，伊誰叱馭半空中。',64,'全唐诗/poet.song.215000.json','["瞬息鱗鱗萬瓦空，伊誰叱馭半空中。", "鬰攸飲氣收殘焰，群祀甘心處下風。", "坤轉乾旋神有□，離居坎上水無功。", "乞靈何日趨祠下，借助青霄作鳳沖。"]'),
('6b96ae1b-6361-47d8-aed4-00ef20a58df7','和題澤民廟','趙希逢','宋','宋诗','song-poetry','','[]','落霞晴雲淡白黎，何人清夢遶山谿。',64,'全唐诗/poet.song.215000.json','["落霞晴雲淡白黎，何人清夢遶山谿。", "邯鄲枕上占炊黍，審雨堂中慰望霓。", "血食不隨今古變，洪休直與國家齊。", "乞靈僕僕紛行客，得意都忘筌與蹄。"]'),
('faa42444-f27a-4638-a5e2-fe29c986254f','和禱富沙','趙希逢','宋','宋诗','song-poetry','','[]','也知銅玉寧無璞，自是蒙金合以沙。',64,'全唐诗/poet.song.215000.json','["也知銅玉寧無璞，自是蒙金合以沙。", "俛首何辜聯盜械，脫身無路覓仙槎。", "懷珍空自經三獻，受用何嘗得五車。", "事業萬分渾杳一，可憐早已髮生華。"]'),
('39b3084b-97aa-4fac-8702-286f56a00951','和采石','趙希逢','宋','宋诗','song-poetry','','[]','平生李白幾詩歌，傳載存亡事不訛。',32,'全唐诗/poet.song.215000.json','["平生李白幾詩歌，傳載存亡事不訛。", "捉月浪傳何所據，欲將遺恨比湘娥。"]'),
('8e884f6a-70de-4fc3-9c09-72842fa08363','和新市雜詠  其一','趙希逢','宋','宋诗','song-poetry','','[]','落日看看宿暮鴉，譙樓畫角動梅花。',32,'全唐诗/poet.song.215000.json','["落日看看宿暮鴉，譙樓畫角動梅花。", "今宵酒興知何處，隠隠歌聲不一家。"]'),
('2191089d-88f5-41ff-a893-0d9611042ac9','和新市雜詠  其二','趙希逢','宋','宋诗','song-poetry','','[]','拚醉秦樓頭强扶，樽空還更問當罏。',32,'全唐诗/poet.song.215000.json','["拚醉秦樓頭强扶，樽空還更問當罏。", "興闌夢覺明朝路，山色煙中半有無。"]'),
('48c5b29d-aca2-463e-a7e0-21cdf1612543','和新市雜詠  其三','趙希逢','宋','宋诗','song-poetry','','[]','醉來援筆壁飛鴉，他日還能罩碧紗。',32,'全唐诗/poet.song.215000.json','["醉來援筆壁飛鴉，他日還能罩碧紗。", "却喜樽前低笑道，長安何處沒閑花。"]'),
('20879bc3-86a3-47fb-87d0-58d12e8bcc6d','和新市雜詠  其四','趙希逢','宋','宋诗','song-poetry','','[]','杯行火急正相催，一醉難酬一笑開。',32,'全唐诗/poet.song.215000.json','["杯行火急正相催，一醉難酬一笑開。", "夜靜酒闌清不奈，好風吹月入樽來。"]'),
('f19cb50c-3d1a-43b8-b0ef-ad10e72cf617','和新市雜詠  其五','趙希逢','宋','宋诗','song-poetry','','[]','相逢逆旅若爲親，一掬鄉心滿面塵。',32,'全唐诗/poet.song.215000.json','["相逢逆旅若爲親，一掬鄉心滿面塵。", "忽聽瑶臺歌四起，頓令歡意可回嗔。"]'),
('a3830b37-def0-40e6-8b7e-d237675a5066','和新市雜詠  其六','趙希逢','宋','宋诗','song-poetry','','[]','婥約精神解語花，娥娥不受點雲遮。',32,'全唐诗/poet.song.215000.json','["婥約精神解語花，娥娥不受點雲遮。", "相看醉後還能醒，驅遣睡魔那用茶。"]'),
('f04bc204-6846-4e7b-9844-129d99218635','和新市雜詠  其七','趙希逢','宋','宋诗','song-poetry','','[]','歌聲嬌带曉鶑啼，何處糟糠更有妻。',32,'全唐诗/poet.song.215000.json','["歌聲嬌带曉鶑啼，何處糟糠更有妻。", "脈脈寸心和酒悶，明朝還恐兩東西。"]'),
('ca018f3d-dd4b-43ce-80c2-9459b9d4fb69','和新市雜詠  其八','趙希逢','宋','宋诗','song-poetry','','[]','新詩曾寄紫雲娘，異日相逢尚未忘。',32,'全唐诗/poet.song.215000.json','["新詩曾寄紫雲娘，異日相逢尚未忘。", "料想怱怱恨離別，愁腸萬縷繫垂楊。"]'),
('05861bc2-543f-427f-b241-8be8abc8eccb','和新市雜詠  其九','趙希逢','宋','宋诗','song-poetry','','[]','離愁別恨滿滄洲，匹馬匆匆去莫留。',32,'全唐诗/poet.song.215000.json','["離愁別恨滿滄洲，匹馬匆匆去莫留。", "山盡回頭人不見，齊雲何日貯高樓。"]'),
('c85a625e-f44e-4cec-bc90-31dff5a00800','和新市雜詠  其一○','趙希逢','宋','宋诗','song-poetry','','[]','絃管樓臺十萬家，暮雲落日映殘霞。',32,'全唐诗/poet.song.215000.json','["絃管樓臺十萬家，暮雲落日映殘霞。", "可曾一夜不携酒，占斷四時長是花。"]'),
('d48fce9e-44a2-4499-b7a3-84db8c2864c8','和三衢道中','趙希逢','宋','宋诗','song-poetry','','[]','飄飄興動酒家帘，身世都拚醉大千。',64,'全唐诗/poet.song.215000.json','["飄飄興動酒家帘，身世都拚醉大千。", "愁逐夢魂回夜半，思隨詩句到天邊。", "再興炎祚諸公力，一線桐江萬古賢。", "何日洗心來伴此，不須別辦買山錢。"]'),
('f8f965e5-e0df-421c-88cd-68c5dea2e9be','和壽昌道中','趙希逢','宋','宋诗','song-poetry','','[]','債甘償道路，脚慣踏江村。',48,'全唐诗/poet.song.215000.json','["債甘償道路，脚慣踏江村。", "驀地心生愧，何人日掩門。", "安貧居陋巷，無事對清樽。", "我亦動思靜，此懷與誰論。"]'),
('a13e8d5b-6610-4396-b06c-afdc7a7dff02','和當塗道中','趙希逢','宋','宋诗','song-poetry','','[]','至今修竹下，陳迹憶山陰。',48,'全唐诗/poet.song.215000.json','["至今修竹下，陳迹憶山陰。", "去去人如水，行行杖掛金。", "柳絲偏惹恨，禽語更關心。", "對景愁千斛，無言酒懶斟。"]'),
('f7493f0c-1750-4963-a7c0-2fbbe32f5c26','和平政橋','趙希逢','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','潮之距京數千里，長短郵亭幾屈指。',256,'全唐诗/poet.song.215000.json','["潮之距京數千里，長短郵亭幾屈指。", "脚踏富沙路恰分，山傍雲飛峰亂起。", "低頭萬里瞰長江，如羊很石爭跳梁。", "篙師駢首帽裹黄，舟行如飛電掣光。", "褰裳淺不比涉洧，舍安就危豈得計。", "何人鞭石壓濤驚，巨川不假舟楫濟。", "俶謀計直凡幾緡，千柱津梁談笑成。", "遂令深谷化平陸，飛翬直上凌空青。", "行盡吳頭并楚尾，多少風光經眼底。", "勝絕未有如此橋，虹光映水洞表裏。", "春來雨漲添洪波，波底森森劍戟羅。", "群魚撥剌慣砰磕，躍水欲作龍騰梭。", "未寒石捲浪花雪，清曉日浴金盤赤。", "更如鏖戰萬鼓鳴，俯觀顔容變行客。", "人間無限事不平，吞恨飲氣那能名。", "誰能似此翻長舌，日夜怒號如訴聲。"]'),
('5573db06-42d6-4e75-9918-dd16c72acfe8','和題易村','趙希逢','宋','宋诗','song-poetry','','[]','路入縈紆半里村，憶達清興起山陰。',64,'全唐诗/poet.song.215000.json','["路入縈紆半里村，憶達清興起山陰。", "對床喜有人如玉，寄遠何勞書抵金。", "萬壑凉風生騎氣，一天離恨更蛩吟。", "丈夫對景休兒女，慷慨相期一片心。"]'),
('e89718cf-daec-4421-942c-aae75284c2b8','和小圃','趙希逢','宋','宋诗','song-poetry','','[]','淵明從日涉，董子不窺園。',48,'全唐诗/poet.song.215000.json','["淵明從日涉，董子不窺園。", "行樂從吾好，安恬亦性根。", "我今勤抱甕，花發應開樽。", "安得恢餘地，群珍賸闡坤。"]'),
('0b204a6e-1b01-40ff-989a-e23438485002','和巫山','趙希逢','宋','宋诗','song-poetry','','[]','奇峰六六插寒江，作賦何人語悖常。',32,'全唐诗/poet.song.215000.json','["奇峰六六插寒江，作賦何人語悖常。", "譽木從旁猶見斥，楚王應有愧於唐。"]'),
('d082362f-167e-4909-9fc5-6b5b155942ec','和山水吟','趙希逢','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','七閩佳山水，秀氣鬰蒼蒼。',184,'全唐诗/poet.song.215000.json','["七閩佳山水，秀氣鬰蒼蒼。", "鍾而爲人物，事業亦叵量。", "我生古瀛州，地匪中州醜。", "雖然得文公，木舌而金口。", "自惟稟受不堅申，安得玉骨秋水神。", "幾番分欲躬樵蘇，手足况有禹偏枯。", "禹猶盡力導河洛，功業何啻等山岳。", "予惟食粟類曹交，所至於人成落落。", "勿謂廣之東，安得萬人雄。", "地本不愛寶，賦予由來公。", "閩廣雖異地，人物差可擬。", "爾來擢倫魁，亦復有人耳。", "聲價壓天下，爭覩如星凰。", "泰山一毫芒，更有萬丈長。"]'),
('67f7d1da-da34-420d-84a7-e373bd92e9bf','和寧川冷渡','趙希逢','宋','宋诗','song-poetry','','[]','解鞍飽有山林興，入耳都無市井聲。',32,'全唐诗/poet.song.215000.json','["解鞍飽有山林興，入耳都無市井聲。", "一榻蕭然誰是伴，琴樽相對太清生。"]'),
('51bb5f39-2cef-4a79-aaf1-0a62d4d33ad7','和江濤','趙希逢','宋','宋诗','song-poetry','','[]','奔騰勢力作弓䟫，夜半聲如萬鼓轟。',32,'全唐诗/poet.song.215000.json','["奔騰勢力作弓䟫，夜半聲如萬鼓轟。", "因想千人揮筆陣，斫營怒氣更崢嶸。"]'),
('ae23d0fd-6904-4098-a182-06680c9453ea','和月巖','趙希逢','宋','宋诗','song-poetry','','[]','涵虛一境絕人煙，掛星貫月棲羽仙。',64,'全唐诗/poet.song.215000.json','["涵虛一境絕人煙，掛星貫月棲羽仙。", "移來海上三島地，喚作人間幾洞天。", "追遊有客驂鸞鳳，滿座清光延兔蟾。", "舉頭耿耿照不寐，料想無人醉欲眠。"]'),
('1ed511bc-3d72-412d-bec5-76ea92d59b45','和早春水西','趙希逢','宋','宋诗','song-poetry','','[]','車塵曀曀慣東西，因覽江山得勝奇。',32,'全唐诗/poet.song.215000.json','["車塵曀曀慣東西，因覽江山得勝奇。", "休嘆勞生空轍迹，未留勳業也留詩。"]'),
('9e9dbcb6-08ff-4c5f-8880-15205d6b000f','和花村  其一','趙希逢','宋','宋诗','song-poetry','','[]','格是而今老有餘，行行真欠瘦筇扶。',32,'全唐诗/poet.song.215000.json','["格是而今老有餘，行行真欠瘦筇扶。", "不將心絮隨風起，一恁閑花有似無。"]'),
('9573ce53-19e8-4410-a538-4b5d2b1fdf9e','和花村  其二','趙希逢','宋','宋诗','song-poetry','','[]','路入前村認杏花，門前水積半溪沙。',32,'全唐诗/poet.song.215000.json','["路入前村認杏花，門前水積半溪沙。", "風流髣髴朱陳俗，白酒黄鷄姓兩家。"]'),
('1158dd57-d283-4cb4-9dc7-5faec38d84f5','和早春梅山','趙希逢','宋','宋诗','song-poetry','','[]','昨夜何人雪裏歸，嶺頭折得去年枝。',32,'全唐诗/poet.song.215000.json','["昨夜何人雪裏歸，嶺頭折得去年枝。", "莫將寒暖分南北，直爲春光剖破籬。"]'),
('a16d82c0-8528-4bb0-baee-3b589af72291','和巖桂','趙希逢','宋','宋诗','song-poetry','','[]','嫦娥羞澀隠閨房，曾記當年竊藥囊。',64,'全唐诗/poet.song.215000.json','["嫦娥羞澀隠閨房，曾記當年竊藥囊。", "奔入月中知幾載，却於秋後噴幽房。", "枝頭遺落兼金屑，坐上濃薰沉水香。", "恍惚蟾宮身屢到，似猶相隔一門牆。"]'),
('ccdc2ab1-0bde-4151-a3b6-784ba0d3f007','和巖桂落英','趙希逢','宋','宋诗','song-poetry','','[]','沉麝爲肌蠟剪英，九霄遞馥到寰瀛。',64,'全唐诗/poet.song.215000.json','["沉麝爲肌蠟剪英，九霄遞馥到寰瀛。", "徘徊忍離花邊去，彷彿如從月窟行。", "殘蘂尚堪燃古鼎，清芬真可濯塵纓。", "紛紛落盡盈盃勺，堪笑承糟空捧罌。"]'),
('48d42623-2679-4af8-b243-7b653b8c1dc4','和野菜吟','趙希逢','宋','宋诗','song-poetry','','[]','人生何用廣田宅，憂懷千歲不滿百。',160,'全唐诗/poet.song.215000.json','["人生何用廣田宅，憂懷千歲不滿百。", "饑來糲飯薦苜蓿，不必膾鯉更炮鱉。", "何人日流餓虎涎，望望一飽蟻慕羶。", "豈知山林一天性，悠然野興浩無邊。", "冬菁春韭總甘美，入口寒泉生頰齒。", "鼎烹雖不羅八珍，盤餐儘定供百指。", "不妨寂寞類首陽，免得市聲入耳忙。", "蕨薇風味千載下，發以姜橙蘇蔱香。", "洗教瓦鼎光如鏡，自拾樵薪歸野徑。", "興來小摘烝復湘，不用玉纖巧餖飣。"]'),
('c4944008-9e27-49d9-aea5-027b12d3dd90','和春閨落花','趙希逢','宋','宋诗','song-poetry','','[]','片片臙脂纈地毛，對花醉臉上紅潮。',32,'全唐诗/poet.song.215000.json','["片片臙脂纈地毛，對花醉臉上紅潮。", "樽前笑指人人看，好與香腮一樣嬌。"]'),
('279a01e0-9cbc-4c3c-92c7-462048e6c0f7','和買盆池蓮','趙希逢','宋','宋诗','song-poetry','','[]','終日歡陪解語蓮，浮花欲比價相千。',32,'全唐诗/poet.song.215000.json','["終日歡陪解語蓮，浮花欲比價相千。", "不須更買盆池景，寂寞無言涴眼前。"]'),
('1b227d5f-3ea9-43b0-bb86-89705bb101e9','和春閨带花','趙希逢','宋','宋诗','song-poetry','','[]','簾捲黄昏月似眉，瘦梅淡月兩相宜。',32,'全唐诗/poet.song.215000.json','["簾捲黄昏月似眉，瘦梅淡月兩相宜。", "樽前况有人如玉，鬢畔疑橫竹外枝。"]'),
('fb6e4b7e-eb2c-4fd9-a08e-6a912e577f00','和舍後植花竹','趙希逢','宋','宋诗','song-poetry','','[]','東西地袤里千餘，三徑環栽松大夫。',64,'全唐诗/poet.song.215000.json','["東西地袤里千餘，三徑環栽松大夫。", "竹比渭川知幾畝，梅移庾嶺可千株。", "清歡不減巴丘橘，勝境如懸費氏壺。", "况欲萬間恢廣厦，莫須更有空閑無。"]'),
('c210bed3-bc99-48b3-80e8-0404363ac8cd','和百舌','趙希逢','宋','宋诗','song-poetry','','[]','四序循環機不息，百花獨梅先占得。',160,'全唐诗/poet.song.215000.json','["四序循環機不息，百花獨梅先占得。", "紛紛紅紫未動頭，飛蝶遊蜂聖得識。", "數聲啼破枝頭春，來從何處綠楊陰。", "黄鸝鉗口燕無語，是甚嬌聲敢囀禽。", "梨花院落如飛雪，百樣間關調巧舌。", "工兼衆語媚韶華，一部笙簧長按節。", "東君拂袖賞音稀，寂寞無言蒿下飛。", "一春滕口說底事，徒爾貽笑諸羽衣。", "人生可以直則直，萬言萬當豈如默。", "三年不鳴忽一鳴，驚動東西與南北。"]'),
('223d4f59-6699-4d9e-84cf-161b0c71b092','和流螢','趙希逢','宋','宋诗','song-poetry','','[]','林塘腐草化爲螢，星散飛來暗復明。',32,'全唐诗/poet.song.215000.json','["林塘腐草化爲螢，星散飛來暗復明。", "拾向書窗輝眼目，當將檠火對南城。"]'),
('f910cdf3-6f0a-4f8d-a513-7f9f3d744be4','和苦蚊','趙希逢','宋','宋诗','song-poetry','','[]','入夜聲不絕，朝來還迹滅。',24,'全唐诗/poet.song.215000.json','["入夜聲不絕，朝來還迹滅。", "身絮巧粘膚，觜針微點鐵。"]'),
('ff55353b-d86b-4088-b770-9a2d5d51e5d5','和雪獅兒','趙希逢','宋','宋诗','song-poetry','','[]','雪獅塑出對瓊巵，玉笋纖纖露手兒。',32,'全唐诗/poet.song.215000.json','["雪獅塑出對瓊巵，玉笋纖纖露手兒。", "掩口樽前還笑我，指頭皴破作霜皮。"]'),
('152ef8eb-1c39-402a-a02c-e5463ef25c60','和水禽','趙希逢','宋','宋诗','song-poetry','','[]','一水微茫天盡頭，淡煙疎雨暗滄洲。',32,'全唐诗/poet.song.215000.json','["一水微茫天盡頭，淡煙疎雨暗滄洲。", "白鷗遠遠隨潮上，隠映寒蘆兩岸秋。"]'),
('8b6d6732-42e5-49ca-8024-f75d08cdc391','和河魨','趙希逢','宋','宋诗','song-poetry','','[]','楊花飛處賤魚蝦，蕨已抽拳韭迸芽。',64,'全唐诗/poet.song.215000.json','["楊花飛處賤魚蝦，蕨已抽拳韭迸芽。", "此日河魨真劍腹，生風谷虎浪磨牙。", "品題不在八珍數，甘美從今衆口誇。", "一死分明非爲國，罪誠由己不關他。"]'),
('e3e22766-24b3-4572-af78-86e44accb6fa','和群鷗','趙希逢','宋','宋诗','song-poetry','','[]','素衣縞服道家流，羽化江湖作白鷗。',32,'全唐诗/poet.song.215000.json','["素衣縞服道家流，羽化江湖作白鷗。", "清節夷齊無以過，可憐不解餓滄洲。"]'),
('829102c6-a1a6-4df4-8cf8-385977b9d75b','和暮秋聞鴈有懷  其一','趙希逢','宋','宋诗','song-poetry','','[]','數聲鴈送故鄉愁，喚起滄江萬頃秋。',32,'全唐诗/poet.song.215000.json','["數聲鴈送故鄉愁，喚起滄江萬頃秋。", "料想日寒風色慘，可堪寂寞冷沙洲。"]'),
('c3b39835-a667-48cc-bbe9-04146c03f8f4','和暮秋聞鴈有懷  其二','趙希逢','宋','宋诗','song-poetry','','[]','有腹夫誰肯貯愁，笑他宋玉浪悲秋。',32,'全唐诗/poet.song.215000.json','["有腹夫誰肯貯愁，笑他宋玉浪悲秋。", "征鴻縱使聲多恨，怎得無聲過小樓。"]'),
('4698e162-3a66-4061-928d-30d81ce83b0c','和釣鰲行','趙希逢','宋','宋诗','song-poetry','','[]','坎蛙難語江湖闊，百十爲群聲亂聒。',256,'全唐诗/poet.song.215000.json','["坎蛙難語江湖闊，百十爲群聲亂聒。", "細聽不作驚人鳴，閣閣終宵口欲血。", "有時鼓腹怒眼獰，水痕微觸心膽驚。", "居汙可笑妄尊大，蓋亦未之覩海鯨。", "巨鰲又非海鯨比，鬐鬛刺天鱗耀綺。", "首冠靈山負蓬萊，定非區區蝸可餌。", "逆風出沒蹤跡神，氣吐雲霧迷昏昏。", "翻濤振浪力贔屭，涵泳焉知皆聖恩。", "何人獨號文章伯，巷北巷南嗟迫窄。", "翻身跳上崑崙山，沼視具區杯雷澤。", "興來撥棹逝中流，風月輸他第一籌。", "不學嚴陵閑釣瀨，也笑范蠡空扁舟。", "自是天上神仙客，所至魚龍先失色。", "絲綸百尺掌握中，放蕩滄波走趠舶。", "垂綸直待鰲口開，剖開鰲腹聲如雷。", "先將鰲頭獻天子，其餘一手擎歸來。"]'),
('72152e05-e10f-447b-a30f-b68c59e1e1b6','和𥏐齋','趙希逢','宋','宋诗','song-poetry','','[]','斗窗甘隠几，幅障莫垂縑。',48,'全唐诗/poet.song.215000.json','["斗窗甘隠几，幅障莫垂縑。", "摇扇風盈室，停盃月礙簷。", "居然身坐甑，儼若轎垂簾。", "睡許蚊蟁伴，客難燕雀兼。"]'),
('a66164c5-6562-4ca2-9360-1e0e0d9747d6','和𥏐齋雜詠','趙希逢','宋','宋诗','song-poetry','','[]','急風狂雨三月頭，門前一水漲清流。',32,'全唐诗/poet.song.215000.json','["急風狂雨三月頭，門前一水漲清流。", "幾回送客滄江上，愁逐亂紅飛遠洲。"]'),
('fed94f97-cc5a-4f70-a5b8-aeaf0123bb02','和幽居  其一','趙希逢','宋','宋诗','song-poetry','','[]','不用堆錢更買山，群峰前後翠遮闌。',64,'全唐诗/poet.song.215000.json','["不用堆錢更買山，群峰前後翠遮闌。", "玻璃千頃清無滓，星月一天光動寒。", "得趣吟成千首易，逃空降服寸心難。", "夢魂勝境飛難到，只把翠微詩細看。"]'),
('f63bda01-83ce-4b79-a044-643f59ea5a77','和幽居  其二','趙希逢','宋','宋诗','song-poetry','','[]','不因搜句不曾忙，盡日柴門閉短牆。',32,'全唐诗/poet.song.215000.json','["不因搜句不曾忙，盡日柴門閉短牆。", "寄傲北窗閑著眼，任他書卷展風床。"]'),
('a597da1b-7c27-4d5b-adb3-02dd8062d603','和幽居  其三','趙希逢','宋','宋诗','song-poetry','','[]','雲鎖煙封山幾重，翠微深處夕陽紅。',64,'全唐诗/poet.song.215000.json','["雲鎖煙封山幾重，翠微深處夕陽紅。", "徑迂楊柳低迷路，木古藤蘿密蔽空。", "枕漱有泉兼有石，衣披和月也和風。", "落花時或隨流水，恍惚桃源陌與通。"]'),
('b7cef9eb-2950-4a69-963a-3b798e6de418','和幽居  其四','趙希逢','宋','宋诗','song-poetry','','[]','謝他逋客請回車，曳鈎清溪儘可漁。',64,'全唐诗/poet.song.215000.json','["謝他逋客請回車，曳鈎清溪儘可漁。", "一飽何思更何慮，四時無欠亦無餘。", "鷗閑與我兩相似，鳩拙於人百不如。", "金馬玉堂夢難到，凄凉分已愛吾廬。"]'),
('47836d18-b26e-4607-9fb7-d282963efef2','和清富樓  其一','趙希逢','宋','宋诗','song-poetry','','[]','禪味曾參老釋曇，混融萬象就中觀。',64,'全唐诗/poet.song.215000.json','["禪味曾參老釋曇，混融萬象就中觀。", "眼前風月隨時幻，胸次乾坤別樣寬。", "自是臨流清可賦，不成無酒白相看。", "碧潭秋月唯堪比，光瑩吾心一片寒。"]'),
('504f04ab-172b-4d51-93e1-9ec1655618de','和清富樓  其二','趙希逢','宋','宋诗','song-poetry','','[]','對景誰能不賦詩，憑高著眼到幽微。',64,'全唐诗/poet.song.215000.json','["對景誰能不賦詩，憑高著眼到幽微。", "下臨無地仙三島，水遠兼天山四圍。", "豈但追陪閑著句，更應珍重爲留衣。", "北山他日移文去，蕙帳無人月滿扉。"]'),
('90ef5a4d-fa19-4cea-971d-8c3141aa750d','和田家  其一','趙希逢','宋','宋诗','song-poetry','','[]','門外無人水滿池，獨□一犬護門幃。',32,'全唐诗/poet.song.215000.json','["門外無人水滿池，獨□一犬護門幃。", "驀然踴躍聞聲喜，翁媼犁鋤带月歸。"]'),
('028365e0-94a0-4446-855d-cf2bcbe44b7b','和田家  其二','趙希逢','宋','宋诗','song-poetry','','[]','笠蓑懶把一身包，沾體何曾怕雨澆。',32,'全唐诗/poet.song.215000.json','["笠蓑懶把一身包，沾體何曾怕雨澆。", "待得年豐饒一飽，大家買酒醉溪橋。"]'),
('18ebd332-ebcd-4f1a-beae-4a27ec7839a7','和田家  其三','趙希逢','宋','宋诗','song-poetry','','[]','攣耳蓬□色似燒，晚山歸負錯薪翹。',32,'全唐诗/poet.song.215000.json','["攣耳蓬□色似燒，晚山歸負錯薪翹。", "逢人猶作嬌羞態，無力輕將手托腰。"]'),
('279839a9-f5ea-43a8-874f-f148e166af58','和田家  其四','趙希逢','宋','宋诗','song-poetry','','[]','茅舍圍圍護刺笆，寂寥無處著紛挐。',32,'全唐诗/poet.song.215000.json','["茅舍圍圍護刺笆，寂寥無處著紛挐。", "斜陽急趁牛羊下，社酒招邀三兩家。"]'),
('c34706c7-691c-4386-bc86-24d7aaa54b5e','和田家  其五','趙希逢','宋','宋诗','song-poetry','','[]','布衫裁就短平腰，兩兩三三步小橋。',32,'全唐诗/poet.song.215000.json','["布衫裁就短平腰，兩兩三三步小橋。", "粗態撩人在何處，山花鬢畔露村嬌。"]'),
('5cf4b500-1154-4b52-92ff-bffb10cefc66','和田家  其六','趙希逢','宋','宋诗','song-poetry','','[]','豪門方奪吏還催，打戶搥門陸續來。',32,'全唐诗/poet.song.215000.json','["豪門方奪吏還催，打戶搥門陸續來。", "力弊筋駑不入腹，愁腸料得日千回。"]'),
('ac45eb18-11a0-4f28-963a-959f79324cca','和田家  其七','趙希逢','宋','宋诗','song-poetry','','[]','贏糧破曉自薪樵，有米無柴著甚燒。',32,'全唐诗/poet.song.215000.json','["贏糧破曉自薪樵，有米無柴著甚燒。", "更有一般欠區處，淡餐糲飯鼎中焦。"]'),
('fd188116-8469-44c1-b2e6-831b052d3c6d','和田家  其八','趙希逢','宋','宋诗','song-poetry','','[]','秋深場圃已登禾，窗下寒機暫釋梭。',32,'全唐诗/poet.song.215000.json','["秋深場圃已登禾，窗下寒機暫釋梭。", "積貯不教如櫛比，索逋門外苦多多。"]'),
('5a12dcbc-41ea-43e7-87b6-8d257f7fc238','和池亭即事','趙希逢','宋','宋诗','song-poetry','','[]','邂逅那堪皆我輩，一觴一詠覺情深。',64,'全唐诗/poet.song.215000.json','["邂逅那堪皆我輩，一觴一詠覺情深。", "浮榮槐枕半炊夢，清興竹林千古心。", "風漲晴空飛絮急，雨滋冷砌任苔侵。", "池亭小立便幽寂，時聽清泉戛玉音。"]'),
('280ecbfc-12bc-44fa-beea-4cc9db8ff635','和山居','趙希逢','宋','宋诗','song-poetry','','[]','峨雲羞殺鵔鸃冠，半掩山扉日不關。',64,'全唐诗/poet.song.215000.json','["峨雲羞殺鵔鸃冠，半掩山扉日不關。", "林下一般安分好，人生萬事轉頭間。", "忘機禽鳥傍人語，入暮牛羊带日還。", "多少江山足詩料，一簑更好伴鷗閑。"]'),
('e1028983-2de5-4667-a510-31c030e61320','和村居','趙希逢','宋','宋诗','song-poetry','','[]','卜築便幽僻，相逢喜客嘉。',48,'全唐诗/poet.song.215000.json','["卜築便幽僻，相逢喜客嘉。", "充庖鋤野笋，飣坐拗山花。", "竹列階前戟，山排門外衙。", "夜深誰是伴，風月兩三家。"]'),
('4696a1ce-01e1-4a99-8a15-62111e4bc3da','和題溪莊','趙希逢','宋','宋诗','song-poetry','','[]','遥望鞦韆露短牆，垂垂楊柳拂西莊。',64,'全唐诗/poet.song.215000.json','["遥望鞦韆露短牆，垂垂楊柳拂西莊。", "漲天無處著飛絮，過雨殘紅驚褪粧。", "禁火寒庖成辟穀，耐饑醉腹喜如囊。", "人生能有幾寒食，回首東風夢一場。"]'),
('c870e1d8-4905-41fd-9a4c-91282d7f7ff8','和南浦水閣','趙希逢','宋','宋诗','song-poetry','','[]','受風蓬鬢三千丈，何日金釵十二行。',32,'全唐诗/poet.song.215000.json','["受風蓬鬢三千丈，何日金釵十二行。", "逆旅相逢成白眼，可憐空學捧心粧。"]'),
('a9cb8977-74e8-4b0e-8280-51f3f8414758','和南劍水閣','趙希逢','宋','宋诗','song-poetry','','[]','莫把鉛刀比莫邪，匣藏文采鎖煙霞。',64,'全唐诗/poet.song.215000.json','["莫把鉛刀比莫邪，匣藏文采鎖煙霞。", "可憐建水蹤猶梗，因憶洛陽酒與花。", "寸念空勞馳北闕，真經早合誦南華。", "幾回魂斷雲山外，一掬鄉心未到家。"]'),
('160e5555-6ccc-4fb4-8322-ac000b466350','和臨清閣','趙希逢','宋','宋诗','song-poetry','','[]','蔬羹相對潑油葱，無事依僧萬慮空。',64,'全唐诗/poet.song.215000.json','["蔬羹相對潑油葱，無事依僧萬慮空。", "强拾放心看語錄，肯將老眼犯塵紅。", "本來無物臺非鏡，會得何心幡動風。", "料想臨清高閣上，超然不與俗人同。"]'),
('15d019d7-2c0e-40d7-944e-7c9aaf47ed1f','和早春酒家','趙希逢','宋','宋诗','song-poetry','','[]','丰姿越女更吳姬，一笑能令酒力微。',32,'全唐诗/poet.song.215000.json','["丰姿越女更吳姬，一笑能令酒力微。", "步月歸來渾未醉，家人疑自剡溪歸。"]'),
('68a48ac9-f416-415d-a2b2-a5d058108775','和歲寒三友亭','趙希逢','宋','宋诗','song-poetry','','[]','春來到處富群英，浮浪應無實副名。',32,'全唐诗/poet.song.215000.json','["春來到處富群英，浮浪應無實副名。", "獨有歲寒三冷友，凌霜傲雪伴詩盟。"]'),
('920c18b2-c6d7-4db9-8333-a6a017ae04ec','和春閨雜詠','趙希逢','宋','宋诗','song-poetry','','[]','春溪買得柳穿魚，酒興飄飄生室廬。',32,'全唐诗/poet.song.215000.json','["春溪買得柳穿魚，酒興飄飄生室廬。", "試問斗藏能有幾，想應不似步兵厨。"]'),
('a2fd9b70-fc1c-40ff-8310-065f2de21b98','和早春層樓','趙希逢','宋','宋诗','song-poetry','','[]','誰架齊雲百尺樓，舞衫歌扇貯風流。',32,'全唐诗/poet.song.215000.json','["誰架齊雲百尺樓，舞衫歌扇貯風流。", "可憐脚力衰多矣，身未上時心已愁。"]'),
('3cc3edea-7d38-4902-86d7-77cfadb8e083','和借景樓','趙希逢','宋','宋诗','song-poetry','','[]','靜夜延孤月，清觴酌九霞。',48,'全唐诗/poet.song.215000.json','["靜夜延孤月，清觴酌九霞。", "歌聲傳皓齒，悲思類鳴笳。", "竊聽酤樓管，真成獻佛花。", "無端惱狂客，酒興滿天涯。"]'),
('e970d45a-adef-490f-b3e5-66dd811e6efd','和雙桂堂','趙希逢','宋','宋诗','song-poetry','','[]','排雲直上叫天門，路入蟾宮不問人。',64,'全唐诗/poet.song.215000.json','["排雲直上叫天門，路入蟾宮不問人。", "縹緲飛梯高著步，廣寒有殿四無鄰。", "天香飄泛非凡境，仙桂栽培今幾春。", "擬欲和根都拔取，有辭還恐到嚴宸。"]'),
('db33de4a-4e26-49fb-8214-edc073ecf38e','和茅亭','趙希逢','宋','宋诗','song-poetry','','[]','獨坐茅亭濯晚凉，簷前萬影立篔簹。',32,'全唐诗/poet.song.215000.json','["獨坐茅亭濯晚凉，簷前萬影立篔簹。", "數聲蕭琴渾疑雨，細細吹來却有香。"]'),
('09d29d68-05ed-463f-aa9f-46c17aea601d','和斗齋','趙希逢','宋','宋诗','song-poetry','','[]','笑他白足道人曇，準擬來同彌勒龕。',64,'全唐诗/poet.song.215000.json','["笑他白足道人曇，準擬來同彌勒龕。", "懸肘不須誇印大，折腰歸去傲窗南。", "久藏還喜有真一，就飲何妨說後三。", "萍實拾來相對剖，味甜疑是蜜中函。"]'),
('6f5c55c1-3535-441c-8b36-2b42f77e646f','和南浦客邸','趙希逢','宋','宋诗','song-poetry','','[]','路滑山邊石，灘渾水底沙。',48,'全唐诗/poet.song.215000.json','["路滑山邊石，灘渾水底沙。", "曉風動銀燭，夜漏滴簷花。", "身伴燈爲客，心隨夢到家。", "頑雲癡未散，合喚阿香車。"]'),
('a827ce55-be3d-4d03-ba9d-51d3d01edd60','和蛾眉亭','趙希逢','宋','宋诗','song-poetry','','[]','兩山相挾作眉彎，不似橫雲照眼寒。',32,'全唐诗/poet.song.215000.json','["兩山相挾作眉彎，不似橫雲照眼寒。", "料想當年餘半額，至今留得與人看。"]'),
('298228c1-53de-4f2a-9acc-f48471cf1f6b','和題丹青閣  其一','趙希逢','宋','宋诗','song-poetry','','[]','落日殘霞映綺疎，群山橫翠壯規模。',32,'全唐诗/poet.song.215000.json','["落日殘霞映綺疎，群山橫翠壯規模。", "登臨那更添風月，喚作凌煙閣內圖。"]'),
('efc5d380-96e3-4eb1-9e54-678183b99eb7','和題丹青閣  其二','趙希逢','宋','宋诗','song-poetry','','[]','回合江流作夢環，誰將傑閣幻人寰。',64,'全唐诗/poet.song.215000.json','["回合江流作夢環，誰將傑閣幻人寰。", "身騰寒碧臨無池，目斷空青送遠山。", "漁笛一聲蘋蓼末，烟帆幾片水雲間。", "求田問舍非吾事，高卧何人似我閑。"]'),
('9db5d77b-a009-4cfa-bbbb-166d6bea01b3','和再還建上舊店','趙希逢','宋','宋诗','song-poetry','','[]','枉將荆棘滿園栽，不放陽和一點回。',32,'全唐诗/poet.song.215000.json','["枉將荆棘滿園栽，不放陽和一點回。", "何事成陰種桃李，相逢一笑看春來。"]'),
('6a38d4a5-886f-46f2-81f7-a7dbe84db1ed','和登樓晚望  其一','趙希逢','宋','宋诗','song-poetry','','[]','遠山寒暮景，無事試登樓。',48,'全唐诗/poet.song.215000.json','["遠山寒暮景，無事試登樓。", "泛渚鷗終日，書空鴈迎秋。", "朱簾高卷□，雨渡自橫舟。", "望極到何許，水窮天盡頭。"]'),
('82565f6d-59c1-43ae-a2e0-734f0e749247','和登樓晚望  其二','趙希逢','宋','宋诗','song-poetry','','[]','一带江流接太虛，危樓特地幻荒蕪。',64,'全唐诗/poet.song.215000.json','["一带江流接太虛，危樓特地幻荒蕪。", "移來瀛丈三山勝，畫出瀟湘八景圖。", "何處歸帆隨倦鳥，滿汀落日照晴鳬。", "須臾得月添佳致，萬頃寒冰浸玉壺。"]'),
('f70f554c-29e4-4668-ba2f-2d22578e4f9a','和九日溪樓遠望','趙希逢','宋','宋诗','song-poetry','','[]','明時月與日俱陽，君子如何謫遠方。',64,'全唐诗/poet.song.215000.json','["明時月與日俱陽，君子如何謫遠方。", "青眼相看惟舊菊，白衣不至謾空觴。", "橫秋過鴈書晴碧，薄暮屯雲带夕黄。", "獨倚危欄閑著句，慚無五字比韋郎。"]'),
('3dd2b921-ac7c-4b70-9ac8-fc1a31ea59d0','和晚醉金樓','趙希逢','宋','宋诗','song-poetry','','[]','少年曾客帝王州，醉倒不知何處樓。',32,'全唐诗/poet.song.215000.json','["少年曾客帝王州，醉倒不知何處樓。", "厭飲清歡成逐夜，時邀明月入簾鈎。"]'),
('c7ecfca6-582b-411f-9e30-e9d4f27239f9','和題蓮花壁間','趙希逢','宋','宋诗','song-poetry','','[]','亂雲翠擁千層蓋，拳落時聽雨打聲。',32,'全唐诗/poet.song.215000.json','["亂雲翠擁千層蓋，拳落時聽雨打聲。", "長笛隔江吹晚霽，水光月色兩分明。"]'),
('f7774608-f546-4488-8d11-86053c75bfce','和別館即事','趙希逢','宋','宋诗','song-poetry','','[]','溪摇日色遠生光，飛絮隨風上下狂。',64,'全唐诗/poet.song.215000.json','["溪摇日色遠生光，飛絮隨風上下狂。", "纈間群花連野發，錦添稚笋滿林香。", "斜陽落盡千山晚，带月歸來一葦航。", "老矣追懽非我事，效顰子美訪黄娘。"]'),
('f8f7442a-5528-43f0-9e40-46e0a7c5ff77','和閲明妃傳  其一','趙希逢','宋','宋诗','song-poetry','','[]','安邊良將不收功，公主如何嫁犬戎。',32,'全唐诗/poet.song.215000.json','["安邊良將不收功，公主如何嫁犬戎。", "若使外孫知大父，單于不自殺其翁。"]'),
('622123e1-9d55-4fab-b19a-306d994d9102','和閲明妃傳  其二','趙希逢','宋','宋诗','song-poetry','','[]','青塚今成土一堆，嬌容埋玉恨難開。',32,'全唐诗/poet.song.215000.json','["青塚今成土一堆，嬌容埋玉恨難開。", "無端當日毛延壽，輕把毫端巧作媒。"]'),
('de02e67d-6175-4525-a3b4-f0451083f674','和讀史','趙希逢','宋','宋诗','song-poetry','','[]','作史先須正論持，是非便把聖經稽。',64,'全唐诗/poet.song.215000.json','["作史先須正論持，是非便把聖經稽。", "兄誅直筆周公弟，母出聲言孔伋妻。", "惡戒欺君書指鹿，報嘉食客載鳴雞。", "至今左右嚴官守，誰復將桐戲剪圭。"]'),
('25c284fa-25ab-48fb-baa1-026e3ca6299b','和讀漢史','趙希逢','宋','宋诗','song-poetry','','[]','丈夫一死誰能惜，直把微軀脫漢王。',32,'全唐诗/poet.song.215000.json','["丈夫一死誰能惜，直把微軀脫漢王。", "不學貪生求富貴，族夷身戮恨尤長。"]'),
('0a32ee3a-03be-4830-9d93-46c005d69d1e','和讀蘇武李陵司馬遷傳  其一','趙希逢','宋','宋诗','song-poetry','','[]','不愛其身過易于，盡判一死外無餘。',32,'全唐诗/poet.song.215000.json','["不愛其身過易于，盡判一死外無餘。", "麒麟閣上沒公議，却把芳名最後書。"]'),
('a9b41905-7698-4a69-9597-a1a189f20dee','和讀蘇武李陵司馬遷傳  其二','趙希逢','宋','宋诗','song-poetry','','[]','携手河梁一別歸，衷情盡寄五言詩。',32,'全唐诗/poet.song.215000.json','["携手河梁一別歸，衷情盡寄五言詩。", "故人妻子存乎否，因甚詩中無片辭。"]'),
('76da9b77-d5dc-4d4e-8b1c-fce5f2313182','和讀張子房傳  其一','趙希逢','宋','宋诗','song-poetry','','[]','三傑留侯不敢名，肯隨走狗例鬺烹。',32,'全唐诗/poet.song.215000.json','["三傑留侯不敢名，肯隨走狗例鬺烹。", "眼中早已無高粉，子擊何嘗有呂生。"]'),
('c1447348-e7b3-4ed4-aaca-86fb64ee56ab','和讀張子房傳  其二','趙希逢','宋','宋诗','song-poetry','','[]','當年罝兔視亡秦，一擊之餘果莫尋。',32,'全唐诗/poet.song.215000.json','["當年罝兔視亡秦，一擊之餘果莫尋。", "堪笑乘輿森萬騎，也無一個眼開人。"]'),
('a4e15a21-f195-4d39-a631-5e1df08d4842','和夜讀離騷','趙希逢','宋','宋诗','song-poetry','','[]','孤忠烈日與秋霜，千古英魂在水央。',64,'全唐诗/poet.song.215000.json','["孤忠烈日與秋霜，千古英魂在水央。", "掩卷長吁悲往事，挑燈痛飲坐寒窗。", "始終與國當同戚，憤抑沉身亦近狂。", "狼跋等詩今可覆，怡然意味最深長。"]'),
('17d52cec-3b2e-4794-aa73-957f9050384a','偈頌五十一首  其一','釋大觀','宋','宋诗','song-poetry','','[]','真不立，妄本空。',34,'全唐诗/poet.song.215000.json','["真不立，妄本空。", "七凹八凸，四闢六通。", "松聲雜雨山長靜，春色带寒花自紅。"]'),
('b8196257-a9af-45cf-ab52-028b095d4c6d','偈頌五十一首  其二','釋大觀','宋','宋诗','song-poetry','','[]','滴滴簷前聞不聞，鏡清無舌與誰論。',32,'全唐诗/poet.song.215000.json','["滴滴簷前聞不聞，鏡清無舌與誰論。", "夜來幾陣尤霶霈，欺壓斜陽綠到根。"]'),
('29dba2bc-ce53-4930-893a-0fe8738d6928','偈頌五十一首  其三','釋大觀','宋','宋诗','song-poetry','','[]','空手把鉏頭，男命怕羅睺。',48,'全唐诗/poet.song.215000.json','["空手把鉏頭，男命怕羅睺。", "步行騎水牛，石虎生肉彪。", "人從橋上過，橋流水不流。", "羲和鞭白日，少昊行清秋。"]'),
('6ce7b3e5-aa68-4b2d-8494-5d28fff08b1b','偈頌五十一首  其四','釋大觀','宋','宋诗','song-poetry','','[]','覓之不得，不覓奚彰。',36,'全唐诗/poet.song.215000.json','["覓之不得，不覓奚彰。", "戳瞎頂門，煒煒煌煌。", "桑疇雨過羅紈膩，麥壟風來餠餌香。"]'),
('13414753-95a3-43d4-b4ec-2c6ce7736107','偈頌五十一首  其五','釋大觀','宋','宋诗','song-poetry','','[]','開口失，閉口喪。',18,'全唐诗/poet.song.215000.json','["開口失，閉口喪。", "脫白露浄，矢在絃上。"]'),
('10cef464-ceb2-49b2-b253-81229a152864','偈頌五十一首  其六','釋大觀','宋','宋诗','song-poetry','','[]','十二月十五，石人相耳語。',40,'全唐诗/poet.song.215000.json','["十二月十五，石人相耳語。", "梅開寒谷春，雪滴晴簷雨。", "太分明，何所覩，南泉不打鹽官鼓。"]'),
('58f69853-7362-46dc-87fa-4f404e8f0607','偈頌五十一首  其七','釋大觀','宋','宋诗','song-poetry','','[]','不動本位，瑞應人間。',63,'全唐诗/poet.song.215000.json','["不動本位，瑞應人間。", "冠羣靈而首出，攝大千於毫端。", "萬彙熙熙兮春臺之樂，萬邦納納兮磐石之安。", "從教戴天履地，擊壤鼓腹兮不知天地之寬。"]'),
('8e8d5b11-cd09-4ae0-b5f3-accc9a7c388a','偈頌五十一首  其八','釋大觀','宋','宋诗','song-poetry','','[]','作者相逢，一西一東。',22,'全唐诗/poet.song.215000.json','["作者相逢，一西一東。", "斷碑刊白字，當道種青松。"]'),
('b6e139da-45ce-4bd1-829c-dc27a1f79503','偈頌五十一首  其九','釋大觀','宋','宋诗','song-poetry','','[]','三世諸佛不知有，覆水難收。',52,'全唐诗/poet.song.215000.json','["三世諸佛不知有，覆水難收。", "狸奴白牯却知有，頭上安頭。", "白日西沈，黄河北流。", "推倒門前案山子，從教坐地看揚州。"]'),
('afe768a2-bc56-4515-8fb7-6a543804e11a','偈頌五十一首  其一○','釋大觀','宋','宋诗','song-poetry','','[]','一入咸陽盡舊游，春風臺榭對芳洲。',32,'全唐诗/poet.song.215000.json','["一入咸陽盡舊游，春風臺榭對芳洲。", "非關好景留人醉，自是行人醉不休。"]'),
('dc7b45b8-9def-4ff1-90cd-e7c000287f2d','偈頌五十一首  其一一','釋大觀','宋','宋诗','song-poetry','','[]','三疊秋風古調清，移商換徵許誰聽。',32,'全唐诗/poet.song.215000.json','["三疊秋風古調清，移商換徵許誰聽。", "周郎一顧揚鞭去，雲外數峰江上青。"]'),
('e410d684-239a-4280-9d8e-bc5a2ef85e79','偈頌五十一首  其一二','釋大觀','宋','宋诗','song-poetry','','[]','天門日射黄金榜，宮殿晴薰赤羽旗。',32,'全唐诗/poet.song.215000.json','["天門日射黄金榜，宮殿晴薰赤羽旗。", "四海九州齊入貢，春風又到萬年枝。"]'),
('0e3d12e2-7342-48c5-9398-3d39c4be303d','偈頌五十一首  其一三','釋大觀','宋','宋诗','song-poetry','','[]','世尊不說說，正月孟春猶寒。',26,'全唐诗/poet.song.215000.json','["世尊不說說，正月孟春猶寒。", "迦葉不聞聞，二月仲春漸暄。"]'),
('5ba1816b-8e7e-4d0f-a1e6-c0a20aadc1dc','偈頌五十一首  其一四','釋大觀','宋','宋诗','song-poetry','','[]','倒拈折筯攪滄溟，無限魚龍暗裏驚。',32,'全唐诗/poet.song.215000.json','["倒拈折筯攪滄溟，無限魚龍暗裏驚。", "一笑機關輕捩轉，東湖午夜月華明。"]'),
('d177d79a-f982-47d9-afb9-60ed3cd936ff','偈頌五十一首  其一五','釋大觀','宋','宋诗','song-poetry','','[]','終日忙忙，秀支替戾剛。',46,'全唐诗/poet.song.215000.json','["終日忙忙，秀支替戾剛。", "那事無妨，僕谷劬禿當。", "不動智佛，長時七出八沒。", "憍梵鉢提，對人倒腹傾腸。"]'),
('5c942263-59c3-4807-8d69-d8fab8bbadc1','偈頌五十一首  其一六','釋大觀','宋','宋诗','song-poetry','','[]','礙塞處，有通疏。',32,'全唐诗/poet.song.215000.json','["礙塞處，有通疏。", "看不足，綽有餘。", "千古華山山下路，輸他潘閬倒騎馿。"]'),
('39aede37-78eb-421e-b7c4-932cd1f70dda','偈頌五十一首  其一七','釋大觀','宋','宋诗','song-poetry','','[]','凌霄跨竈，凌滅吾宗。',48,'全唐诗/poet.song.215000.json','["凌霄跨竈，凌滅吾宗。", "危分險布，鐵網千重。", "三更白如晝，掇轉太虛空。", "幻智庵前覓不得，蕭蕭松竹引清風。"]'),
('128171bb-56cf-4582-ad3a-a94213ed15a7','偈頌五十一首  其一八','釋大觀','宋','宋诗','song-poetry','','[]','平常是道，不涉平常。',36,'全唐诗/poet.song.215000.json','["平常是道，不涉平常。", "顛來倒去，規圓矩方。", "林花著雨胭脂落，水荇牽風翠带長。"]'),
('93e7faa8-0753-4c2b-9b38-f8c05d106a60','偈頌五十一首  其一九','釋大觀','宋','宋诗','song-poetry','','[]','峰巒秀異，鶴不停機。',20,'全唐诗/poet.song.215000.json','["峰巒秀異，鶴不停機。", "靈木迢然，鳳無依倚。"]'),
('13f89867-defa-4a42-9bf2-84f40b175ade','偈頌五十一首  其二○','釋大觀','宋','宋诗','song-poetry','','[]','孤危不立，坐斷千差。',20,'全唐诗/poet.song.215000.json','["孤危不立，坐斷千差。", "有笑陪賓，無贓驗賊。"]'),
('4b7876ed-d4ab-48d0-a552-e2a81e143a78','偈頌五十一首  其二一','釋大觀','宋','宋诗','song-poetry','','[]','取不得舍不得，不可得中只麽得。',35,'全唐诗/poet.song.215000.json','["取不得舍不得，不可得中只麽得。", "萬籟收聲兮萬象自閑，秋水吞空兮秋天一色。"]'),
('52977f6b-05fc-4838-96a8-cec664a6230e','偈頌五十一首  其二二','釋大觀','宋','宋诗','song-poetry','','[]','日復日，夜復夜。',20,'全唐诗/poet.song.215000.json','["日復日，夜復夜。", "竇八布衫穿，虛空生柄欛。"]'),
('7ae7c936-6651-4584-b47b-9839bff4178e','偈頌五十一首  其二三','釋大觀','宋','宋诗','song-poetry','','[]','寬廓非外，寂寥非內。',36,'全唐诗/poet.song.215000.json','["寬廓非外，寂寥非內。", "拽轉虛空，須彌粉碎。", "土宿頷下髭鬚長，波斯眼深鼻孔大。"]'),
('1ce64af5-9478-486a-bf5a-248c9ecfd6ba','偈頌五十一首  其二四','釋大觀','宋','宋诗','song-poetry','','[]','圓覺伽藍，牛頭北馬頭南。',34,'全唐诗/poet.song.215000.json','["圓覺伽藍，牛頭北馬頭南。", "平等性智，七十三八十四。", "齩定牙關，四稜蹋地。"]'),
('c5e523c8-836f-47b8-8b4c-04e660c36db1','偈頌五十一首  其二五','釋大觀','宋','宋诗','song-poetry','','[]','久晴還雨，禾山解打鼓。',43,'全唐诗/poet.song.215000.json','["久晴還雨，禾山解打鼓。", "久雨還晴，普化愛摇鈴。", "錢是足陌，物是定價，趙州直得五年分疏不下。"]'),
('e41d15b5-b815-4646-a7a1-902e54df1b53','偈頌五十一首  其二六','釋大觀','宋','宋诗','song-poetry','','[]','井梧葉葉響颼飀，攪動明河萬里秋。',44,'全唐诗/poet.song.215000.json','["井梧葉葉響颼飀，攪動明河萬里秋。", "楖𣗖摩挲生遠興，白雲流水共悠悠。", "不是寒山子，誰臨古渡頭。"]'),
('62e1d8ad-4c8e-4dd2-a2b9-40601fa5b440','偈頌五十一首  其二七','釋大觀','宋','宋诗','song-poetry','','[]','一見便見，臨崖滸眼。',20,'全唐诗/poet.song.215000.json','["一見便見，臨崖滸眼。", "一得永得，坐井觀天。"]'),
('975aca37-656c-4d38-8d29-aea710a43f6b','偈頌五十一首  其二八','釋大觀','宋','宋诗','song-poetry','','[]','秋光杪暮，霜吹凄肅。',70,'全唐诗/poet.song.215000.json','["秋光杪暮，霜吹凄肅。", "無位真人，草眠露宿。", "慈雲忍俊不禁，試爲臨風招之，式微式微胡不歸。", "胡不歸，一堂和氣春熙熙。", "三條椽下堪自怡，東挨西倚終奚爲。"]'),
('9386385b-a333-497c-8348-e6a2e1fea4e5','偈頌五十一首  其二九','釋大觀','宋','宋诗','song-poetry','','[]','春風緩，春日暖。',46,'全唐诗/poet.song.215000.json','["春風緩，春日暖。", "山鳥嘲啾，山花爛熳。", "達磨面壁九年，歸宗拭壞雙眼。", "諸人還會麽，南山粲，白石爛。"]'),
('34fdd960-74a0-4952-ac06-dec28afde563','偈頌五十一首  其三○','釋大觀','宋','宋诗','song-poetry','','[]','擁之不聚，撥之不散。',20,'全唐诗/poet.song.215000.json','["擁之不聚，撥之不散。", "聽之不聞，覷之不見。"]'),
('05bd11c0-eff5-46e1-bfd1-9759e48948c9','偈頌五十一首  其三一','釋大觀','宋','宋诗','song-poetry','','[]','生也如是，白骼樹頭魚扇子。',74,'全唐诗/poet.song.215000.json','["生也如是，白骼樹頭魚扇子。", "死也如是，泥牛飲乾東澗水。", "更待說偈，舜若多神三赤喙。", "討甚巴鼻，醜惡重童無處洗。", "徑山供盡死款，慈雲也不相饒，從來生死不同條。"]'),
('7a8f9da4-cb3e-45e3-a348-fb0de1c9a0b3','偈頌五十一首  其三二','釋大觀','宋','宋诗','song-poetry','','[]','不慕諸聖，不重己靈。',44,'全唐诗/poet.song.215000.json','["不慕諸聖，不重己靈。", "櫜弓戢矢，坐享太平。", "德山有棒，正好束之高閣。", "臨濟有喝，也應無處施呈。"]'),
('0a1856b0-f7b4-4db7-ba6d-9b3503b97d3e','偈頌五十一首  其三三','釋大觀','宋','宋诗','song-poetry','','[]','蓮開陸地，海湧鼇山。',26,'全唐诗/poet.song.215000.json','["蓮開陸地，海湧鼇山。", "不知今夕是何夕，山林城市約同看。"]'),
('e88e839e-060d-43e8-870f-db57759455b1','偈頌五十一首  其三四','釋大觀','宋','宋诗','song-poetry','','[]','閙浩浩，靜悄悄。',28,'全唐诗/poet.song.215000.json','["閙浩浩，靜悄悄。", "古策風高，玉壺春曉。", "左顧無瑕，右盼已老。"]'),
('bbc952b7-b34c-4374-9124-2e40c1d4481d','偈頌五十一首  其三五','釋大觀','宋','宋诗','song-poetry','','[]','三百餘會，盡是死句。',38,'全唐诗/poet.song.215000.json','["三百餘會，盡是死句。", "娑羅樹間，翻成活句。", "活中死，死中活，水綠山青，天寬地闊。"]'),
('055824e1-bf7c-4c00-b0de-d43211d09fa4','偈頌五十一首  其三六','釋大觀','宋','宋诗','song-poetry','','[]','癡癡兀兀，乖乖厓厓。',36,'全唐诗/poet.song.215000.json','["癡癡兀兀，乖乖厓厓。", "水乳和同，肝膽楚越。", "共倚闌干舒笑眼，四山松桂動秋風。"]'),
('829b8a1c-0d4f-4f20-824a-beaf9bd4425c','偈頌五十一首  其三七','釋大觀','宋','宋诗','song-poetry','','[]','片段悠揚點太空，卷舒無地覓行蹤。',32,'全唐诗/poet.song.215000.json','["片段悠揚點太空，卷舒無地覓行蹤。", "業風有意相交輥，又復從龍過別峰。"]'),
('2087dd9d-216f-4337-8d45-1acc55a0743b','偈頌五十一首  其三八','釋大觀','宋','宋诗','song-poetry','','[]','暗瓦霜凝寒客夢，晴窗日透借朝溫。',60,'全唐诗/poet.song.215000.json','["暗瓦霜凝寒客夢，晴窗日透借朝溫。", "不能緘口圍爐坐，斂袂空趨畫戟門。", "堪悲堪笑不動尊，天津橋看弄胡孫。", "此意與誰論，長者子無裩。"]'),
('5239d702-47cb-4017-919d-7e71cdd300a5','偈頌五十一首  其三九','釋大觀','宋','宋诗','song-poetry','','[]','淮雲慘淡，淮水枯竭。',50,'全唐诗/poet.song.215000.json','["淮雲慘淡，淮水枯竭。", "徑山老子無言說，喝得巖厓成百裂，末後全提太親切。", "笑不徹，哭不徹，憍梵鉢提驚吐舌。"]'),
('376c1485-a0a9-497f-a4ba-93ec55fc900a','偈頌五十一首  其四○','釋大觀','宋','宋诗','song-poetry','','[]','衆毛成毬，衆水成流。',37,'全唐诗/poet.song.215000.json','["衆毛成毬，衆水成流。", "衆人成市，衆土成丘。", "育王聚衆作夏，今夏東州，明夏西州。"]'),
('c5b9f62c-06d7-4ca5-94ef-292c62fc748f','偈頌五十一首  其四一','釋大觀','宋','宋诗','song-poetry','','[]','霜風未老，愛景如春。',38,'全唐诗/poet.song.215000.json','["霜風未老，愛景如春。", "空洞絕朕，彌滿剎塵。", "今日明日，瞥喜瞥嗔，暗把風流賣與人。"]'),
('5ff339f1-ad6b-4990-93cf-6c3f896caa5b','偈頌五十一首  其四二','釋大觀','宋','宋诗','song-poetry','','[]','九日無白醪，紫萸烹茗好。',48,'全唐诗/poet.song.215000.json','["九日無白醪，紫萸烹茗好。", "今古說登高，誰踏古皇道。", "落葉鼓真風，黄菊說玄要。", "自笑太無端，相牽入荒草。"]'),
('a3bf9bd3-a09b-4a71-9998-59ebfa298db9','偈頌五十一首  其四三','釋大觀','宋','宋诗','song-poetry','','[]','春雨如膏，春雲如鶴。',50,'全唐诗/poet.song.215000.json','["春雨如膏，春雲如鶴。", "春草離離，春花灼灼。", "騎聲蓋色兮何太乖張，毫忽不形兮填溝塞壑。", "直往無前，猶欠一著。"]'),
('698c6565-e153-4e3f-a374-00a84b7a61cc','偈頌五十一首  其四四','釋大觀','宋','宋诗','song-poetry','','[]','慈深願廣育聖明，首出萬國之儀刑。',32,'全唐诗/poet.song.215000.json','["慈深願廣育聖明，首出萬國之儀刑。", "壽崇功德無能名，妙高山色青又青。"]'),
('0d4ac0f1-40f7-402d-af58-f6f77eab5e6b','偈頌五十一首  其四五','釋大觀','宋','宋诗','song-poetry','','[]','行不到處行一步，甜瓜徹蒂甜。',44,'全唐诗/poet.song.215000.json','["行不到處行一步，甜瓜徹蒂甜。", "說不到處說一句，苦瓠連根苦。", "掃盡從前閑佛祖，發機須是千鈞弩。"]'),
('57b3c65b-bc7e-465f-91d7-ee24f5cac474','偈頌五十一首  其四六','釋大觀','宋','宋诗','song-poetry','','[]','律非縛，禪非脫。',51,'全唐诗/poet.song.215000.json','["律非縛，禪非脫。", "蝴蝶夢莊周，周公制禮樂。", "會則事同一家，不會則萬別千差。", "一片白雲生嶺上，幾回開了又還遮。"]'),
('af931a9c-73c3-424d-b949-71317b8faaab','偈頌五十一首  其四七','釋大觀','宋','宋诗','song-poetry','','[]','春色融融，花氣濛濛。',50,'全唐诗/poet.song.215000.json','["春色融融，花氣濛濛。", "六窗俱不鑰，當處不留蹤。", "危欄同徧倚，身在寂寥中。", "幾欲全提先漏洩，滑唇黄鳥弄春風。"]'),
('09662cef-26d2-46f4-9aff-d3b2b363b1f0','偈頌五十一首  其四八','釋大觀','宋','宋诗','song-poetry','','[]','簸土揚塵，金剛正體。',36,'全唐诗/poet.song.215000.json','["簸土揚塵，金剛正體。", "七顛八倒，大寂定門。", "排空煙嶂添愁色，著雨林花带淚痕。"]'),
('1a000734-3a25-46b0-8490-00d7908c15ad','偈頌五十一首  其四九','釋大觀','宋','宋诗','song-poetry','','[]','見見之時，雨洗淡紅桃萼嫩。',52,'全唐诗/poet.song.215000.json','["見見之時，雨洗淡紅桃萼嫩。", "見非是見，風摇淺碧柳絲輕。", "見猶離見，白雲影裏怪石露。", "見莫能及，流水光中古木清。"]'),
('7477428a-4b07-478d-a20b-35e317a204cb','偈頌五十一首  其五○','釋大觀','宋','宋诗','song-poetry','','[]','監本倔强，匙挑不上。',61,'全唐诗/poet.song.215000.json','["監本倔强，匙挑不上。", "馽空雲蒂補虛空，陸地滔天翻白浪。", "暗中拈出定命竿，鶻眼鷹睛迷向當。", "老和尚爲誰沒齒更穿齦，從教疑殺天下人。"]'),
('2a60d012-41c2-402d-b241-6898335922d6','偈頌五十一首  其五一','釋大觀','宋','宋诗','song-poetry','','[]','荆棘鋒刃叢，洞房絲竹裏。',28,'全唐诗/poet.song.215000.json','["荆棘鋒刃叢，洞房絲竹裏。", "威鳳何須住碧梧，卧龍終不鑑止水。"]'),
('63f8ce8c-02c7-40ed-9015-31c785d274a0','頌古十七首  其一','釋大觀','宋','宋诗','song-poetry','','[]','乾坤雖有作，太平本無象。',24,'全唐诗/poet.song.215000.json','["乾坤雖有作，太平本無象。", "赫日正中天，去却脩羅掌。"]'),
('99ba4a63-e9a8-4cbd-a9ca-c7b13822c217','頌古十七首  其二','釋大觀','宋','宋诗','song-poetry','','[]','自是兵家貴伐謀，鏖鋒擒敵未爲優。',32,'全唐诗/poet.song.215000.json','["自是兵家貴伐謀，鏖鋒擒敵未爲優。", "沈沈刁斗三更月，玉帳威行紫塞秋。"]'),
('54715c3f-bbc2-4eb6-afeb-02c3a13c0121','頌古十七首  其三','釋大觀','宋','宋诗','song-poetry','','[]','忽看龍舟壓浪飛，鼓聲催促笛聲悲。',32,'全唐诗/poet.song.215000.json','["忽看龍舟壓浪飛，鼓聲催促笛聲悲。", "錦標到手還輕放，轉得頭來事已非。"]'),
('a098f3dd-3b22-4e4e-9500-9d377414c886','頌古十七首  其四','釋大觀','宋','宋诗','song-poetry','','[]','故園紅紫自芳菲，不在春風著意吹。',32,'全唐诗/poet.song.215000.json','["故園紅紫自芳菲，不在春風著意吹。", "待得征人重回首，枝頭香雪已紛披。"]'),
('3cd6c46d-0b18-455b-b92c-56ff79e57d17','頌古十七首  其五','釋大觀','宋','宋诗','song-poetry','','[]','纔是貪他便著他，其間半露又全遮。',32,'全唐诗/poet.song.215000.json','["纔是貪他便著他，其間半露又全遮。", "只今誰是傍觀者，一笑何勞掛齒牙。"]'),
('dee6459b-ee51-49e9-a745-c4c0740c72f3','頌古十七首  其六','釋大觀','宋','宋诗','song-poetry','','[]','吹無孔笛，和氈拍版。',36,'全唐诗/poet.song.215000.json','["吹無孔笛，和氈拍版。", "父子和同，冰炭相反。", "末上之機果若何，定州元出花瓷碗。"]'),
('39cd486f-f0a3-40f6-9ac6-6a1358d2daac','頌古十七首  其七','釋大觀','宋','宋诗','song-poetry','','[]','一鼓薰風至自南，再行璧月掛蒼杉。',32,'全唐诗/poet.song.215000.json','["一鼓薰風至自南，再行璧月掛蒼杉。", "錦筵公子方沈醉，白雪幽蘭空再三。"]'),
('d5edca9a-f996-4569-ab59-627172dbb978','頌古十七首  其八','釋大觀','宋','宋诗','song-poetry','','[]','咄哉古墓一狐精，化作人來耍弄人。',32,'全唐诗/poet.song.215000.json','["咄哉古墓一狐精，化作人來耍弄人。", "華表未然先敗也，至今無地可容身。"]'),
('90b5703d-2365-463b-89bc-6c19e7f95c36','頌古十七首  其九','釋大觀','宋','宋诗','song-poetry','','[]','休論鳳箭射烏巢，看取虛弓落九包。',32,'全唐诗/poet.song.215000.json','["休論鳳箭射烏巢，看取虛弓落九包。", "收放若爲逃羿手，控弦傍助亦徒勞。"]'),
('4c2deef2-ab66-4806-a5f3-dd8cc84337e1','頌古十七首  其一○','釋大觀','宋','宋诗','song-poetry','','[]','兩聲不合共交肩，毒手纔施報老拳。',32,'全唐诗/poet.song.215000.json','["兩聲不合共交肩，毒手纔施報老拳。", "今日上天同碧落，明朝入地共黄泉。"]'),
('80b7a5e5-578c-48fc-942e-77dca6e78562','頌古十七首  其一一','釋大觀','宋','宋诗','song-poetry','','[]','客泛靈槎犯斗牛，銀河碧海暗通流。',32,'全唐诗/poet.song.215000.json','["客泛靈槎犯斗牛，銀河碧海暗通流。", "昆侖推倒無依倚，萬里長空一樣秋。"]'),
('185dd08f-ae10-4015-bd51-bb7c0c96b8c3','頌古十七首  其一二','釋大觀','宋','宋诗','song-poetry','','[]','賈勇揚旌無大敵，看看身已陷重圍。',32,'全唐诗/poet.song.215000.json','["賈勇揚旌無大敵，看看身已陷重圍。", "要令奪角衝關去，駕與青龍不解騎。"]'),
('343c909b-2cf4-4037-b06e-a4b963e1915a','頌古十七首  其一三','釋大觀','宋','宋诗','song-poetry','','[]','饑人貪食良農粟，渴漢錯飲蠱家水。',32,'全唐诗/poet.song.215000.json','["饑人貪食良農粟，渴漢錯飲蠱家水。", "對面還成千里遥，賊人有智過君子。"]'),
('67d48e7f-1206-42b5-b107-53a623a667e4','頌古十七首  其一四','釋大觀','宋','宋诗','song-poetry','','[]','張公屋畔盡桑麻，李老園中只種花。',32,'全唐诗/poet.song.215000.json','["張公屋畔盡桑麻，李老園中只種花。", "滿目風光無限好，笑呼銀盌酌流霞。"]'),
('57c6817c-9390-4e1f-8676-dbba5facc2ac','頌古十七首  其一五','釋大觀','宋','宋诗','song-poetry','','[]','江面無風平似鏡，轉頭變態互呈新。',32,'全唐诗/poet.song.215000.json','["江面無風平似鏡，轉頭變態互呈新。", "馮夷駕浪險難涉，漁父操舟妙若神。"]'),
('98f192ea-bf08-48f9-8b72-affb6b2cc02e','頌古十七首  其一六','釋大觀','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','葉脫風高天地秋，長江衮衮只東流。',32,'全唐诗/poet.song.215000.json','["葉脫風高天地秋，長江衮衮只東流。", "行人不折離亭柳，羌笛空吹落日愁。"]'),
('18908465-b714-426b-9350-d788684451d3','頌古十七首  其一七','釋大觀','宋','宋诗','song-poetry','','[]','善戰何如善用謀，孫吳兵法豈同儔。',32,'全唐诗/poet.song.215000.json','["善戰何如善用謀，孫吳兵法豈同儔。", "秋風古塞看形勢，一樣邊聲兩樣愁。"]'),
('abb505f6-8c88-4882-aeb7-0ae4d022ba1a','出山相贊','釋大觀','宋','宋诗','song-poetry','','[]','入山去龍章鳳質，出山來敗衣勃率。',30,'全唐诗/poet.song.215000.json','["入山去龍章鳳質，出山來敗衣勃率。", "更將悟底分疎，添得一場𣸩淈。"]'),
('178a245b-6354-46ad-9be8-17fd4e18fbfb','補陀大士贊','釋大觀','宋','宋诗','song-poetry','','[]','海天寥泬，海岸孤絕。',28,'全唐诗/poet.song.215000.json','["海天寥泬，海岸孤絕。", "見得親切，虛空釘橛。", "怒濤舂碎巖前月。"]'),
('8cb285ba-089b-47ef-91e0-b80470565d19','馬郎婦贊','釋大觀','宋','宋诗','song-poetry','','[]','倩盼動嬋娟，常持六萬言。',24,'全唐诗/poet.song.215000.json','["倩盼動嬋娟，常持六萬言。", "金沙灘上月，五欲浪中翻。"]'),
('4fbdd91b-4004-4749-a326-76c344778340','越王感應大士贊','釋大觀','宋','宋诗','song-poetry','','[]','海山嶄絕，海濤舂撞。',74,'全唐诗/poet.song.215000.json','["海山嶄絕，海濤舂撞。", "海風披拂，海雲飄揚。", "仰慧日之破暗兮誰其迷照，觀普門之不鑰兮去不至方。", "感應道交，叵測叵量。", "越國投誠，菩提影現。", "我作是說，增金以黄。"]'),
('9ba1f766-5ffd-41f7-968d-3b436fc307c5','過水布袋贊','釋大觀','宋','宋诗','song-poetry','','[]','深則厲，淺則揭。',18,'全唐诗/poet.song.215000.json','["深則厲，淺則揭。", "七十二汀，無風浪起。"]'),
('dc825b26-47fb-4bef-919b-5b16938c836d','布袋贊','釋大觀','宋','宋诗','song-poetry','','[]','兜率陀天，長汀管界。',32,'全唐诗/poet.song.215000.json','["兜率陀天，長汀管界。", "潑布袋打開，自買還自賣。", "眨上眉毛，敗也敗也。"]'),
('cad946fc-2318-4af9-8f65-dd3a2f0ba683','維摩贊','釋大觀','宋','宋诗','song-poetry','','[]','環堵室，十笏地。',18,'全唐诗/poet.song.215000.json','["環堵室，十笏地。", "咄哉維摩，病在者裏。"]'),
('7b643061-df0b-4657-b8c7-650c74f682d8','豐干寒拾贊','釋大觀','宋','宋诗','song-poetry','','[]','來何處，去何之。',26,'全唐诗/poet.song.215000.json','["來何處，去何之。", "與二子，何所期。", "虎視眈眈，陰飈凄凄。"]'),
('feaba144-eaaa-422c-8a4e-a172b632f9ce','寒山掃地贊','釋大觀','宋','宋诗','song-poetry','','[]','橫也掃，豎也掃。',18,'全唐诗/poet.song.215000.json','["橫也掃，豎也掃。", "七佛之師，狼藉不少。"]'),
('47a300e9-0c69-447b-af8f-6ccc9a721fea','拾得收菜滓贊','釋大觀','宋','宋诗','song-poetry','','[]','一機不副，截斷千差。',35,'全唐诗/poet.song.215000.json','["一機不副，截斷千差。", "瓶瀉妙答，綴齒粘牙。", "何如在國清寺裏，偷佛飯食菜滓。"]'),
('b5b529d0-aff4-474a-94eb-a5bac728fff1','渡蘆達磨贊','釋大觀','宋','宋诗','song-poetry','','[]','南頭問，不善答。',48,'全唐诗/poet.song.215000.json','["南頭問，不善答。", "北頭去，不相合。", "自謂踏得著，全然沒交涉。", "無枝葉處，枝葉縱橫。", "無風波處，風波匼匝。"]'),
('e7c6bdff-da2b-43d7-8089-bdf38f76d6c5','達磨贊','釋大觀','宋','宋诗','song-poetry','','[]','一花移自西，五葉香燦爛。',34,'全唐诗/poet.song.215000.json','["一花移自西，五葉香燦爛。", "嗅蕊與尋芳，紛如蜂蝶亂。", "地闊天寬，難圖滋蔓。"]'),
('8feedee5-15ab-4acb-b09f-528005d2b802','羅漢贊','釋大觀','宋','宋诗','song-poetry','','[]','藕竅藏身，不形一縷。',50,'全唐诗/poet.song.215000.json','["藕竅藏身，不形一縷。", "掀播風雲，澤徧大地。", "彼其隠現大小之不同，終莫能逃乎應量之器。", "明眼人前，可賤可貴。"]'),
('62aec917-39c8-430b-808f-dd113eb9c302','大慧宏智二禪師揖讓圖贊','釋大觀','宋','宋诗','song-poetry','','[]','載色載笑，和氣津津。',62,'全唐诗/poet.song.215000.json','["載色載笑，和氣津津。", "半前落後，超軼絕塵。", "瘴面忽澤兮疾雷將奮，犀顱茁霜兮枯木生春。", "腹背受敵，百萬買鄰。", "相見易得好，共事難爲人。"]'),
('d871fd9f-b4e3-49b6-af48-ccc336aa0baf','蓮社圖贊','釋大觀','宋','宋诗','song-poetry','','[]','天運悠悠終典午，競從廬阜尋歸處。',64,'全唐诗/poet.song.215000.json','["天運悠悠終典午，競從廬阜尋歸處。", "鑿池種藕擬奚爲，西山幾度看懸鼓。", "愛酒淵明挽不來，貪佛靈運推不去。", "同盟二九姑置之，咄爾而今在何許。"]'),
('a0c3d41e-ab81-480e-bf81-f78ef27ee8e9','遠法師陸脩靜贊','釋大觀','宋','宋诗','song-poetry','','[]','一笑相逢，悠然意消。',89,'全唐诗/poet.song.215000.json','["一笑相逢，悠然意消。", "植藩籬兮肝膽楚越，外形骸兮鵬鷃逍遥。", "凉襟灑灑兮何須鶴馭之風，別袖翩翩兮不見虎溪之橋。", "此東林六事之一兮，猶可想見其丰標。", "古不可挽，今不可招。", "火生蓮花，雪長芭蕉。"]'),
('a2eaf76d-5b3a-4aa3-81d0-002d08c24692','東山源和尚贊','釋大觀','宋','宋诗','song-poetry','','[]','門裏蟲，蠱裏毒。',110,'全唐诗/poet.song.215000.json','["門裏蟲，蠱裏毒。", "纔過凌霄峰，渾家成不睦。", "指白爲黑兮質證有頭之冤，改調移聲兮唱出無譜之曲。", "自奉川之富沙以至乎劍池，深處兮有誰共躅。", "何須象骨巖高，須知已展不縮。", "韶成九包至，樵唱一夔足。", "家私莫隠，全封半幅。", "贊之駡之，口啞舌禿。"]'),
('54917e21-c71e-4f0b-9fda-c883755c8dd6','頑空法師贊','釋大觀','宋','宋诗','song-poetry','','[]','眼頭生角，囊裏盛錐。',95,'全唐诗/poet.song.215000.json','["眼頭生角，囊裏盛錐。", "駕古軌轍，闢坦路達。", "龍藏忘筌兮揭義天之寥豁，麈尾倒握兮翻辯瀾之渺瀰。", "堂堂之陳，正正之旗。", "非其所是，是其所非。", "發老嘯之韜略，茂老豁之孫枝。", "迨其涅槃後，有借萬象舌兮其誰知之。"]'),
('43d8650b-55bc-4164-99e0-2b90dd1dbf8a','寒谷暉法師贊','釋大觀','宋','宋诗','song-poetry','','[]','祖庭力探，義天橫截。',66,'全唐诗/poet.song.215000.json','["祖庭力探，義天橫截。", "南湖雨華，屢踞前列。", "鼎峙三觀兮於菟元斑，區分一乘兮尾閭自泄。", "海闊山遥，難追軌轍。", "雲暖誰尋寒谷春，晴宵又耿長空月。"]'),
('7214b955-4ed3-4fc5-9cca-aa2fe3ba0778','漢章雲法師贊','釋大觀','宋','宋诗','song-poetry','','[]','魁梧厚厖，慈和安祥。',92,'全唐诗/poet.song.215000.json','["魁梧厚厖，慈和安祥。", "聲在江湖品目，儀表衡台學場。", "空假中之列三兮，一與三之不立。", "修多羅如標月兮，指與月之俱忘。", "四處提撕，四花飛揚。", "未老掩光，返常寂光。", "此其所以爲柏庭之克家，雲公漢章者也。"]'),
('0df1a40d-73cd-4f95-8e75-8f15f59a7b11','雲谷粹長老贊','釋大觀','宋','宋诗','song-poetry','','[]','閒如雲，虛如谷。',70,'全唐诗/poet.song.215000.json','["閒如雲，虛如谷。", "歲晚一庵，湖山千簇。", "師資相忘，古靈何必拊背。", "動靜無間，茶陵空自跌足。", "一味卷舌冥懷，付與松風度曲。", "玉几如此抑揚，也是喚么作六。"]'),
('fcc7865e-a9a7-46d1-ade5-f14a3a6d97ef','芝巖禪師贊','釋大觀','宋','宋诗','song-poetry','','[]','和氣藹叢芝，觸著變荆棘。',81,'全唐诗/poet.song.215000.json','["和氣藹叢芝，觸著變荆棘。", "笑把凌霄峰信脚踏翻，直得新昌石佛額頭汗出。", "慈雲峰頂，機用縱橫。", "凌空駕虛，從其建立。", "高崙蒼蒼，東湖羃羃。", "僧繇妙筆亦難傳，絲毫不動成狼藉。", "咦。"]'),
('ffa19e0a-ac74-4834-b9e0-1518adf5b7c7','照講師贊','釋大觀','宋','宋诗','song-poetry','','[]','口哆眉厖，坐如釘樁。',57,'全唐诗/poet.song.215000.json','["口哆眉厖，坐如釘樁。", "戒香逆風，孤行凌霜。", "一新受經重其本，三主法社持其綱。", "此其所以發毫端毗尼藏，而樹末世精進幢者也。"]'),
('7325e14a-915e-45e6-9500-0612a4de1da0','南磵果法師贊','釋大觀','宋','宋诗','song-poetry','','[]','氣和色莊，襟度洋洋。',109,'全唐诗/poet.song.215000.json','["氣和色莊，襟度洋洋。", "雪殘春嶂，月午秋江。", "峙凌虛金碧兮增飛來小朶之奇觀，發昔人幽潜兮來典午咸和之遺芳。", "或見或聞，意消心降。", "若夫奉己淡薄，接物慈祥。", "不泥文字，不墮平常。", "此所以爲北峰之克家，而於自受用三昧中，合乎性具之宗綱。"]'),
('eae5f873-e499-4d1c-bfc8-f81e3dd665fa','頤蒙法師贊','釋大觀','宋','宋诗','song-poetry','','[]','癯然容儀，軒然作爲。',74,'全唐诗/poet.song.215000.json','["癯然容儀，軒然作爲。", "古潜清苕，珠媚蟾輝。", "筌忘大部兮半點不膠名相，冥通三觀兮一毫不著玄微。", "石磵付衣，末流蓍龜。", "山雷山泉兮從教名𢷕，虛空解講兮其誰知之。"]'),
('566cfecb-f980-407d-98d4-71ff309f7a97','山隠居士贊','釋大觀','宋','宋诗','song-poetry','','[]','僧之形，人之英。',90,'全唐诗/poet.song.215000.json','["僧之形，人之英。", "何所作兮畦衣常披，何所說兮玉麈常橫。", "世情悠悠兮若秋雲之淡，胸次了了兮懸秋月之明。", "其稟也靈，其施也平。", "六窗自虛，萬象自呈。", "斯何人歟，豈不入山林而隠，不濯滄浪而清者耶。"]'),
('d8925079-fafb-4dc8-a217-1e8cf98bfe26','樊路分爲母陳安人請贊','釋大觀','宋','宋诗','song-poetry','','[]','母儀慈淑，閫範持循。',104,'全唐诗/poet.song.215000.json','["母儀慈淑，閫範持循。", "善行冰雪，壽骨松椿。", "雍容堂上兮鳳霞儼儼，羅列堂下兮蘭玉詵詵。", "厚德陰儲兮留乎奕葉，和氣輯睦兮浹乎鄉鄰。", "媲城東之作家兮付佛身於等幻，秉月上之迅機兮應日用而常親。", "若問其中轉身處，虛空揣出妙無痕。"]'),
('a101bfcf-feea-4cea-b07c-cc5ef545b391','自贊','釋大觀','宋','宋诗','song-poetry','','[]','是境不涉，逢緣不借。',68,'全唐诗/poet.song.215000.json','["是境不涉，逢緣不借。", "惡人隨順，喜人凌跨。", "撥千聖賸語爲畫處山川，笑從上發機如巾結兔馬。", "絲糝弗容留，虛空生柄欛。", "只今納敗向誰，他駡不如自駡。"]'),
('dacb78b9-1236-4535-be5c-70c489a1420f','保福溥長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','雲門普，千鈞弩。',26,'全唐诗/poet.song.215000.json','["雲門普，千鈞弩。", "驀地一發，當陽飲羽。", "冤有頭兮債有主。"]'),
('b7d6743f-5993-4b2e-bcf8-e0c513493a85','法喜涇長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','有準繩，無捉摸。',38,'全唐诗/poet.song.215000.json','["有準繩，無捉摸。", "開口錯商量，鐵蒺藜確確。", "日冷月熱，涇清渭濁，昨夜鳳巢生鸑鷟。"]'),
('96926bca-d1d2-400f-9e90-92102116afc0','集福鑑長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','雷轟電馳，寸毫尺釐。',29,'全唐诗/poet.song.215000.json','["雷轟電馳，寸毫尺釐。", "全機大用，放下竹篦。", "突出雲門顧鑑，咦。"]'),
('f151864b-b8b0-4f41-b6c1-c4c323025481','明化惟長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','爲無所爲，益無所益。',46,'全唐诗/poet.song.215000.json','["爲無所爲，益無所益。", "和氣如春，近傍不得。", "有時嶮處少機關，拶倒臨濟白拈賊。", "以冤報冤，其義不忒。"]'),
('5efbf09d-7866-4a4c-abc5-2718855705a5','溢首座請贊','釋大觀','宋','宋诗','song-poetry','','[]','{毛畏}{毛畏}𣯧𣯧，顒顒昂昂。',163,'全唐诗/poet.song.215000.json','["{毛畏}{毛畏}𣯧𣯧，顒顒昂昂。", "强出人前，果見乖張。", "直如劈竹而人罕知其曲，圓如走丸而吾常用其方。", "聞說我宗甚奇特，當甚多年苕帚樁。", "明修棧道，暗渡陳倉。", "出語全無碑記，考賊不用證贓。", "敢濫稱花木瓜直下兒孫，真所謂米盡到糠。", "箇樣嘴臉非惟人惡，吾亦自惡，那堪形之丹青，懸之高堂。", "第一分付斷雲，付與丙丁收藏。", "覆水自來收不得，從教四海沸如湯。"]'),
('fd2dbc99-04b4-4b99-a09e-4dc5a60b1703','西山泳長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','馽空雲蒂，補太虛縫。',40,'全唐诗/poet.song.215000.json','["馽空雲蒂，補太虛縫。", "雖在窮相手頭，却要因人發用。", "等閒撞著箇冤家，活脫臨時看拈弄。"]'),
('dbf55b26-1fdc-4c35-bf97-3307dcf4b663','棲真身長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','我無我，柰這箇。',40,'全唐诗/poet.song.215000.json','["我無我，柰這箇。", "眨得眼，話已墮。", "翻轉面皮，放人不過。", "搥碎連城之璧，大肆秦人之禍。"]'),
('e862e3d6-fdbb-44c1-bf09-77dd7ccb8a43','梨洲戒長老請贊','釋大觀','宋','宋诗','song-poetry','','[]','相牽相引，自拈自弄。',36,'全唐诗/poet.song.215000.json','["相牽相引，自拈自弄。", "賺正因人，變滅胡種。", "業在其中不自知，九成韶集丹山鳳。"]'),
('2069a17d-bc74-4f12-9baf-b0c2dffcd009','小師清默請贊','釋大觀','宋','宋诗','song-poetry','','[]','直如鈎，曲如弦。',38,'全唐诗/poet.song.215000.json','["直如鈎，曲如弦。", "拍盲使去，罔測其然。", "不解深跧，强出人前。", "默然兮意傳更待馿年。"]'),
('d0e72871-9610-4566-a66b-2761bc74f6e9','小師清泰請贊','釋大觀','宋','宋诗','song-poetry','','[]','瞥喜瞥嗔，沒頭沒腦。',70,'全唐诗/poet.song.215000.json','["瞥喜瞥嗔，沒頭沒腦。", "道泰時清，生風起草。", "等閒相撞，黑漆竹篦劈面來。", "無禪可談，三寸舌頭胡亂掃。", "九九百百，自不知老。", "稱爲臨濟兒孫，頑石何曾是寶。"]'),
('8b2e92bd-79f6-462e-b888-33b4791b741c','小師清瑞請贊','釋大觀','宋','宋诗','song-poetry','','[]','萎萎蕤蕤，自把不定，人多不悅。',45,'全唐诗/poet.song.215000.json','["萎萎蕤蕤，自把不定，人多不悅。", "一味從空架空，知他有何所說。", "養子緣，迷子訣，六月炎炎飄瑞雪。"]'),
('79c280ea-a3b2-40e5-938c-1166ea349da4','壽平章秋壑師相','釋大觀','宋','宋诗','song-poetry','','[]','稽首毗盧法身主，三身一體圓滿覺。',384,'全唐诗/poet.song.215000.json','["稽首毗盧法身主，三身一體圓滿覺。", "曼殊室利大智海，普賢清浄行願門。", "大慈悲父觀世音，信住行向地等妙。", "五十三位善知識，權實擁護天龍神。", "慈威加被儼在上，鑑茲贊祝日行空。", "癸酉仲秋之八日，定光金地産異人。", "自威音前秉正因，向靈山上受記莂。", "優鉢孕奇時一現，昴宿騰精瑞兩間。", "千靈嘉會當其時，君臣道合若符節。", "昇平規模愈持重，呼吸變故常鎮浮。", "身徇國難入重險，手扶日轂陞中天。", "遠夷縮縮憚威略，生民熙熙安袵席。", "嗣皇矜式尊爲師，萬彙仰戴恃爲命。", "佛法流行明盛世，持世護法端有憑。", "二千年後視今日，二千年前等無異。", "如來慧命期永續，衆生正信當不斷。", "整頓乾坤大力量，安樂黎庶大福德。", "我此伽藍鄮嶺東，釋尊舍利所鎮臨。", "即茲吉祥殊勝地，衮繡光儀立壽祠。", "穰穰緇侶方儼集，鐘鼓梵唄何所祝。", "萬象舌頭悉稱壽，寶塔顯爲舒瑞光。", "昔阿育王造佛塔，其數滿八萬四千。", "一塔該八萬四千，八萬四千同一塔。", "八萬四千妙吉祥，八萬四千妙殊勝。"]'),
('f53aec1b-81aa-4524-b445-6fd61f241dd0','題覺心居士轉物軒','釋大觀','宋','宋诗','song-poetry','','[]','兩沼灧寒碧，一堂納寬閒。',158,'全唐诗/poet.song.215000.json','["兩沼灧寒碧，一堂納寬閒。", "高柳逢春新翠展，寒梅霽雪清香繁。", "好本栽培常爛熳，四序芳馨看互換。", "雜華境徧剎塵中，十波羅蜜更主伴。", "覺心隠几隨彷徉，六用俱妙無可降。", "跏趺不語亦不默，篆煙一縷春晝長。", "釋迦老子何所見，教譚三百皆方便。", "就中一處最親切，轉物不爲物所轉。", "此堂物物元無殊，隨人受用有親疎。", "塵塵攝入大毗盧，應笑本來物無轉亦無。"]'),
('a8a97649-007e-42ff-a2cd-8663f8e14b0d','人我擔','釋大觀','宋','宋诗','song-poetry','','[]','分人分我謾多端，一串黄金鎖骨寒。',32,'全唐诗/poet.song.215000.json','["分人分我謾多端，一串黄金鎖骨寒。", "善賈何曾停死貨，明明擔出與人看。"]'),
('f3d0d7bc-fb68-4df9-ad8a-ed7da2b8fae4','示錦屏趙高士','釋大觀','宋','宋诗','song-poetry','','[]','真游誰管客程賒，閬苑春風幾度花。',32,'全唐诗/poet.song.215000.json','["真游誰管客程賒，閬苑春風幾度花。", "若會粟中藏世界，寥陽不是玉皇家。"]'),
('f38b8068-dcb0-4482-aebb-957aac73b6c4','性空','釋大觀','宋','宋诗','song-poetry','','[]','萬有俱該等太虛，更須拈却趙州無。',32,'全唐诗/poet.song.215000.json','["萬有俱該等太虛，更須拈却趙州無。", "如今若欲知端的，舜若新添頷下鬚。"]'),
('01ecb571-09a6-45f1-9088-76b45b002541','絕詮','釋大觀','宋','宋诗','song-poetry','','[]','虛空講得四花飛，大地山河總發機。',32,'全唐诗/poet.song.215000.json','["虛空講得四花飛，大地山河總發機。", "碧眼黄頭無處覓，是中元不動唇皮。"]'),
('6dce5eb8-739b-4969-be73-485096e57f87','日本仙侍者歸國','釋大觀','宋','宋诗','song-poetry','','[]','三應聲中密意通，分明飯布裹春風。',32,'全唐诗/poet.song.215000.json','["三應聲中密意通，分明飯布裹春風。", "休論親切不親切，巨舶回程至海東。"]'),
('24ee2c72-6c7d-48fb-a748-fc9a95101e53','道者復幹接待','釋大觀','宋','宋诗','song-poetry','','[]','旋營屋子嵌雲山，舊日靈泉氣象還。',32,'全唐诗/poet.song.215000.json','["旋營屋子嵌雲山，舊日靈泉氣象還。", "但有過門教歇去，誰云道者少機關。"]'),
('cc0234aa-d6b2-4734-8bda-99b0516eeaf2','日者王振齋','釋大觀','宋','宋诗','song-poetry','','[]','言口談天有振齋，五行曾不涉安排。',32,'全唐诗/poet.song.215000.json','["言口談天有振齋，五行曾不涉安排。", "小軒對坐似無語，幾度晴雲過斷崖。"]'),
('9a777705-2ac1-4f55-8ef9-276c6a237d84','賀大淵自資福住白雲','釋大觀','宋','宋诗','song-poetry','','[]','者邊颺下舀溪杓，鈯斧又移深處山。',32,'全唐诗/poet.song.215000.json','["者邊颺下舀溪杓，鈯斧又移深處山。", "說與白雲門外客，相逢莫作舊時看。"]'),
('9bae6c4a-1569-49e7-b5e2-192ecbe0eb84','病中送湛侍者之京','釋大觀','宋','宋诗','song-poetry','','[]','別我從容藥鼎邊，迢迢京路紫霞連。',32,'全唐诗/poet.song.215000.json','["別我從容藥鼎邊，迢迢京路紫霞連。", "重提藥病相治句，却道親依已五年。"]'),
('5ba1e114-de53-410c-a9cc-1bfa68fc3a09','示沙彌','釋大觀','宋','宋诗','song-poetry','','[]','維衛芳騰蔓愈滋，花花葉葉轉芬披。',32,'全唐诗/poet.song.215000.json','["維衛芳騰蔓愈滋，花花葉葉轉芬披。", "鄮峰酷烈較些子，曇萼翻成鐵蒺藜。"]'),
('e837c71b-0c32-4758-9fa5-d89bef305d67','示林侍者','釋大觀','宋','宋诗','song-poetry','','[]','點墨如將當已長，分明白飯糝椒薑。',32,'全唐诗/poet.song.215000.json','["點墨如將當已長，分明白飯糝椒薑。", "出門相送都無說，堂下秋花自吐香。"]'),
('5ff4b838-e31b-4571-9b51-62aecfe1051d','晦機','釋大觀','宋','宋诗','song-poetry','','[]','舌上雷轟一默間，纖塵不動鼓波瀾。',32,'全唐诗/poet.song.215000.json','["舌上雷轟一默間，纖塵不動鼓波瀾。", "拈花會上人無數，輸與頭陀一破顔。"]'),
('54c80609-8ef3-4f44-9bc8-522c6d80f8f0','沙彌付衣','釋大觀','宋','宋诗','song-poetry','','[]','鷲嶺將何付飲光，十成綿密轉乖張。',32,'全唐诗/poet.song.215000.json','["鷲嶺將何付飲光，十成綿密轉乖張。", "鄮峰恁麽不恁麽，尺線單絲自短長。"]'),
('11333ddd-108b-4799-a05a-e66448386464','吳道人求語回庵','釋大觀','宋','宋诗','song-poetry','','[]','東遊何見便還西，覓我伽陀要指迷。',32,'全唐诗/poet.song.215000.json','["東遊何見便還西，覓我伽陀要指迷。", "領取庵頭好消息，冬蔬經雨翠交畦。"]'),
('df131dde-610a-4e62-86b8-12a832de66c0','和靜照詩韻  其一','釋大觀','宋','宋诗','song-poetry','','[]','日轂陞邊不計程，轉頭已是隔重溟。',32,'全唐诗/poet.song.215000.json','["日轂陞邊不計程，轉頭已是隔重溟。", "更遭尊者相勾引，瀑搗飛梁夢未醒。"]'),
('5a32911a-48e7-4594-94c8-a338c8ab1a59','和靜照詩韻  其二','釋大觀','宋','宋诗','song-poetry','','[]','諸方門戶總經過，惱亂春風有幾多。',32,'全唐诗/poet.song.215000.json','["諸方門戶總經過，惱亂春風有幾多。", "今日蒸雲重覩對，絲毫不隔最誵訛。"]'),
('b8894c65-6dd2-46bd-abb4-e67c6c7a51dc','問物初和尚','廣利寺僧','宋','宋诗','song-poetry','','[]','一封詔出禁庭中，催起慈峰住鄮峰。',32,'全唐诗/poet.song.215000.json','["一封詔出禁庭中，催起慈峰住鄮峰。", "今日開堂宣妙法，祥雲瑞氣罩虛空。"]'),
('ed095bb0-3d95-49c9-aad8-84c1820b1050','秋夕過松陵','武衍','宋','宋诗','song-poetry','','[]','月冷江空夜氣濃，桂香飛下廣庭風。',32,'全唐诗/poet.song.215000.json','["月冷江空夜氣濃，桂香飛下廣庭風。", "不知何處神仙過，鶴唳數聲煙靄中。"]'),
('a9134df7-963f-4a00-96f5-ac28bf252236','鶑','武衍','宋','宋诗','song-poetry','','[]','柳外飛來恰弄聲，瞥然流去一梭輕。',32,'全唐诗/poet.song.215000.json','["柳外飛來恰弄聲，瞥然流去一梭輕。", "分明啼斷春愁處，風不驚花午院晴。"]'),
('182f439b-d6d4-45e1-be31-9bc5f96a1059','宮詞補遺  其一','武衍','宋','宋诗','song-poetry','','[]','梨花風動玉闌香，春色沈沈鎖建章。',32,'全唐诗/poet.song.215000.json','["梨花風動玉闌香，春色沈沈鎖建章。", "唯有落紅官不禁，儘教飛舞出宮牆。"]'),
('b9680c11-9869-40f2-af56-6d1f7587a31d','宮詞補遺  其二','武衍','宋','宋诗','song-poetry','','[]','牡丹春籞正穠華，有旨今年不賞花。',32,'全唐诗/poet.song.215000.json','["牡丹春籞正穠華，有旨今年不賞花。", "剪落金盤三百朶，內批分賜近臣家。"]'),
('22c53a39-4882-4e9b-b674-f6446e544f11','采桑曲  其一','武衍','宋','宋诗','song-poetry','','[]','粉光薄薄髻雲垂，葉滿湘籠獨步時。',32,'全唐诗/poet.song.215000.json','["粉光薄薄髻雲垂，葉滿湘籠獨步時。", "女伴未來歸未得，水邊閒照插花枝。"]'),
('a0bed79a-2ed9-43b3-910b-6f866dabea3e','采桑曲  其二','武衍','宋','宋诗','song-poetry','','[]','道是蠶忙未是忙，日長猶得事梳妝。',32,'全唐诗/poet.song.215000.json','["道是蠶忙未是忙，日長猶得事梳妝。", "羅敷有語何曾解，倚樹偷窺馬上郎。"]'),
('1171903f-097b-4293-912b-17cc49f1f5ca','虛皇壇月下聞笙','武衍','宋','宋诗','song-poetry','','[]','何人吹動玉笙攢，天闊風高桂殿寒。',32,'全唐诗/poet.song.215000.json','["何人吹動玉笙攢，天闊風高桂殿寒。", "聲軋五雲飛不去，夜深和鶴落瑶壇。"]'),
('0fab26b5-4e21-4027-b972-fe4c1cd3c815','宮思','武衍','宋','宋诗','song-poetry','','[]','當時十五正嬌妍，選入宮中二十年。',32,'全唐诗/poet.song.215000.json','["當時十五正嬌妍，選入宮中二十年。", "誰料祇今三十五，舞鞾未蹋玉階前。"]'),
('764617a9-9ac4-419b-a1de-4f8a7f1889ed','書畫扇','武衍','宋','宋诗','song-poetry','','[]','雙成午夜約飛瓊，齊駕紅鸞看月明。',32,'全唐诗/poet.song.215000.json','["雙成午夜約飛瓊，齊駕紅鸞看月明。", "縹緲碧雲歸去曉，洞天霜冷玉簫清。"]'),
('5c4bbd2e-730c-4a24-bcec-dab6ebd97023','贈苕上隠者','武衍','宋','宋诗','song-poetry','','[]','夾谿槐柳綠雲堆，轍蹟何嘗到碧苔。',32,'全唐诗/poet.song.215000.json','["夾谿槐柳綠雲堆，轍蹟何嘗到碧苔。", "不種桃花緣底事，恐因流水悞人來。"]'),
('e57a28af-82bd-4bca-9ec6-f645e9f5a026','開元廣寒詞','武衍','宋','宋诗','song-poetry','','[]','桂華珠殿水精樓，柘袖籠香乙夜游。',32,'全唐诗/poet.song.215000.json','["桂華珠殿水精樓，柘袖籠香乙夜游。", "飛下銀橋人不覺，月明三十六宮秋。"]'),
('60a35fe2-a639-46ab-ba96-19645277efc8','客去','武衍','宋','宋诗','song-poetry','','[]','晉人冠子羽人衣，客去移牀傍小池。',32,'全唐诗/poet.song.215000.json','["晉人冠子羽人衣，客去移牀傍小池。", "扇影不摇蘄竹浄，藕花風裏看唐詩。"]'),
('b9f458ed-b164-409c-8bf9-653256c52930','游吳門同樂園疥池光亭壁呈使君張都承','武衍','宋','宋诗','song-poetry','','[]','一城和氣萬家春，金碧樓臺處處新。',32,'全唐诗/poet.song.215000.json','["一城和氣萬家春，金碧樓臺處處新。", "太守不孤同樂意，木蘭堂上看遊人。"]'),
('4a252b45-0c77-4465-a82c-c41b201a9854','春日舟中書所見  其一','武衍','宋','宋诗','song-poetry','','[]','翠峰斜倚側金翹，羅带縈紅罥碧桃。',32,'全唐诗/poet.song.215000.json','["翠峰斜倚側金翹，羅带縈紅罥碧桃。", "應是春愁禁不得，東風深院粉牆高。"]'),
