('27344b57-bc05-4cbd-befa-48116c5e1b06','春曉山行馬上口占  其一','武衍','宋','宋诗','song-poetry','','[]','山深竹暗曉風輕，幾樣幽禽錯雜鳴。',32,'全唐诗/poet.song.215000.json','["山深竹暗曉風輕，幾樣幽禽錯雜鳴。", "駐馬細聽渾不識，就中惟識子規聲。"]'),
('a5d5c5d0-5730-41f2-ae0b-c8f1ddaa90bd','春曉山行馬上口占  其二','武衍','宋','宋诗','song-poetry','','[]','路轉前山復後山，宿煙收盡薄生寒。',32,'全唐诗/poet.song.215000.json','["路轉前山復後山，宿煙收盡薄生寒。", "吟鞭忽指松梢月，絕勝城中樓上看。"]'),
('d4e652e7-0fb5-4533-9768-238334290619','陽復','武衍','宋','宋诗','song-poetry','','[]','一變陽爻七日初，窗閒測影弄徐徐。',32,'全唐诗/poet.song.215000.json','["一變陽爻七日初，窗閒測影弄徐徐。", "不知曾未添宮線，但覺多翻數葉書。"]'),
('1aaa213e-f7bc-4b4f-b71a-2986dd7e0264','劉八窗見訪一夕即別','武衍','宋','宋诗','song-poetry','','[]','五年苕上別，別後愧相疎。',48,'全唐诗/poet.song.215000.json','["五年苕上別，別後愧相疎。", "今夕知何夕，憶渠俄見渠。", "同持一杯酒，勝寄百封書。", "未及論心事，曉風囘蹇馿。"]'),
('26ed166c-eeb0-453e-9de7-7a4fec5c2379','悼戴式之','武衍','宋','宋诗','song-poetry','','[]','四海詩人說石屏，一時知己盡公卿。',64,'全唐诗/poet.song.215000.json','["四海詩人說石屏，一時知己盡公卿。", "家傳衣鉢生無愧，氣挾江湖老更清。", "重感慨時多比興，最瑰奇處是歌行。", "九原不作空遺稿，三些吟魂淚爲傾。"]'),
('cc2618c8-dc4a-4e27-853e-979121712dfc','嘗葡萄','武衍','宋','宋诗','song-poetry','','[]','壓架駢枝露顆圓，水精落落照晴軒。',32,'全唐诗/poet.song.215000.json','["壓架駢枝露顆圓，水精落落照晴軒。", "微酸自是江南種，尚忍因渠說太原。"]'),
('b1d1678a-89ca-4109-9474-93396c97a5d4','睡覺','武衍','宋','宋诗','song-poetry','','[]','睡覺東風忽惘然，起翻雲母續爐煙。',64,'全唐诗/poet.song.215000.json','["睡覺東風忽惘然，起翻雲母續爐煙。", "半醒不醉宿酲思，欲雨又晴寒食天。", "春草池塘詩夢裏，梨花庭院酒尊前。", "誰憐倦客長安市，節物驚心憶舊年。"]'),
('3dd3d38d-aaa3-4cdc-97cf-de5f3e12a209','晴絲','武衍','宋','宋诗','song-poetry','','[]','何處飛來繚碧空，敲吟終日費形容。',64,'全唐诗/poet.song.215000.json','["何處飛來繚碧空，敲吟終日費形容。", "榑桑老繭抽纖緯，星殿殘機剪素茸。", "驀忽带歸簾外燕，等閒惹住柳邊蜂。", "風柔日薄樓臺晚，一縷低垂力正慵。"]'),
('34d9f86b-eada-4187-b7df-cc32cc5d8c7d','謝曹東甽跋吟卷','武衍','宋','宋诗','song-poetry','','[]','十年湖海仰師儒，八斗衣傳子建餘。',64,'全唐诗/poet.song.215000.json','["十年湖海仰師儒，八斗衣傳子建餘。", "袖裏有詩須印證，句中無眼定趦趄。", "吹香玉唾清如許，刮膜金篦病已除。", "媼扇何曾求貴重，等閒中得會稽書。"]'),
('996d8f52-d567-4977-ad0d-93785158ea6c','楓橋道中','武衍','宋','宋诗','song-poetry','','[]','路接官河柳行斜，蹇馿衝暑憇田家。',64,'全唐诗/poet.song.215000.json','["路接官河柳行斜，蹇馿衝暑憇田家。", "雨餘天迥雲生葉，日午風輕稻放花。", "襏襫已懸黄犢睡，桔槔不動綠陰遮。", "老翁相見如相識，命坐藜牀自析瓜。"]'),
('d510d43f-bf2b-45a4-a158-e0e871e48298','郊居紀實','武衍','宋','宋诗','song-poetry','','[]','既安能適復何疑，小築重營即舊規。',64,'全唐诗/poet.song.215000.json','["既安能適復何疑，小築重營即舊規。", "狡兔反爲三窟累，鷦鷯終遂一枝期。", "種成水際芙蓉徑，鑿得亭前菡萏池。", "客有可人尊有酒，四時風月總相宜。"]'),
('3498be89-24df-4d94-b062-966f9417081f','送外家通倅方澹菴','武衍','宋','宋诗','song-poetry','','[]','風節傳清素，名多爲宦游。',48,'全唐诗/poet.song.215000.json','["風節傳清素，名多爲宦游。", "花封纔解綬，芝檢趣監州。", "等上持麾節，歸來覲冕旒。", "江南與江北，底用說離愁。"]'),
('973c7b55-bd76-4ce8-b535-b7c15b9c2e78','松陵晚泊','武衍','宋','宋诗','song-poetry','','[]','漭漭風濤外，天隨底處尋。',48,'全唐诗/poet.song.215000.json','["漭漭風濤外，天隨底處尋。", "碧雲千嶂暝，紅樹九秋深。", "故國荒城夢，空江倦客心。", "行藏那復計，篷月闖孤斟。"]'),
('40a239b3-e0a0-415f-942c-7a81cc4e5b9c','小游僊詞','武衍','宋','宋诗','song-poetry','','[]','天風吹上碧嶙峋，鸞鶴聲清草木薰。',32,'全唐诗/poet.song.215000.json','["天風吹上碧嶙峋，鸞鶴聲清草木薰。", "金闕玉樓行欲遍，却携明月出紅雲。"]'),
('b79fe679-7010-4ea7-bee6-a7177faea198','寄湯伯起','武衍','宋','宋诗','song-poetry','','[]','徙家城市去，不爲故人留。',48,'全唐诗/poet.song.215000.json','["徙家城市去，不爲故人留。", "種菊應無地，觀山合起樓。", "別來通訊少，春至作詩不。", "池上雙檉綠，孤吟我正愁。"]'),
('79b80264-2664-4ce9-8d47-7d8090c95df7','次韻答菊莊湯伯起','武衍','宋','宋诗','song-poetry','','[]','數弓蔬地一方池，吾愛吾廬祇自知。',64,'全唐诗/poet.song.215000.json','["數弓蔬地一方池，吾愛吾廬祇自知。", "蘆碧補交楊柳缺，檉紅攙上藕花遲。", "翠陰圍合疑無日，涼意蕭騷賸有詩。", "君欲重來須更待，嫩煙浮動晚晴時。"]'),
('bbaabd28-ffa1-4411-95c6-aeb4141a4b8c','別燕','武衍','宋','宋诗','song-poetry','','[]','寶墨煙雲邈，金風庭戶秋。',48,'全唐诗/poet.song.215000.json','["寶墨煙雲邈，金風庭戶秋。", "有雛堪作伴，無計若爲留。", "謹勿沾鯨浪，應須避蜃樓。", "裁詩聊寄遠，煩慰玉人愁。"]'),
('da374326-2ceb-4a94-8ef0-2b5d949f3d98','西陵觀梅','武衍','宋','宋诗','song-poetry','','[]','障霜篝日奪天機，九月梅花賞玉蕤。',32,'全唐诗/poet.song.215000.json','["障霜篝日奪天機，九月梅花賞玉蕤。", "到了不如春意勝，水邊風韻兩三枝。"]'),
('5f84fa80-0192-4f05-bb53-e330bb199be4','小院','武衍','宋','宋诗','song-poetry','','[]','小院秋聲動碧梧，颯然涼思滿籧篨。',32,'全唐诗/poet.song.215000.json','["小院秋聲動碧梧，颯然涼思滿籧篨。", "年來懶結青鐙伴，却課兒曹讀夜書。"]'),
('4815160e-2bc1-4618-a278-05a9c150a5fc','夏日書事','武衍','宋','宋诗','song-poetry','','[]','緩將琴軫卷將書，誰信閒中事有餘。',64,'全唐诗/poet.song.215000.json','["緩將琴軫卷將書，誰信閒中事有餘。", "約客論茶和水試，課童移菊带泥鉏。", "竹櫳日午猶關鶴，水檻朝來自餧魚。", "山薊已苗瓜已蔓，適安生計未全疎。"]'),
('f3d8f36e-127f-4a45-b578-890e399b7eba','訪隠者居','武衍','宋','宋诗','song-poetry','','[]','蘚磴披蘿入，茅堂著竹遮。',48,'全唐诗/poet.song.215000.json','["蘚磴披蘿入，茅堂著竹遮。", "綠看流去水，紅惜落殘花。", "蜀鳥啼春靜，山童厭客譁。", "細觀題壁者，一一是詩家。"]'),
('79890863-d04c-4751-9122-df64eb164339','宮中詞','武衍','宋','宋诗','song-poetry','','[]','睡餘羅袖印眉山，行傍妝臺理墜鬟。',32,'全唐诗/poet.song.215000.json','["睡餘羅袖印眉山，行傍妝臺理墜鬟。", "聖主憂勤排當少，犀椎魚撥總成閒。"]'),
('4a2a4c4f-db9d-4da0-a1f1-377aad6bc87a','邊烽既息穡事告登歌以五十六字用和擊壤','武衍','宋','宋诗','song-poetry','','[]','見說邊頭事已寧，捷書復得壽春城。',64,'全唐诗/poet.song.215000.json','["見說邊頭事已寧，捷書復得壽春城。", "從來方面多豪傑，均與朝廷繫重輕。", "棗實雖紅休北顧，稻花垂白近西成。", "民無饑色添歡色，氣象方纔似太平。"]'),
('ef5cb212-a9c5-4f52-b61b-4fbb5eb8d71a','京口策應戍將歸營','武衍','宋','宋诗','song-poetry','','[]','老矣猶征調，新從淮上歸。',48,'全唐诗/poet.song.215000.json','["老矣猶征調，新從淮上歸。", "盡知邊境事，曾解壽春圍。", "腥血封刀匣，黄沙漬鐵衣。", "奏功均得賞，沽酒醉斜暉。"]'),
('288e7744-b61b-4f8c-92ac-1e190a7fcc3a','枕邊','武衍','宋','宋诗','song-poetry','','[]','枕邊清坐散餘酲，慘淡西窗月半明。',32,'全唐诗/poet.song.215000.json','["枕邊清坐散餘酲，慘淡西窗月半明。", "燕子夢囘簾未捲，楝花風信曉寒輕。"]'),
('e9102287-5270-4f44-bdf6-f2ee258fee03','癖','武衍','宋','宋诗','song-poetry','','[]','賸欲收神省費心，三生癡癖本來深。',64,'全唐诗/poet.song.215000.json','["賸欲收神省費心，三生癡癖本來深。", "典衣尋訪晉朝畫，折簡借觀雷氏琴。", "帖字逼真嘗細搨，詩聯敲穩每長吟。", "鏡中一笑成何事，鬢影秋絲日見侵。"]'),
('05c63ffe-6e4b-4689-b65c-74fe21d8f752','清明湖上','武衍','宋','宋诗','song-poetry','','[]','榆火初傳禁漏殘，滿城和氣在湖山。',64,'全唐诗/poet.song.215000.json','["榆火初傳禁漏殘，滿城和氣在湖山。", "接天楊柳風煙裏，照水桃花圖畫閒。", "舊路人穿新路去，長橋船出斷橋還。", "吾皇應喜民胥樂，歲許西門入夜關。"]'),
('4a4c59e4-0ee8-4148-8393-5b618f234130','宿呂城舟中','武衍','宋','宋诗','song-poetry','','[]','古堞遺蹤何處尋，斷煙殘日意沈沈。',64,'全唐诗/poet.song.215000.json','["古堞遺蹤何處尋，斷煙殘日意沈沈。", "飛湍過閘風雷怒，峭岸如山草木深。", "燈火鄰船喧客枕，江天漂梗碎鄉心。", "明朝沽酒新豐市，怊悵無人伴苦吟。"]'),
('3c7aacd6-592c-42fd-8f18-bd1944c032f3','送客之潤赴時貴約','武衍','宋','宋诗','song-poetry','','[]','折柳亭邊未問津，江山先入夢來頻。',64,'全唐诗/poet.song.215000.json','["折柳亭邊未問津，江山先入夢來頻。", "漕渠水足新逢雨，客路風光恰是春。", "莫論孫劉悲既往，願言賓主樂相親。", "曾留短絕題多景，君到應須爲拂塵。"]'),
('c88b25cf-7f07-4569-aa8e-b79c14f49947','送徐雲友歸行都','武衍','宋','宋诗','song-poetry','','[]','落落奇男子，長年走客塵。',48,'全唐诗/poet.song.215000.json','["落落奇男子，長年走客塵。", "白身無寸祿，青眼欠高人。", "病爲思詩苦，貧緣立行真。", "片雲留不住，歸醉洛陽春。"]'),
('7dc4d788-66c2-4508-aba3-e84083b2a8bf','伯氏自吳門來輦下再宿即別','武衍','宋','宋诗','song-poetry','','[]','把酒論新事，移牀問故山。',48,'全唐诗/poet.song.215000.json','["把酒論新事，移牀問故山。", "桑麻云已長，親戚喜相安。", "斷鴈江湖外，馳心夢寐間。", "兩年三度別，此別覺尤難。"]'),
('026ba104-4221-41ce-857a-faf808ec3336','劉後村被召','武衍','宋','宋诗','song-poetry','','["\u8861\u5c71"]','銜上官雖顯，吟邊興不衰。',48,'全唐诗/poet.song.215000.json','["銜上官雖顯，吟邊興不衰。", "細評南嶽稿，遠過後山詩。", "才大人多忌，名高上素知。", "瓣香吾敢後，幸見召環時。"]'),
('61594f72-b513-4d1b-9087-7c09c3883cc1','送友人赴長沙酒官','武衍','宋','宋诗','song-poetry','','[]','老楓殘月曉江濱，送客歸來又送君。',64,'全唐诗/poet.song.215000.json','["老楓殘月曉江濱，送客歸來又送君。", "愁滴離聲三疊淚，眼穿行色萬重雲。", "過湘應取離騷續，到邑終期課最聞。", "莫爲西班羞薄宦，要思先世立殊勳。"]'),
('f91a83ae-2ee1-4ef6-a19d-f86b7553f37b','杏花','武衍','宋','宋诗','song-poetry','','[]','柳店春風酒旆斜，紫綃團萼數枝花。',32,'全唐诗/poet.song.215000.json','["柳店春風酒旆斜，紫綃團萼數枝花。", "香肌元是多豐膩，錯把紅梅看作他。"]'),
('7cd1d103-b879-4c73-a767-a5a4708b0b51','寓京口四首答湯菊莊兼簡分司鄭料院 北固亭口占','武衍','宋','宋诗','song-poetry','','[]','三生結得潤人緣，卮酒時來暖客氈。',32,'全唐诗/poet.song.215000.json','["三生結得潤人緣，卮酒時來暖客氈。", "北固兒童雖不識，也緣巾屨過山前。"]'),
('1dccf154-f536-43e3-a993-aa21391883eb','寓京口四首答湯菊莊兼簡分司鄭料院 鶻山','武衍','宋','宋诗','song-poetry','','[]','屹然孤石蘚痕青，千古江湍洗不平。',32,'全唐诗/poet.song.215000.json','["屹然孤石蘚痕青，千古江湍洗不平。", "蒼鶻飛來復飛去，不知身爲此山名。"]'),
('441a1539-4a56-4a3e-8841-b829b18cf51c','寓京口四首答湯菊莊兼簡分司鄭料院 甘露寺很石','武衍','宋','宋诗','song-poetry','','[]','二雄曾向此般還，鼎立功名各未安。',32,'全唐诗/poet.song.215000.json','["二雄曾向此般還，鼎立功名各未安。", "留得坐時頑石在，至今人尚說曹瞞。"]'),
('467c87a2-b99e-4988-b0d7-fa62e739b194','寓京口四首答湯菊莊兼簡分司鄭料院 月觀遠眺','武衍','宋','宋诗','song-poetry','','[]','朝宗亭下浪冥冥，何日尋觀瘞鶴銘。',32,'全唐诗/poet.song.215000.json','["朝宗亭下浪冥冥，何日尋觀瘞鶴銘。", "更欲裹茶邀客去，短篷敲火瀹中泠。"]'),
('46ed8ff0-ec39-40ea-8eed-36ff1bec9b2e','歲在丁亥郊禋禮成皇帝登門肆赦獲睹盛典恭成口號','武衍','宋','宋诗','song-poetry','','[]','閶闔煌煌闢曉雲，千官鵠立望嚴宸。',64,'全唐诗/poet.song.215000.json','["閶闔煌煌闢曉雲，千官鵠立望嚴宸。", "鶴書飛下珠簷峻，雉扇分開玉座新。", "山壽聲中團喜氣，鈞天奏處隔香塵。", "明王盛事民何幸，三載恩寬四海春。"]'),
('4864fbfb-49f4-4f3f-a53c-f91166070ee0','正元二日與菊莊湯伯起歸隠陳鴻甫汎舟湖上二首  其一','武衍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','春雲漠漠雨踈踈，小𦩘衝煙入畫圖。',32,'全唐诗/poet.song.215000.json','["春雲漠漠雨踈踈，小𦩘衝煙入畫圖。", "除却淡妝濃抹句，更將何語說西湖。"]'),
('86d9abbd-8c55-4832-a73b-733b6a692b00','正元二日與菊莊湯伯起歸隠陳鴻甫汎舟湖上二首  其二','武衍','宋','宋诗','song-poetry','','[]','櫂轉逋山𫇢落暉，春風深鎖恨依依。',32,'全唐诗/poet.song.215000.json','["櫂轉逋山𫇢落暉，春風深鎖恨依依。", "松間一鶴俄飛起，疑是先生出未歸。"]'),
('e576abf2-1670-4ece-80a4-ebc559378a83','送蕙坡趙富陽赴高郵元幕見次','武衍','宋','宋诗','song-poetry','','[]','相逢客裏便相歡，握手真能出肺肝。',64,'全唐诗/poet.song.215000.json','["相逢客裏便相歡，握手真能出肺肝。", "買得酒尊曾共酌，带來詩卷每容看。", "舊聞遊宦多知己，今喜公朝與好官。", "一片淮雲千里月，覲圭何日入長安。"]'),
('83e67e09-3e93-46fa-9ddd-686b940c5b26','蘆筍','武衍','宋','宋诗','song-poetry','','[]','春風荻渚暗潮平，紫綠尖新嫩茁生。',64,'全唐诗/poet.song.215000.json','["春風荻渚暗潮平，紫綠尖新嫩茁生。", "带水掐來隨手脆，櫂船歸去滿篝輕。", "竹根稚子難專美，澗底香芹可配羹。", "風味祇應漁舍占，玉盤空厭五侯鯖。"]'),
('57e0eb8b-66de-466b-a4b4-bc06b150a834','湖亭席上','武衍','宋','宋诗','song-poetry','','[]','寒食梨花月，新晴楊柳風。',48,'全唐诗/poet.song.215000.json','["寒食梨花月，新晴楊柳風。", "愁融山色裏，興極酒杯中。", "綠髮日夜變，青春今古同。", "忍教行樂處，容易夕陽紅。"]'),
('d034ac16-69ec-440a-af05-a40a318067d8','哀魏方泉  其一','武衍','宋','宋诗','song-poetry','','[]','每見中吳士，多稱太守賢。',48,'全唐诗/poet.song.215000.json','["每見中吳士，多稱太守賢。", "一毫無暴政，千里樂豐年。", "心醉西樓月，身飛北闕天。", "那知人事異，夢絕柳橋邊。"]'),
('59fc027e-fde2-4b1b-9862-4c6181606a6f','哀魏方泉  其二','武衍','宋','宋诗','song-poetry','','[]','詔下催歸覲，人傳便尹京。',48,'全唐诗/poet.song.215000.json','["詔下催歸覲，人傳便尹京。", "班纔聯從橐，庭忽舞銘旌。", "玉樹悲中折，金丹聖莫生。", "澤多唯乳子，天道若無情。"]'),
('281c458a-37ea-4be5-99f7-ead189f0c707','寄吳德章簽判','武衍','宋','宋诗','song-poetry','','[]','莫轉朱弦軫，知音世不慳。',48,'全唐诗/poet.song.215000.json','["莫轉朱弦軫，知音世不慳。", "吟情清似水，壯志屹於山。", "自入鄉關去，相思雲樹間。", "春風吹五葉，早趁集英班。"]'),
('453481e2-d65c-45c6-a913-f2336e5b4a1c','書所懷','武衍','宋','宋诗','song-poetry','','[]','閒拂塵中鏡，猶憐壁上梭。',48,'全唐诗/poet.song.215000.json','["閒拂塵中鏡，猶憐壁上梭。", "生平多坎壈，知己半銷磨。", "對酒成孤酌，橫琴寓九歌。", "相思江水闊，歲晚客如何。"]'),
('7d0b2638-150f-47a3-a31e-797837fdc23f','蠟梅  其一','武衍','宋','宋诗','song-poetry','','[]','磬口檀心紫暈重，繁香微洩繡簾風。',32,'全唐诗/poet.song.215000.json','["磬口檀心紫暈重，繁香微洩繡簾風。", "照花休用添紅燭，却怕輕明暖易融。"]'),
('a336bb96-3d2f-46eb-a74c-1067efce998a','蠟梅  其二','武衍','宋','宋诗','song-poetry','','[]','賦得姿容類至中，哨枝宿葉又春風。',32,'全唐诗/poet.song.215000.json','["賦得姿容類至中，哨枝宿葉又春風。", "品題雖入江梅譜，可惜名同韻不同。"]'),
('1b1ce829-6f30-40b5-959d-5dc2090c0a17','恭謝慶成詩十闋  其一','武衍','宋','宋诗','song-poetry','','[]','二載明禋帝意專，瓣香盍謝祖宗前。',32,'全唐诗/poet.song.215000.json','["二載明禋帝意專，瓣香盍謝祖宗前。", "願前盛典從頭數，紹述應須億萬年。"]'),
('6871b45a-8423-47e3-a8ef-641422603000','恭謝慶成詩十闋  其二','武衍','宋','宋诗','song-poetry','','[]','麝蠟籠紗粲玉階，珠櫳齊撤九門開。',32,'全唐诗/poet.song.215000.json','["麝蠟籠紗粲玉階，珠櫳齊撤九門開。", "一天星斗明如月，法駕徐擎出殿來。"]'),
('b8af8755-f578-4c70-a496-9fbacd2367bb','恭謝慶成詩十闋  其三','武衍','宋','宋诗','song-poetry','','[]','宮監推簾探曉星，景陽鍾動已妝成。',32,'全唐诗/poet.song.215000.json','["宮監推簾探曉星，景陽鍾動已妝成。", "鳳輿陸續銜車馬，黄道香濃尾駕行。"]'),
('be07ae62-3cb3-4b12-b45a-094c2630658f','恭謝慶成詩十闋  其四','武衍','宋','宋诗','song-poetry','','[]','禮成列聖宴群工，浩蕩春風到竹宮。',32,'全唐诗/poet.song.215000.json','["禮成列聖宴群工，浩蕩春風到竹宮。", "傳旨簪花俄侶錦，信知天子是天公。"]'),
('87e286ff-1bcb-4e0c-a646-da5e324b5d94','恭謝慶成詩十闋  其五','武衍','宋','宋诗','song-poetry','','[]','大官宣勸禮優寬，中殿妃嬪各盡歡。',32,'全唐诗/poet.song.215000.json','["大官宣勸禮優寬，中殿妃嬪各盡歡。", "和氣滿城天色好，不妨直際晚回鑾。"]'),
('b034a1d6-cf95-4e69-812d-1512339d8c08','恭謝慶成詩十闋  其六','武衍','宋','宋诗','song-poetry','','[]','樂奏仙韶進壽觥，觚棱風細寶香清。',32,'全唐诗/poet.song.215000.json','["樂奏仙韶進壽觥，觚棱風細寶香清。", "隔簾微見龍顔啟，緣是優人有笑聲。"]'),
('4a7ca772-b9d3-4f34-9a5b-5e330dc1ba82','恭謝慶成詩十闋  其七','武衍','宋','宋诗','song-poetry','','[]','宮前儀衛尚般還，花裏聲傳午漏殘。',32,'全唐诗/poet.song.215000.json','["宮前儀衛尚般還，花裏聲傳午漏殘。", "見說御園才放水，聖心游泳正觀瀾。"]'),
('9e3c8a82-0d11-4663-9d65-f5138df8f31b','恭謝慶成詩十闋  其八','武衍','宋','宋诗','song-poetry','','[]','染羅彫草斡天機，簇戴工夫鬭出奇。',32,'全唐诗/poet.song.215000.json','["染羅彫草斡天機，簇戴工夫鬭出奇。", "唯有近臣恩數異，尚方別賜細欒枝。"]'),
('b03bc905-7c66-430a-b99e-fac7b4597d07','恭謝慶成詩十闋  其九','武衍','宋','宋诗','song-poetry','','[]','小白長紅十里春，歸來天仗擁香塵。',32,'全唐诗/poet.song.215000.json','["小白長紅十里春，歸來天仗擁香塵。", "翩翩黄屋彫霞裏，輦上無花止一人。"]'),
('df6fd0ab-bbc3-4539-babf-3a285fe4dde1','恭謝慶成詩十闋  其一○','武衍','宋','宋诗','song-poetry','','[]','士庶重重間綺羅，霽光熏作小春和。',32,'全唐诗/poet.song.215000.json','["士庶重重間綺羅，霽光熏作小春和。", "御街兩行瞻天表，比似前回人更多。"]'),
('86003581-d239-46a9-9652-90189a705792','病目','武衍','宋','宋诗','song-poetry','','[]','病目醫治兩睫寬，迎風猶苦淚漫漫。',64,'全唐诗/poet.song.215000.json','["病目醫治兩睫寬，迎風猶苦淚漫漫。", "水邊望月雖無礙，燈下觀書便覺難。", "索句每防愁入腎，好杯多是熱歸肝。", "法當著意收神觀，不用金篦久自安。"]'),
('d068f5f4-053d-49b7-9389-8853a91523ed','飲葯房陳戶山居分韻得閤字','林尚仁','宋','宋诗','song-poetry','','[]','常人厭寂寥，隠士畏喧雜。',124,'全唐诗/poet.song.215000.json','["常人厭寂寥，隠士畏喧雜。", "山居主人百好無，終日哦詩閉書閤。", "我本山中人，心事亦頗合。", "杖藜約客行幽深，來扣吟扉坐陳榻。", "不敘寒暄說晚唐，滿座春風屢傾榼。", "霜晴沙路軟如泥，谷鳥相呼聲自答。", "花時不飲空白頭，世味由來如嚼蠟。", "祇憐無夢化作蝴蝶飛，遶盡百花深處日千匝。"]'),
('bdfcd9ec-c93a-414c-8ac9-302c5c104996','暑夜','林尚仁','宋','宋诗','song-poetry','','[]','松風生晚凉，坐久市聲歇。',24,'全唐诗/poet.song.215000.json','["松風生晚凉，坐久市聲歇。", "客去行獨吟，踏石碎明月。"]'),
('f64fc638-1b0f-4122-8c24-212b05430844','題蘆鄉思歸圖','林尚仁','宋','宋诗','song-poetry','','[]','不畫梅花却畫蘆，自言家在箇鄉居。',32,'全唐诗/poet.song.215000.json','["不畫梅花却畫蘆，自言家在箇鄉居。", "當時恨不曾添雁，爲带平安一紙書。"]'),
('0bc10d8f-4b54-4db2-be6a-17200b748fea','九日登烏回寄鄭渭濱','林尚仁','宋','宋诗','song-poetry','','[]','烏回山下寺，閑抱一琴遊。',48,'全唐诗/poet.song.215000.json','["烏回山下寺，閑抱一琴遊。", "客路黄花晚，江城寒露秋。", "持書誰送酒，懷古獨凭樓。", "想爾西風裏，遶籬吟未休。"]'),
('23712a92-1f90-4829-ae19-78b7a090530b','和陳葯房納凉','林尚仁','宋','宋诗','song-poetry','','[]','貪凉分石坐，野服岸巾紗。',48,'全唐诗/poet.song.215000.json','["貪凉分石坐，野服岸巾紗。", "竹暗鳴風葉，溪暄聚水花。", "深村人語靜，高樹鳥飛斜。", "不飲論文酒，敲碁煮夜茶。"]'),
('f5831bed-9eb0-49be-8318-4f184bf40f46','贈歌者','林尚仁','宋','宋诗','song-poetry','','[]','聲逐嬌雲學鳳鳴，王孫幾醉拍欄聽。',32,'全唐诗/poet.song.215000.json','["聲逐嬌雲學鳳鳴，王孫幾醉拍欄聽。", "春深莫唱關情曲，多少行人過柳亭。"]'),
('7c8b76e1-7c52-4946-a461-f59d3534a061','新昌道中','林尚仁','宋','宋诗','song-poetry','','[]','春紅落盡雨霏霏，爲怯輕寒尚夾衣。',64,'全唐诗/poet.song.215000.json','["春紅落盡雨霏霏，爲怯輕寒尚夾衣。", "村路每於泥處滑，鄉音漸與市人非。", "護蠶谿女條桑去，抱布山翁換米歸。", "世味徧嘗只如此，幾番清夢落漁磯。"]'),
('217cf842-b113-4122-abb4-6edb8a31421f','寓華亭下砂鹽場','林尚仁','宋','宋诗','song-poetry','','[]','地僻民居少，官勤國課優。',48,'全唐诗/poet.song.215000.json','["地僻民居少，官勤國課優。", "遠程驅瘦馬，小港礙行舟。", "晴日鹽花曉，風潮海氣秋。", "野人因買鶴，半月此遲留。"]'),
('b1480608-973d-4dbb-b1f1-60c53e634cf3','秋日書懷','林尚仁','宋','宋诗','song-poetry','','[]','十年客路歎飄蓬，歷盡風霜鬢欲空。',64,'全唐诗/poet.song.215000.json','["十年客路歎飄蓬，歷盡風霜鬢欲空。", "睡少半疑茶作祟，愁多全覺酒無功。", "數蛩厭靜鳴秋雨，一葉驚寒落晚風。", "惆悵故園歸未得，草荒籬下菊花叢。"]'),
('a3817c0f-95aa-4ab0-b9e3-52a961e29c1f','適越留別','林尚仁','宋','宋诗','song-poetry','','[]','江亭飲罷起離愁，何事西風又越遊。',32,'全唐诗/poet.song.215000.json','["江亭飲罷起離愁，何事西風又越遊。", "潮信欲來人欲去，夕陽紅蓼滿汀洲。"]'),
('413239a0-4c74-456a-89fd-dab47d4e1b36','此山林僉葯房陳戶偕張牧隠暮春晦日載酒相過席上以手揮素絃爲韻得絃字','林尚仁','宋','宋诗','song-poetry','','[]','春詩敲未穩，一醉傍琴眠。',48,'全唐诗/poet.song.215000.json','["春詩敲未穩，一醉傍琴眠。", "吟客相過日，飛花欲盡天。", "竹陰池水暗，樹色島雲連。", "幽鳥可人意，數聲清似絃。"]'),
('2d0114f7-2fd9-4388-9724-394d5fb7d76a','寒夜即事','林尚仁','宋','宋诗','song-poetry','','[]','吟苦過於顛，吟成亦自憐。',48,'全唐诗/poet.song.215000.json','["吟苦過於顛，吟成亦自憐。", "凍油燈影薄，深屋語聲圓。", "分月照歸客，避寒移卧氈。", "一冬少閑日，不得到梅邊。"]'),
('3c0a0405-1e79-48e6-946b-d63e7819f1ef','春日偶成','林尚仁','宋','宋诗','song-poetry','','[]','未逢知己愧蹉跎，又見春風長徑莎。',64,'全唐诗/poet.song.215000.json','["未逢知己愧蹉跎，又見春風長徑莎。", "杜宇一聲詩思減，楊花三月客愁多。", "從人乞米貧如舊，借吏抄書字半訛。", "懶說江湖十年事，近來平地亦風波。"]'),
('5fb541d1-2665-4f93-9287-7cb6ce255535','廢寺','林尚仁','宋','宋诗','song-poetry','','[]','敕額雖存屋半傾，爐香無主佛無靈。',32,'全唐诗/poet.song.215000.json','["敕額雖存屋半傾，爐香無主佛無靈。", "豪家不管空門事，日夜西風語塔鈴。"]'),
('05230922-a6cd-4cfc-9aeb-2a27840785f0','自賦','林尚仁','宋','宋诗','song-poetry','','[]','學書學劍兩無成，天乞梅邊隠姓名。',64,'全唐诗/poet.song.215000.json','["學書學劍兩無成，天乞梅邊隠姓名。", "未必清閑非盛福，縱教富貴亦虛榮。", "百年有限春風老，萬事無心夜月明。", "何計莫餐煙火供，漱流眠石過今生。"]'),
('bdbcd00d-d53c-4a50-ac6c-62785fbad18f','送林雲岫歸省','林尚仁','宋','宋诗','song-poetry','','[]','西風吹客衣，束擔出王畿。',48,'全唐诗/poet.song.215000.json','["西風吹客衣，束擔出王畿。", "千里莫嫌遠，幾人猶未歸。", "山空秋鶴瘦，天闊暮雲飛。", "料得還家日，將詩壽綵闈。"]'),
('6eaa62a8-b342-425f-9f07-5588b321ebab','雨中和張西麓','林尚仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨聲聽易厭，况復事關心。',48,'全唐诗/poet.song.215000.json','["雨聲聽易厭，况復事關心。", "終夜不成寐，一春徒費吟。", "委紅花命薄，重碧酒盃深。", "何日西湖上，移船繫柳陰。"]'),
('9ab6f6a4-a91b-4a98-879b-e98c173c1f6c','連雨留宿陳葯房吟所','林尚仁','宋','宋诗','song-poetry','','[]','谿水分流急，谿雲带濕飛。',48,'全唐诗/poet.song.215000.json','["谿水分流急，谿雲带濕飛。", "防饑童乞米，畏冷客添衣。", "雨院碁聲潤，風窗燭影微。", "終須待晴去，踏月夜深歸。"]'),
('87d8aad6-3dc5-4eaa-8d84-94e36c6b3913','偶題','林尚仁','宋','宋诗','song-poetry','','[]','矮屋過如斗樣寬，閉門渾不受春寒。',32,'全唐诗/poet.song.215000.json','["矮屋過如斗樣寬，閉門渾不受春寒。", "海棠睡去梨花瘦，次第東風到牡丹。"]'),
('1d8cfe13-4069-4b92-aa05-3689d5ab88e1','弔友人墓','林尚仁','宋','宋诗','song-poetry','','[]','樹陰雲影暗空山，銘石雖存不忍看。',32,'全唐诗/poet.song.215000.json','["樹陰雲影暗空山，銘石雖存不忍看。", "燒罷紙錢灰未冷，落花啼鴂雨聲寒。"]'),
('37390842-350f-497f-bfa7-11634af14485','遊陽明洞天','林尚仁','宋','宋诗','song-poetry','','[]','每箇虛亭坐片時，旋尋古蹟上巖梯。',64,'全唐诗/poet.song.215000.json','["每箇虛亭坐片時，旋尋古蹟上巖梯。", "石含秋色苔痕老，洞接雲天樹影低。", "樵客出林驚虎嘯，道人臨水聽猿啼。", "吟邊欲記陽明事，恐動山靈不敢題。"]'),
('904d760a-229f-443a-9a95-fad5df6efdd6','清真觀','林尚仁','宋','宋诗','song-poetry','','[]','一宮占斷水中央，瘦竹添丁護短牆。',64,'全唐诗/poet.song.215000.json','["一宮占斷水中央，瘦竹添丁護短牆。", "老鸛聲中松子落，遊鱼影裏藕花香。", "雲房不雨琴常潤，池閣無風榻自凉。", "擬辦隠心終老此，便須歸與鶴商量。"]'),
('677dcb44-24ae-49f0-8003-3d84665b9018','春晚','林尚仁','宋','宋诗','song-poetry','','[]','春事又無幾，陰晴苦不齊。',48,'全唐诗/poet.song.215000.json','["春事又無幾，陰晴苦不齊。", "久貧交味薄，多病語聲低。", "落絮行風徑，歸雲度晚谿。", "故鄉二千里，日夜子規啼。"]'),
('007c5e69-7db4-406b-8033-467087fedb35','贈褚雪巘','林尚仁','宋','宋诗','song-poetry','','[]','多年林下隠，猶带舊儒酸。',48,'全唐诗/poet.song.215000.json','["多年林下隠，猶带舊儒酸。", "自說因詩苦，還如學易難。", "曉窗花氣潤，夜枕雨聲寒。", "又欲名山去，應尋勝跡看。"]'),
('536c1671-1e8b-49a9-9f34-25a66ca74600','村居即事','林尚仁','宋','宋诗','song-poetry','','[]','外事少曾聞，深居似隠君。',48,'全唐诗/poet.song.215000.json','["外事少曾聞，深居似隠君。", "谿明花照影，風細水行文。", "蠶室寒初閉，蜂房早已分。", "偶因尋藥去，踏破一村雲。"]'),
('19cfd52f-df94-441a-b888-8dc398b7bb46','寓舍留別','林尚仁','宋','宋诗','song-poetry','','[]','撥盡寒灰雨夜深，半窗燈影伴孤吟。',32,'全唐诗/poet.song.215000.json','["撥盡寒灰雨夜深，半窗燈影伴孤吟。", "不眠只有琴知得，明日陽關何處心。"]'),
('3dcbc983-8016-4b28-b597-85c3ec38aff2','課伐木','林尚仁','宋','宋诗','song-poetry','','[]','手揮樵斧氣如虹，幾樹寒煙一餉空。',32,'全唐诗/poet.song.215000.json','["手揮樵斧氣如虹，幾樹寒煙一餉空。", "午夜無依烏鵲冷，數聲應恨月明中。"]'),
('ab6e7a55-f995-438f-ac8f-17955d33193b','懷潘寒巖','林尚仁','宋','宋诗','song-poetry','','[]','別後空相憶，無書直至今。',48,'全唐诗/poet.song.215000.json','["別後空相憶，無書直至今。", "頻年千里客，多事半生心。", "卯酒欺人醉，春詩带病吟。", "倚欄政無緒，一鳥過花陰。"]'),
('14530296-30aa-48ca-84f2-b45568da8dbc','余種竹方成扁其室曰竹所友人以詩至用其韻','林尚仁','宋','宋诗','song-poetry','','[]','屋老苔荒席久虛，近分一榻與雲俱。',64,'全唐诗/poet.song.215000.json','["屋老苔荒席久虛，近分一榻與雲俱。", "梅花未種招蜂怨，竹所雖清欠鶴圖。", "無事看山如對客，有時隠几亦忘吾。", "過門除却能吟者，不是高僧即老儒。"]'),
('8fca0beb-acaf-42a1-96a7-5937a74227fa','山居','林尚仁','宋','宋诗','song-poetry','','[]','帝城花錦地，讓與市人居。',48,'全唐诗/poet.song.215000.json','["帝城花錦地，讓與市人居。", "萬事不到耳，一貧唯讀書。", "掃牀留月宿，種藥带雲鋤。", "未晚多先醉，爲官恐不如。"]'),
('51a8368c-983c-4ab2-8e4f-35b7d202fdaa','簡許有實','林尚仁','宋','宋诗','song-poetry','','[]','閑磨霜刃破銀瓜，沉水香銷日影斜。',32,'全唐诗/poet.song.215000.json','["閑磨霜刃破銀瓜，沉水香銷日影斜。", "吟客不來情思懶，晚風庭院落槐花。"]'),
('f2bb8066-d9f7-4a0b-b225-47f49bb1a989','陳葯房聞人禺谿黄平嶺春日相過分得琴字','林尚仁','宋','宋诗','song-poetry','','[]','半生無厚業，祇合住山林。',48,'全唐诗/poet.song.215000.json','["半生無厚業，祇合住山林。", "留客旋沽酒，典衣因買琴。", "晴窗行野馬，高樹語春禽。", "彼此知心久，相看意轉深。"]'),
('48df67ab-c2ff-47bf-bcc0-337163bb50c9','過友人幽居','林尚仁','宋','宋诗','song-poetry','','[]','門似野人家，空園擬種瓜。',48,'全唐诗/poet.song.215000.json','["門似野人家，空園擬種瓜。", "有僧分石坐，無酒問鄰賒。", "獨鶴喜欲舞，老梅寒自花。", "此身歸未去，猶愧暮林鴉。"]'),
('aee255c3-2af7-43c6-9328-6c9a9450649f','旅懷','林尚仁','宋','宋诗','song-poetry','','[]','欲暮西風引客愁，十年如夢住他州。',64,'全唐诗/poet.song.215000.json','["欲暮西風引客愁，十年如夢住他州。", "故交零落誰知己，往事凄凉歎白頭。", "一紙音書燈下淚，滿城砧杵月明秋。", "早知世路風波險，只在山中煮石休。"]'),
('2e0cc72d-3efc-4dbd-aeff-ca34691bdff7','懷蒲一庵許紒巖','林尚仁','宋','宋诗','song-poetry','','[]','新營一榻養天和，獨喜身閑鬢未皤。',64,'全唐诗/poet.song.215000.json','["新營一榻養天和，獨喜身閑鬢未皤。", "藥性不諳緣病少，花名慣識爲吟多。", "移書曬日防留蠹，寫帖臨池擬換鵝。", "不到玉峰今兩載，故人情味近如何。"]'),
('666412f2-d5fa-4ee4-8036-5ea640671b8b','陳葯房舟中分得詩字','林尚仁','宋','宋诗','song-poetry','','[]','移舟春岸曉，小雨欲晴時。',48,'全唐诗/poet.song.215000.json','["移舟春岸曉，小雨欲晴時。", "煙樹望疑暗，水程行較遲。", "推蓬山色近，得句野鷗知。", "來往無多路，歸囊又一詩。"]'),
('a2ca7ccd-23ab-48ab-ba12-6f0768489b0b','寄表兄鄭古潭','林尚仁','宋','宋诗','song-poetry','','[]','江湖風浪惡，飄泊此依依。',48,'全唐诗/poet.song.215000.json','["江湖風浪惡，飄泊此依依。", "白髮親俱老，深春人未歸。", "雲留行李住，風遣落花飛。", "强飲盃中物，芳心莫易違。"]'),
('0f13cea6-3eb4-4bc1-9b50-01470fad1bdd','閒裏','林尚仁','宋','宋诗','song-poetry','','[]','閒裏身心得自如，春風茅屋燕同居。',32,'全唐诗/poet.song.215000.json','["閒裏身心得自如，春風茅屋燕同居。", "松花滿地谿雲滑，一榻晴窗卧看書。"]'),
('119968a7-a550-46b7-a2d6-b2149add55c2','寄西湖友人','林尚仁','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖邊春更好，別後費吟思。',48,'全唐诗/poet.song.215000.json','["湖邊春更好，別後費吟思。", "載酒曾遊處，憶君同醉時。", "面風花落易，背日雪消遲。", "早晚携琴去，山中與鶴期。"]'),
('acf2cc2d-b751-4b16-be8a-fe1fd7af23eb','送友人別','林尚仁','宋','宋诗','song-poetry','','[]','此心偶無事，君復敘離情。',48,'全唐诗/poet.song.215000.json','["此心偶無事，君復敘離情。", "江國多寒色，春風幾日程。", "雪添行李重，船逐浪花輕。", "後夜應相憶，空山月正明。"]'),
('28d4c049-b52d-4f2e-8546-a85e1f6a8c46','送楊巨川遊邊','林尚仁','宋','宋诗','song-poetry','','[]','此行不必話離愁，且舉匏樽醉幾籌。',64,'全唐诗/poet.song.215000.json','["此行不必話離愁，且舉匏樽醉幾籌。", "天下豈無山可買，男兒當與國分憂。", "劍辭星匣邊風凜，船駕雲帆海月流。", "莫道讀書無用處，讀書方有用兵謀。"]'),
('8fb7e50c-b5f4-4b06-a9fd-3d433f948b4c','寄鄉友','林尚仁','宋','宋诗','song-poetry','','[]','此身拘不得，暮楚又朝吳。',48,'全唐诗/poet.song.215000.json','["此身拘不得，暮楚又朝吳。", "故國幾人在，三年一字無。", "天風潮信急，江月雁聲孤。", "久不看明鏡，年來有白鬚。"]'),
('4777adbc-65d5-4908-9b7c-624788f4d8f0','寄吳宗之','林尚仁','宋','宋诗','song-poetry','','[]','在家猶苦熱，客路足應疲。',48,'全唐诗/poet.song.215000.json','["在家猶苦熱，客路足應疲。", "書劍果何地，江湖非舊時。", "久晴苗欲雨，多病藥如飴。", "憶自分携後，知心更有誰。"]'),
('eb00dfbf-6f3e-492d-84d3-be3de3ac445b','雪中呈社友','林尚仁','宋','宋诗','song-poetry','','[]','風雨蕭蕭攪雪飛，一寒如此只貪詩。',32,'全唐诗/poet.song.215000.json','["風雨蕭蕭攪雪飛，一寒如此只貪詩。", "酒瓢傾盡囊金少，恐被梅花笑不知。"]'),
('196fca3d-5598-43d2-b43c-a4bab2f69b84','送陸月湖歸玉峰','林尚仁','宋','宋诗','song-poetry','','[]','行李無多半是詩，買船兼載鶴同歸。',32,'全唐诗/poet.song.215000.json','["行李無多半是詩，買船兼載鶴同歸。", "思君晚泊吳江冷，風捲蘆花幾雁飛。"]'),
('32ecf777-e151-49b2-ade6-06d9b314435a','喜友人爲僧','林尚仁','宋','宋诗','song-poetry','','[]','身披雲衲瘦伶俜，一刺新添得寺名。',64,'全唐诗/poet.song.215000.json','["身披雲衲瘦伶俜，一刺新添得寺名。", "餐供未便趺足坐，誦經猶作讀書聲。", "禪窗欲晚聞鐘掩，吟履逢秋踏葉行。", "應是千生修得到，幾人頭白尚無成。"]'),
('61dca0cb-3064-48dc-93e7-510de93eab53','贈許紒巖','林尚仁','宋','宋诗','song-poetry','','[]','年齒未三十，清名已照人。',48,'全唐诗/poet.song.215000.json','["年齒未三十，清名已照人。", "才高猶苦學，俸薄不言貧。", "留客醉終日，愛花吟過春。", "自憐閑未得，滿面撲京塵。"]'),
('9983cd48-da0f-46b7-9e32-c9c01cbaca85','辛亥元日遊聞人省庵園和陳葯房韻','林尚仁','宋','宋诗','song-poetry','','[]','倚欄吟未穩，把酒問溪山。',48,'全唐诗/poet.song.215000.json','["倚欄吟未穩，把酒問溪山。", "今日又添歲，一冬無此閑。", "梅花依竹靜，雪意避春慳。", "次第燈期近，重逢一解顔。"]'),
('b4d00634-f315-4d21-8c2d-bdee7ba85ab1','賀陳石泉宰華亭歸','林尚仁','宋','宋诗','song-poetry','','[]','天下稱繁邑，一廉如此希。',48,'全唐诗/poet.song.215000.json','["天下稱繁邑，一廉如此希。", "政成人惜去，官滿鶴先歸。", "家學傳金管，春風入紫薇。", "知音正當路，健翼看高飛。"]'),
('10cd2606-ea29-4240-a8b5-31a0a42b6859','夜坐','林尚仁','宋','宋诗','song-poetry','','[]','焚香獨坐勘騷經，庭樹無風葉不鳴。',32,'全唐诗/poet.song.215000.json','["焚香獨坐勘騷經，庭樹無風葉不鳴。", "靜入夜深聞鼓吹，一池明月亂蛙聲。"]'),
('0621209d-399a-4268-9560-2f83d8c6eb2d','梅雨','林尚仁','宋','宋诗','song-poetry','','[]','繁聲不可聽，點滴似秋霖。',48,'全唐诗/poet.song.215000.json','["繁聲不可聽，點滴似秋霖。", "谿長欲無岸，窗低微復陰。", "葛衣凉意重，礎石潤痕深。", "欲出愁泥濘，依依獨客心。"]'),
('09e49fdd-e68a-4d2f-b157-1d8953acdcf1','訪隠者','林尚仁','宋','宋诗','song-poetry','','[]','姓名多已在仙行，見說曾傳辟穀方。',64,'全唐诗/poet.song.215000.json','["姓名多已在仙行，見說曾傳辟穀方。", "未必詔書徵便起，可憐人世老猶忙。", "浴蒲磵冷雲初濕，種朮山春土亦香。", "何日此身分半隠，歸須先製芰荷裳。"]'),
('e8468eb6-d223-4b05-ad36-edb1a1a2d9ab','戲友人買侍兒歸','林尚仁','宋','宋诗','song-poetry','','[]','幾扣吟窗多不遇，識君雖久會君稀。',64,'全唐诗/poet.song.215000.json','["幾扣吟窗多不遇，識君雖久會君稀。", "近聞行李擔書去，添得明珠伴劍歸。", "開甕酒香春遶屋，倚欄人醉月侵衣。", "野夫別有觀心法，不在深山獨掩扉。"]'),
('4983c1c5-786b-4148-abee-5b19b577965b','鶴','林尚仁','宋','宋诗','song-poetry','','[]','楚楚異凡禽，相看瘦不禁。',48,'全唐诗/poet.song.215000.json','["楚楚異凡禽，相看瘦不禁。", "饑尋芝朮晚，夢憶海山深。", "華表千年事，青天萬里心。", "一聲唳清夜，霜月滿疎林。"]'),
('6e7124b6-b83a-42b4-b3cf-c5345976c7c7','寄陳赤嵌','何文季','宋','宋诗','song-poetry','','[]','英雄空有淚沾襟，千古興亡感慨深。',64,'全唐诗/poet.song.215000.json','["英雄空有淚沾襟，千古興亡感慨深。", "邱壑正多亡國恨，干戈消盡讀書心。", "容身天地生何補，入眼風霜老不禁。", "却笑紅塵知退晚，能教早計卧山林。"]'),
('0f1f3910-a724-4bde-91de-28ce10fc8fd1','寄懷','何文季','宋','宋诗','song-poetry','','[]','衣冠不忍墜家聲，風雨瀟瀟鷄自鳴。',64,'全唐诗/poet.song.215000.json','["衣冠不忍墜家聲，風雨瀟瀟鷄自鳴。", "身似孤蓬隨地轉，家無長物带書行。", "荒涼松竹鄉心外，淡薄虀鹽世味輕。", "幸有田疇堪料理，何如買犢且歸耕。"]'),
('6caf7746-7600-4f51-a393-e1ee4a3c4776','送黄坡峰','何文季','宋','宋诗','song-poetry','','[]','浮萍浩蕩夾桑榆，茅屋田園狐兔墟。',64,'全唐诗/poet.song.215000.json','["浮萍浩蕩夾桑榆，茅屋田園狐兔墟。", "拾橡豈能饑杜甫，鬻車終不困相如。", "子規枝上他鄉月，白鶴峰頭處士廬。", "三徑雖荒歸亦好，筆耕還有腹中書。"]'),
('2b4a8144-92f6-4184-aee7-c4e315e9b4b7','寄彭府教','何文季','宋','宋诗','song-poetry','','[]','食薇已愧首陽人，肯學楊雄作美新。',64,'全唐诗/poet.song.215000.json','["食薇已愧首陽人，肯學楊雄作美新。", "滿目山河長是淚，窮崖草木不知春。", "狂來自與白雲笑，老去從教俗子嗔。", "湖海論交無久近，相逢同是漢遺民。"]'),
('24be7fdf-97db-41bd-a886-ccceee3a1cd2','送翁主學謁靖山提舉','何文季','宋','宋诗','song-poetry','','[]','三百年間植士林，年來零落幾青衿。',64,'全唐诗/poet.song.215000.json','["三百年間植士林，年來零落幾青衿。", "人間已厭詩書味，堂上猶聞絲竹音。", "山向靜中涵易象，陽於復處見天心。", "執經弟子趨函丈，祗恐門前雪意深。"]'),
('fd9edcca-1d23-4791-8b4b-1373f4604f9f','寄朱五哥','何文季','宋','宋诗','song-poetry','','[]','單父琴邊遇賞音，臯比巍坐屋廬深。',64,'全唐诗/poet.song.215000.json','["單父琴邊遇賞音，臯比巍坐屋廬深。", "客中莫放揮金手，酒後無忘守口箴。", "投筆未酬豪傑志，讀書猶識聖賢心。", "何時棹破山陰雪，共對青燈談古今。"]'),
('25e6e9f3-4ca0-4e84-acbe-851e394f2539','送邵省元','何文季','宋','宋诗','song-poetry','','[]','血汗文場日未東，秋香壓倒萬花叢。',64,'全唐诗/poet.song.215000.json','["血汗文場日未東，秋香壓倒萬花叢。", "幾年豹隠山中霧，一息鵬摶海上風。", "魁業正須期遠大，微官豈足論窮通。", "龍門有客來相訪，爲說憂時鬢已翁。"]'),
('755ec9cd-8ec2-4c59-bbaa-f7530df4d0c9','寄蘧覺陳先生','何文季','宋','宋诗','song-poetry','','[]','白髮相看重別離，幾囘默坐撚吟髭。',64,'全唐诗/poet.song.215000.json','["白髮相看重別離，幾囘默坐撚吟髭。", "子猷不作乘舟興，龐老終無出郭時。", "隔面雲山如有礙，輸心泓穎寄相思。", "文溪遺稿傷淪落，此事還當付與誰。"]'),
('c7ec6fde-7b04-4124-9cfd-9f4f06b686b9','寄姚達泉','何文季','宋','宋诗','song-poetry','','[]','鵬程九萬儘天寬，剛被西風鎩羽翰。',64,'全唐诗/poet.song.215000.json','["鵬程九萬儘天寬，剛被西風鎩羽翰。", "四海車書新宇宙，幾家門戶舊衣冠。", "園花灼灼酣春夢，澗竹亭亭傲歲寒。", "正氣莫教銷鑠盡，典型留與後人看。"]'),
('44c8cf84-a8d3-43cb-a38c-fe7dde144464','再用汪縣尹韻寄彭府教','何文季','宋','宋诗','song-poetry','','[]','日入崦嵫萬念灰，出門笑口爲誰開。',64,'全唐诗/poet.song.215000.json','["日入崦嵫萬念灰，出門笑口爲誰開。", "人從飯顆山頭遇，春在梅花枝上來。", "有夢欲隨流水去，無詩怕被黑雲催。", "疊山曾是江湖友，恨殺吟魂喚不囘。"]'),
('b3bba408-b6c7-4358-9315-93c18e30d174','寄懷','何文季','宋','宋诗','song-poetry','','[]','白髮蕭蕭壯氣衰，垂頭兀兀董生帷。',64,'全唐诗/poet.song.215000.json','["白髮蕭蕭壯氣衰，垂頭兀兀董生帷。", "饑難煮字將焚硯，語不驚人懶作詩。", "昔日卞和常泣玉，今時墨子更悲絲。", "自從夢筆風流後，枯朽那能出菌芝。"]'),
('66d3ac4c-0713-42f8-915f-65128e08edbd','寄石溪  其一','何文季','宋','宋诗','song-poetry','','[]','錦雲曾逐好風來，强學嬌顰寄雁囘。',32,'全唐诗/poet.song.215000.json','["錦雲曾逐好風來，强學嬌顰寄雁囘。", "鯨浪拍天滄海闊，祇愁無路到蓬萊。"]'),
('6024e724-9173-4a80-81cf-6c8036c43962','寄石溪  其二','何文季','宋','宋诗','song-poetry','','[]','龐老多年不入州，一竿危坐石溪頭。',32,'全唐诗/poet.song.215000.json','["龐老多年不入州，一竿危坐石溪頭。", "山中飽食魚羹飯，不博人間萬戶侯。"]'),
('2572f210-4da4-4c65-afde-893229178662','寄石溪  其三','何文季','宋','宋诗','song-poetry','','[]','長天淡淡雁沈沈，人在桃源路更深。',32,'全唐诗/poet.song.215000.json','["長天淡淡雁沈沈，人在桃源路更深。", "一點靈犀千里月，雲遮不斷故人心。"]'),
('7b0e41cd-7be8-468c-9de4-8f79565bb6c7','題嚴子陵垂釣圖','何文季','宋','宋诗','song-poetry','','[]','卧足曾將帝腹加，拂衣歸去伴烟霞。',32,'全唐诗/poet.song.215000.json','["卧足曾將帝腹加，拂衣歸去伴烟霞。", "祗消一釣名千古，虧殺當年鄧仲華。"]'),
('a9cd14da-5591-470b-8c5c-7588df82c032','別徐大使','何文季','宋','宋诗','song-poetry','','[]','去來書畫米家船，聊結梅花一笑緣。',32,'全唐诗/poet.song.215000.json','["去來書畫米家船，聊結梅花一笑緣。", "不爲蓴鱸棄官去，歸心祗在白雲邊。"]'),
('2516b47b-e62d-4109-9c79-ff27716b2943','何達觀久客他鄉音問曠絕一日忽見過又匆匆告別吾老且病未知後會何如走筆以贈','何文季','宋','宋诗','song-poetry','','[]','風萍渺無跡，一日扣柴扉。',48,'全唐诗/poet.song.215000.json','["風萍渺無跡，一日扣柴扉。", "乍見猶疑夢，相逢遽語違。", "子方懷遠志，誰復挽征衣。", "烟雨松楸隔，何當賦式微。"]'),
('c9d8293a-3ac7-49a0-a896-9570816ba738','別趙丞','何文季','宋','宋诗','song-poetry','','[]','花縣平分月，冰壺不受塵。',48,'全唐诗/poet.song.215000.json','["花縣平分月，冰壺不受塵。", "圓機皆中理，禮愛獨親仁。", "晚菊長留節，寒梅自作春。", "無家可歸去，須有築臺人。"]'),
('c5eae12d-cb52-4858-ac07-7f5a59162591','秋堂弟自贛歸建安作別','何文季','宋','宋诗','song-poetry','','[]','同飲西江甫兩春，匆匆馬首又東馳。',64,'全唐诗/poet.song.215000.json','["同飲西江甫兩春，匆匆馬首又東馳。", "歸與華閣春風裏，憶我鈴齋夜雨時。", "好把汗青傳久遠，莫將朱紫裹愚癡。", "閩中多有南翔雁，折取梅花寄一枝。"]'),
('08f36383-ce9a-4869-8c0b-2df37ec6cd24','寄蘧覺先生','何文季','宋','宋诗','song-poetry','','[]','雲山隔斷故人疎，聞道新生三鳳雛。',32,'全唐诗/poet.song.215000.json','["雲山隔斷故人疎，聞道新生三鳳雛。", "老我只添頭上雪，淒涼光景不堪書。"]'),
('c518fc68-0ff4-4699-9486-aef64e2ed347','畫呂仙贊','何文季','宋','宋诗','song-poetry','','[]','杖頭挑起碧山雲，劍氣擘開滄浪海。',32,'全唐诗/poet.song.215000.json','["杖頭挑起碧山雲，劍氣擘開滄浪海。", "鞭龍笞鳳遊八區，長嘯一聲天浩蕩。"]'),
('8528b41a-5a00-4258-9a5f-21ae41843f21','吳子珍登仕避地大寧示詩賡韻以謝','何文季','宋','宋诗','song-poetry','','[]','雁行聲價壓朋儔，凜凜詞鋒炯二矛。',32,'全唐诗/poet.song.215000.json','["雁行聲價壓朋儔，凜凜詞鋒炯二矛。", "寶劍神光埋不住，夜衝星斗落旄頭。"]'),
('a3b26330-9b80-4b41-950d-033b2fd9ea51','宣差曾思丁得替歸詩以贈之','何文季','宋','宋诗','song-poetry','','[]','田家不放淚痕乾，日日深山吏打門。',32,'全唐诗/poet.song.215000.json','["田家不放淚痕乾，日日深山吏打門。", "憶昔宣差提調日，關征不到杏花村。"]'),
('2f8bb870-ea93-426b-81b3-6fa2565c3416','山礬花','祝穆','宋','宋诗','song-poetry','','[]','玲瓏葉底雪花寒，清晝香薰草木間。',32,'全唐诗/poet.song.215000.json','["玲瓏葉底雪花寒，清晝香薰草木間。", "移植小軒供宴坐，恍疑身在普陀山。"]'),
('07f026a5-e075-478c-8f57-55a1662612ff','豫章','祝穆','宋','宋诗','song-poetry','','[]','豫章偃蹇兩蒼龍，雪幹寧須匠石逢。',32,'全唐诗/poet.song.215000.json','["豫章偃蹇兩蒼龍，雪幹寧須匠石逢。", "借重歲寒雙大字，絕勝松拜大夫封。"]'),
('ee733270-0234-4470-9229-58fa17df8e5a','句  其一','祝穆','宋','宋诗','song-poetry','','[]','黄花自與淵明別，不見閑人直到今。',16,'全唐诗/poet.song.215000.json','["黄花自與淵明別，不見閑人直到今。"]'),
('3b503a92-7346-46d8-8a57-c41b7dc5b101','句  其二','祝穆','宋','宋诗','song-poetry','','[]','細花穿弱縷，盤向綠雲鬟。',12,'全唐诗/poet.song.215000.json','["細花穿弱縷，盤向綠雲鬟。"]'),
('71c43788-bb54-4531-8550-aebf7a7ae329','白雲亭','釋正韶','宋','宋诗','song-poetry','','[]','白雲亭上白雲閑，雲滿危欄雪滿山。',32,'全唐诗/poet.song.215000.json','["白雲亭上白雲閑，雲滿危欄雪滿山。", "雪似白雲雲似雪，不知何處是人間。"]'),
('559ea40e-5adb-4d64-b9ab-780fa6896f28','夏令燬生佛銜','詹夢璧','宋','宋诗','song-poetry','','[]','共稱生佛戴恩波，一飽歡騰鼓腹歌。',32,'全唐诗/poet.song.215000.json','["共稱生佛戴恩波，一飽歡騰鼓腹歌。", "家有佛銜收拾去，人心有佛可收麽。"]'),
('d9af8c60-4b84-4fe1-9549-6bf1703fee10','仙人石','徐圓老','宋','宋诗','song-poetry','','[]','花開炫紅霞，景接長春壑。',36,'全唐诗/poet.song.215000.json','["花開炫紅霞，景接長春壑。", "終古斯石存，蒼苔涴雙脚。", "安得洞仙來，重遊跨白鶴。"]'),
('e93fa272-dc1a-4074-8513-e87e4d4256ea','寄劉後村','湯漢','宋','宋诗','song-poetry','','[]','唐朝空自貴宏詞，科目何嘗得退之。',64,'全唐诗/poet.song.215000.json','["唐朝空自貴宏詞，科目何嘗得退之。", "掌制徒聞誇子厚，殘篇僅見命敦詩。", "堪嗟實錄無完傳，太息淮西有後碑。", "寄語莆田紫薇老，文章蓋世例如斯。"]'),
('74d7a1a5-8d94-45a2-a7ee-ae918ed09c52','自儆','湯漢','宋','宋诗','song-poetry','','[]','春秋責備賢者，造物計校好人。',28,'全唐诗/poet.song.215000.json','["春秋責備賢者，造物計校好人。", "一點莫留餘滓，十分成就全身。"]'),
('be95995a-3e40-4e50-b0f8-d51ec905a27c','題靈鷲四首  其一','湯漢','宋','宋诗','song-poetry','','[]','靈鷲古道場，攝乎大國間。',24,'全唐诗/poet.song.215000.json','["靈鷲古道場，攝乎大國間。", "一日忽翬飛，四顧無靦顔。"]'),
('e7abe463-9509-487b-a437-2e2531e7a7b0','題靈鷲四首  其二','湯漢','宋','宋诗','song-poetry','','[]','引泉已成沼，對石宜破窗。',24,'全唐诗/poet.song.215000.json','["引泉已成沼，對石宜破窗。", "他年澗上橋，爲子書春淙。"]'),
('82a17a3d-3ebe-42e7-906b-13f2f5a067bf','題靈鷲四首  其三','湯漢','宋','宋诗','song-poetry','','[]','南澗靜者徒，小試扶顛手。',24,'全唐诗/poet.song.215000.json','["南澗靜者徒，小試扶顛手。", "期畢棟宇工，拂衣入巖岫。"]'),
('f697b867-4f0e-4f08-84d8-312cc09b500d','題靈鷲四首  其四','湯漢','宋','宋诗','song-poetry','','[]','問禪去靈隠，聽講去天竺。',24,'全唐诗/poet.song.215000.json','["問禪去靈隠，聽講去天竺。", "還有無求人，來尋靈鷲宿。"]'),
('2105943a-5c8e-4c01-9c5a-dc9a02b29754','宿孔野雲丹房','湯漢','宋','宋诗','song-poetry','','[]','天師煉丹時，丹鼎見龍虎。',48,'全唐诗/poet.song.215000.json','["天師煉丹時，丹鼎見龍虎。", "丹成天師去，龍虎名萬古。", "溪深松杪風，山明夜來雨。", "雨後丹鳳鳴，風前黄鵠舉。"]'),
('ec13cb8b-ad1d-4715-885c-13dabb576c14','贈久軒提刑江東二首  其一','湯漢','宋','宋诗','song-poetry','','[]','江右皇華遡浙東，按行特地到山中。',64,'全唐诗/poet.song.215000.json','["江右皇華遡浙東，按行特地到山中。", "柴門忽有高軒過，衰俗久無前輩風。", "嵩嶽氣摇消息長，祝融開霽鬼神通。", "荒崖絕谷留光彩，長使人懷太極翁。"]'),
('6d48d613-ea65-4eb1-9544-d9432b4adab3','贈久軒提刑江東二首  其二','湯漢','宋','宋诗','song-poetry','','[]','嚮來廷諍偉堂堂，不負西山與紫陽。',64,'全唐诗/poet.song.215000.json','["嚮來廷諍偉堂堂，不負西山與紫陽。", "盡道拾遺當召黯，不應清詔久煩滂。", "真儒事業誰能測，憂國忠純不謾狂。", "一上蓬萊看雲海，細氈歸去論虞唐。"]'),
('219b4c21-af4e-4e97-bed7-8a62d4361244','觀魚亭','湯漢','宋','宋诗','song-poetry','','[]','有亭翼然山之阿，源頭活水養魚多。',122,'全唐诗/poet.song.215000.json','["有亭翼然山之阿，源頭活水養魚多。", "雲山四面如畫圖，金梭上下光相摩。", "池上木深陰翳地，池下荷生香撲鼻。", "携酒邀朋池上觀，圉圉洋洋真得意。", "咄，東海鯉，南溟魚，自信時人莫淺窺，神靈豈是池中物。", "變化成龍會有期，一朝烜赫雷聲壯。", "翻身直透三層浪，揚鬐鼓鬣橫千丈。"]'),
('1843ee2b-cfa8-4e3b-b902-911e78e705c6','偈頌一百三十六首  其一','釋惟一','宋','宋诗','song-poetry','','[]','是法住法位，世間相常住。',24,'全唐诗/poet.song.215000.json','["是法住法位，世間相常住。", "佛殿對三門，燈籠掛露柱。"]'),
('ce808d85-28f1-42e5-a97d-58f515864343','偈頌一百三十六首  其二','釋惟一','宋','宋诗','song-poetry','','[]','浴冰橋畔，伏虎巖前。',42,'全唐诗/poet.song.215000.json','["浴冰橋畔，伏虎巖前。", "雪消松杪，春到梅邊。", "古佛眼睛突出，瞿曇面目昭然。", "認著依前隔大千。"]'),
('708e8c71-0323-44dd-b2c6-8fdd72709c13','偈頌一百三十六首  其三','釋惟一','宋','宋诗','song-poetry','','[]','夜夜明星現，有眼誰不見。',40,'全唐诗/poet.song.215000.json','["夜夜明星現，有眼誰不見。", "此夜老瞿曇，却被明星轉。", "直至而今雙眼花，無瑕白玉自生瑕。"]'),
('4625ecc5-7fc7-405d-a2ea-17748df183b0','偈頌一百三十六首  其四','釋惟一','宋','宋诗','song-poetry','','[]','和暖上元天氣，是處笙歌動地。',28,'全唐诗/poet.song.215000.json','["和暖上元天氣，是處笙歌動地。", "瑞巖無可設施，隨分放燈一二。"]'),
('4d43badc-e707-4d02-98d7-cd22aa04c5aa','偈頌一百三十六首  其五','釋惟一','宋','宋诗','song-poetry','','[]','今朝十五，明朝十六。',96,'全唐诗/poet.song.215000.json','["今朝十五，明朝十六。", "瓠苦瓜甜，松直棘曲。", "辟支老漢，炎夏衣楮，嚴冬浴冰，謾自辛勤，徒勞檢束。", "爭似而今禪和，三三兩兩，水邊林下，寒向火，熱乘凉，又誰管你地覆天翻，天翻地覆。", "是玉也大奇，只恐不是玉。"]'),
('ee98d038-235c-4940-beb1-ed201b280a3a','偈頌一百三十六首  其六','釋惟一','宋','宋诗','song-poetry','','[]','露冷風清，山空月明。',52,'全唐诗/poet.song.215000.json','["露冷風清，山空月明。", "天際歸鴻書梵字，夜深砧杵送秋聲。", "眼覷不見，耳聽不聞。", "與君傾盡此時心，莫認山河作眼睛。"]'),
('17834d45-d833-4845-80b9-aba689dc5dd1','偈頌一百三十六首  其七','釋惟一','宋','宋诗','song-poetry','','[]','伏虎巖前，螺江江上。',32,'全唐诗/poet.song.215000.json','["伏虎巖前，螺江江上。", "一去一來，無去來相。", "今朝古辟支，昔日翁和尚。"]'),
('a4b85346-c69e-4ed3-beec-3f4356916c55','偈頌一百三十六首  其八','釋惟一','宋','宋诗','song-poetry','','[]','微雨潤枯荄，嚴風攪林木。',64,'全唐诗/poet.song.215000.json','["微雨潤枯荄，嚴風攪林木。", "梅唇已破香，柳眼眠未足。", "塵世競奔忙，光景相追逐。", "林間無事人，好唱雲門曲。", "今朝臘月二十五，明朝臘月二十六。"]'),
('77513771-a750-4225-9154-657378a621c7','偈頌一百三十六首  其九','釋惟一','宋','宋诗','song-poetry','','[]','今日上元令節，雨意連綿未歇。',38,'全唐诗/poet.song.215000.json','["今日上元令節，雨意連綿未歇。", "過去燃燈如來，全體一時漏泄。", "簷頭滴滴，分明歷歷。"]'),
('32a05a9e-d04d-428f-860c-a60bc394af42','偈頌一百三十六首  其一○','釋惟一','宋','宋诗','song-poetry','','[]','建嶺雲，建溪水。',56,'全唐诗/poet.song.215000.json','["建嶺雲，建溪水。", "縹緲無邊，淵深無底。", "盡情收拾歸來，點滴無非珍貴。", "拋向諸人面前，切忌自生擬議。", "見之不取，思之千里。"]'),
('16bf9484-ddc2-48c1-8f99-ff3461063576','偈頌一百三十六首  其一一','釋惟一','宋','宋诗','song-poetry','','[]','禪禪，風生木杪，葉墜庭前。',67,'全唐诗/poet.song.215000.json','["禪禪，風生木杪，葉墜庭前。", "唧唧寒蛩吟破壁，聲聲歸雁度遼天。", "諸人若也會得，此去吳屯不遠。", "若也不會，藍溪水透洋邊。", "阿呵呵，笑倒武夷張大僊。"]'),
('b55880da-dead-4168-96bb-f1947e3637d2','偈頌一百三十六首  其一二','釋惟一','宋','宋诗','song-poetry','','[]','皎潔中秋月，清光處處同。',48,'全唐诗/poet.song.215000.json','["皎潔中秋月，清光處處同。", "是人皆照破，無水不形容。", "圓滿纖塵浄，婆娑桂影重。", "古今爭賞翫，誰到廣寒宮。"]'),
('cb10ee3c-e855-4dbc-880b-3888028a6daf','偈頌一百三十六首  其一三','釋惟一','宋','宋诗','song-poetry','','[]','舊日重陽，今日重陽，籬菊披金淺淺黄。',79,'全唐诗/poet.song.215000.json','["舊日重陽，今日重陽，籬菊披金淺淺黄。", "休訝去年蓬鬢，今歲半成霜。", "喜得同人相訪，那邊風景，此間風景，且莫論量。", "相與對花賒一醉，高歌大笑，手舞足蹈，聽教人道掣顛狂。"]'),
('8635f032-270d-4b03-89a4-ab2436d1eccf','偈頌一百三十六首  其一四','釋惟一','宋','宋诗','song-poetry','','[]','虎溪冰瑩長空月，鳳嶺松吟後夜風。',32,'全唐诗/poet.song.215000.json','["虎溪冰瑩長空月，鳳嶺松吟後夜風。", "堪笑堪悲翁老子，儼然不改舊時容。"]'),
('f74da4ee-d802-40e6-b670-274bf6c1ae19','偈頌一百三十六首  其一五','釋惟一','宋','宋诗','song-poetry','','[]','可祖齊腰立雪，長慶坐破蒲團。',80,'全唐诗/poet.song.215000.json','["可祖齊腰立雪，長慶坐破蒲團。", "一人鐵壁覷要透，一人滄海瀝須乾。", "鐵壁透，滄海乾，出禮三拜依位立，捲起簾來天下寬。", "堪悲堪笑，何易何難。", "信道梅花香撲鼻，須是徹骨一番寒。"]'),
('bc6bd944-f8d6-4a6b-a825-9545b69a39ff','偈頌一百三十六首  其一六','釋惟一','宋','宋诗','song-poetry','','[]','羅綺叢中，笙歌社裏。',20,'全唐诗/poet.song.215000.json','["羅綺叢中，笙歌社裏。", "燈明如來，放光現瑞。"]'),
('7325345c-eacf-4067-9d04-49051fbf086c','偈頌一百三十六首  其一七','釋惟一','宋','宋诗','song-poetry','','[]','秋風捲地，秋水連天。',36,'全唐诗/poet.song.215000.json','["秋風捲地，秋水連天。", "千山影瘦，萬木蕭然。", "漁笛數聲江上月，樵歌一曲嶺頭烟。"]'),
('a83fceda-7f4a-4a40-8014-087a7da265bb','偈頌一百三十六首  其一八','釋惟一','宋','宋诗','song-poetry','','[]','楊岐三脚馿，虎丘睡虎子。',24,'全唐诗/poet.song.215000.json','["楊岐三脚馿，虎丘睡虎子。", "毛色既一同，蹄爪亦相似。"]'),
('02a088f8-3da5-4ec8-a7f9-bb3c844272dc','偈頌一百三十六首  其一九','釋惟一','宋','宋诗','song-poetry','','[]','無礙慧門，鐵壁鐵壁。',28,'全唐诗/poet.song.215000.json','["無礙慧門，鐵壁鐵壁。", "一擊擊開，不勞餘力。", "幾人把手拽不入。"]'),
('174c697c-0d7c-483e-90fb-c540a7ce7e3c','偈頌一百三十六首  其二○','釋惟一','宋','宋诗','song-poetry','','[]','橫一丈，豎一丈。',54,'全唐诗/poet.song.215000.json','["橫一丈，豎一丈。", "滿室風生，半窗月上。", "山僧要坐便坐，要起便起，終不向這裏無風起浪。", "諸人若不散去，照顧劈脊拄杖。"]'),
('d393a8a2-05fd-4b85-a03a-bbf501f0098c','偈頌一百三十六首  其二一','釋惟一','宋','宋诗','song-poetry','','[]','目視雲霄，有一拳未敢分付。',170,'全唐诗/poet.song.215000.json','["目視雲霄，有一拳未敢分付。", "日遊閙市，三十棒且待別時。", "遇坎則止，乘流而行。", "既無跡於去來，寧有心於動靜。", "昨日恁麽，逸翮獨翔，孤風絕侶。", "今日不恁麽，翫江月，聽松風。", "拈起閤皂山，濃蘸清江水。", "平展金鳳洲，寫出祖師意。", "貼向十字街頭，俾人人知道，一年十二月，臘月是年尾。", "寶祐改元，又從頭起。", "萬年萬年更萬年，清江依舊清無底。", "道泰不傳天子令，時清休唱太平歌。"]'),
('4a9829ef-44e5-4688-80fa-5502fa14993a','偈頌一百三十六首  其二二','釋惟一','宋','宋诗','song-poetry','','[]','不如隨分納些些，何處青山不是家。',32,'全唐诗/poet.song.215000.json','["不如隨分納些些，何處青山不是家。", "玉笛橫吹皇化裏，風前清韻徹天涯。"]'),
('39f0d322-72a7-497a-919c-ea1d6b3f7db7','偈頌一百三十六首  其二三','釋惟一','宋','宋诗','song-poetry','','[]','惠力大寶藏，日轉萬億匝。',64,'全唐诗/poet.song.215000.json','["惠力大寶藏，日轉萬億匝。", "一日萬億匝，千日千萬億。", "願以轉輪數，仰祝天子壽。", "惟願天子壽，復倍轉輪數。", "繁開玉葉茂金枝，永與法輪無盡時。"]'),
('1a2a8b4a-bd15-4502-ad93-d4095f7b5bf6','偈頌一百三十六首  其二四','釋惟一','宋','宋诗','song-poetry','','[]','翠柳堤邊舞，黄鶑樹上鳴。',32,'全唐诗/poet.song.215000.json','["翠柳堤邊舞，黄鶑樹上鳴。", "瞿曇真實相，歷歷在而今。", "誰言入滅向雙林。"]'),
('1b3942ac-78dc-48ee-99b5-de6f44a3d71a','偈頌一百三十六首  其二五','釋惟一','宋','宋诗','song-poetry','','[]','這箇老漢，殊無所解。',56,'全唐诗/poet.song.215000.json','["這箇老漢，殊無所解。", "不惟屈屈曲曲，且是頑頑頼頼。", "我昔沒興見之，直至而今尀耐。", "燒炷香，禮三拜。", "喫拳打拳，彼此莫怪。"]'),
('516aab83-3c84-47c5-a9e6-44c996e2793e','偈頌一百三十六首  其二六','釋惟一','宋','宋诗','song-poetry','','[]','今朝結制，號令宜先。',72,'全唐诗/poet.song.215000.json','["今朝結制，號令宜先。", "三章約法，普示人天。", "身不可妄動，亦不可塊然。", "口不可妄開，亦不可默然。", "意不可妄舉，亦不可罔然。", "依如是行如是住，圓覺伽藍常現前。"]'),
('3a3589c5-dbad-4450-a6cc-a0b9d86228ac','偈頌一百三十六首  其二七','釋惟一','宋','宋诗','song-poetry','','[]','獅子吼，無畏說，百獸聞之皆腦裂。',16,'全唐诗/poet.song.215000.json','["獅子吼，無畏說，百獸聞之皆腦裂。"]'),
('b189399b-0344-4ca2-b160-5cadb501a965','偈頌一百三十六首  其二八','釋惟一','宋','宋诗','song-poetry','','[]','晝也惺惺，夜也惺惺。',32,'全唐诗/poet.song.215000.json','["晝也惺惺，夜也惺惺。", "既不掉舉，亦不昏沉。", "何須求白玉，只此是黄金。"]'),
('9de0f491-4c13-4e55-96fd-68d1386109ad','偈頌一百三十六首  其二九','釋惟一','宋','宋诗','song-poetry','','[]','夏熱乘凉，冬寒向火。',49,'全唐诗/poet.song.215000.json','["夏熱乘凉，冬寒向火。", "自古自今，總恁麽過。", "不知二祖立雪齊腰，畢竟圖箇什麽。", "以吾之不可，學柳下惠之可。"]'),
('5eea6248-bb14-464f-8919-2f07d4e9b6e5','偈頌一百三十六首  其三○','釋惟一','宋','宋诗','song-poetry','','[]','無禪不參，無道可學。',48,'全唐诗/poet.song.215000.json','["無禪不參，無道可學。", "只責諸人如醉而醒，如夢而覺。", "醉既醒，夢既覺。", "雖然只是舊時人，却與舊時相遼邈。"]'),
('63bfea6f-9c34-444d-95c9-2c29ab1a3e26','偈頌一百三十六首  其三一','釋惟一','宋','宋诗','song-poetry','','[]','德山拆殿，寶峰燒香。',28,'全唐诗/poet.song.215000.json','["德山拆殿，寶峰燒香。", "二俱不惡，一種不臧。", "瞿曇元自面皮黄。"]'),
('9da89d0b-ee26-437b-b2c6-9dc37f8b15c7','偈頌一百三十六首  其三二','釋惟一','宋','宋诗','song-poetry','','[]','開門待知識，知識喜來過，兩兩不成雙，一一無回互。',76,'全唐诗/poet.song.215000.json','["開門待知識，知識喜來過，兩兩不成雙，一一無回互。", "共卧不共床，同行不同步。", "昭然在目前，目前不可覩。", "雖則不可覩，我獨知其故。", "聖容菩薩來西天，盧仙夏人在東土。"]'),
('57450ef7-b90d-400a-bd8c-43095cb640c7','偈頌一百三十六首  其三三','釋惟一','宋','宋诗','song-poetry','','[]','山前一片閑田地，無意求之却宛然。',32,'全唐诗/poet.song.215000.json','["山前一片閑田地，無意求之却宛然。", "幾許風光都買盡，不曾費著一文錢。"]'),
('f1b33fad-7733-495a-95a0-97b35288286c','偈頌一百三十六首  其三四','釋惟一','宋','宋诗','song-poetry','','[]','今朝解制，且作麽生。',36,'全唐诗/poet.song.215000.json','["今朝解制，且作麽生。", "從前約束，一槩放行。", "萬里秋天飛一鶚，東西南北任縱橫。"]'),
('20159131-cd72-46da-81fd-2d4884a74b65','偈頌一百三十六首  其三五','釋惟一','宋','宋诗','song-poetry','','[]','昨從天上去，元不離地下。',46,'全唐诗/poet.song.215000.json','["昨從天上去，元不離地下。", "今歸地下來，亦不離天上。", "上下無間，來去無差。", "天河秋一雁，砧杵夜千家。"]'),
('56da6daf-369e-40d9-89a0-4c0f93a892a8','偈頌一百三十六首  其三六','釋惟一','宋','宋诗','song-poetry','','[]','六年雪嶺竟無成，練得身形似鶴形。',48,'全唐诗/poet.song.215000.json','["六年雪嶺竟無成，練得身形似鶴形。", "盡謂見明星悟道，何曾悟道見明星。", "入山何富，出山何貧，知心能幾人。"]'),
('5ee14b94-e3cb-4273-89ef-d3c0aee055a2','偈頌一百三十六首  其三七','釋惟一','宋','宋诗','song-poetry','','[]','春風料峭，春雨連綿。',36,'全唐诗/poet.song.215000.json','["春風料峭，春雨連綿。", "桃花逐浪，新竹籠煙。", "香嚴已往靈雲去，一度春深一愴然。"]'),
('025d92a1-7e39-4329-b439-6c5635ef5c25','偈頌一百三十六首  其三八','釋惟一','宋','宋诗','song-poetry','','[]','這老凍儂，惺惺懵懂。',45,'全唐诗/poet.song.215000.json','["這老凍儂，惺惺懵懂。", "分明無一絲毫，剛道有三斤重。", "只知恁麽脫空相誑，不知其讎甚於戴天之不共。"]'),
('6ea59d96-59f5-4419-b9d4-7f14793ca13b','偈頌一百三十六首  其三九','釋惟一','宋','宋诗','song-poetry','','[]','去從閙市紅塵去，歸向白雲深處歸。',32,'全唐诗/poet.song.215000.json','["去從閙市紅塵去，歸向白雲深處歸。", "因甚更無迎與送，去來寸步不曾移。"]'),
('09c80c20-26bf-422b-a1a4-b04f43fc23cb','偈頌一百三十六首  其四○','釋惟一','宋','宋诗','song-poetry','','[]','細不可減，大無以加。',46,'全唐诗/poet.song.215000.json','["細不可減，大無以加。", "近在眼睫，遠過天涯。", "是著即錯，擬之又差。", "缺齒老胡會不得，空携隻履返流沙。"]'),
('ffc24bb0-16ea-43eb-a5d3-31bd0cfc17f1','偈頌一百三十六首  其四一','釋惟一','宋','宋诗','song-poetry','','[]','五五午時書，妖邪盡掃除。',48,'全唐诗/poet.song.215000.json','["五五午時書，妖邪盡掃除。", "一堂風悄悄，千古意如如。", "蒲飲先春雪，糭餐明月珠。", "舌頭如具眼，醉飽樂無餘。"]'),
('e83d8cd6-9bbb-4309-b01f-ab5476301e82','偈頌一百三十六首  其四二','釋惟一','宋','宋诗','song-poetry','','[]','一月在天，影含衆水。',60,'全唐诗/poet.song.215000.json','["一月在天，影含衆水。", "只如雙劍峰頭月，何似芙蓉溪上月。", "芙蓉溪上月，何似泐潭潭底月。", "若道同，東西各一涯，若道別，天無第二月。"]'),
('669e740f-1bd2-4386-ba7e-4a00bb77f8e8','偈頌一百三十六首  其四三','釋惟一','宋','宋诗','song-poetry','','[]','白雲巖上月，太平松下影。',24,'全唐诗/poet.song.215000.json','["白雲巖上月，太平松下影。", "深夜秋風生，都成一片境。"]'),
('0a6e33dc-d1fa-489b-954f-5ef6e9f45490','偈頌一百三十六首  其四四','釋惟一','宋','宋诗','song-poetry','','[]','雨暗西山，雲飛南浦。',48,'全唐诗/poet.song.216000.json','["雨暗西山，雲飛南浦。", "老盧仙腰纏騎鶴，朝度黄茅八凸。", "獨秀峰草木泉石爲之鼓舞。", "因甚如此，家貧願隣富。"]'),
('9429e8c6-7299-4ef5-88bf-51524ec16982','偈頌一百三十六首  其四五','釋惟一','宋','宋诗','song-poetry','','[]','瞿曇未解這一著，雪嶺六年空卜度。',58,'全唐诗/poet.song.216000.json','["瞿曇未解這一著，雪嶺六年空卜度。", "不知眼病見空花，認作明星一何錯。", "自累猶可，更累兒孫。", "珊瑚枕上兩行淚，半是思君半恨君。"]'),
('cd8ee5b5-2aec-426c-ba84-883d8e10de1d','偈頌一百三十六首  其四六','釋惟一','宋','宋诗','song-poetry','','[]','歲盡年窮，多少人脚忙手亂，惟有寶峰恬然不管。',38,'全唐诗/poet.song.216000.json','["歲盡年窮，多少人脚忙手亂，惟有寶峰恬然不管。", "來年更有新條在，惱亂春風卒未休。"]'),
('bb1f6f97-0e72-4413-b9aa-81d0faa33e59','偈頌一百三十六首  其四七','釋惟一','宋','宋诗','song-poetry','','[]','我與黄面老漢，有千古不忘之恨，甚欲爛槌一頓。',37,'全唐诗/poet.song.216000.json','["我與黄面老漢，有千古不忘之恨，甚欲爛槌一頓。", "今日因甚放過，老不以筋力爲能。"]'),
('d724462e-34ea-4731-9def-33c769d7ea95','偈頌一百三十六首  其四八','釋惟一','宋','宋诗','song-poetry','','[]','踞此室，坐此座。',18,'全唐诗/poet.song.216000.json','["踞此室，坐此座。", "佛來祖來，一一按過。"]'),
('7712c2c6-19b3-478b-aade-1cc141d64b08','偈頌一百三十六首  其四九','釋惟一','宋','宋诗','song-poetry','','[]','諸人不是不將來，老僧不是不分付。',30,'全唐诗/poet.song.216000.json','["諸人不是不將來，老僧不是不分付。", "將來既是分明，分付亦非莽鹵。"]'),
('a101ad13-d77e-4b84-a546-ac2f5bb3b445','偈頌一百三十六首  其五○','釋惟一','宋','宋诗','song-poetry','','[]','雨注河傾，共談無義。',40,'全唐诗/poet.song.216000.json','["雨注河傾，共談無義。", "陳蒲鞋倒退三千，睡虎子讓一頭地。", "有問如何若何，不能以手夾鼻。"]'),
('e6fdd41e-84f9-478f-8471-7f4f7b10fec5','偈頌一百三十六首  其五一','釋惟一','宋','宋诗','song-poetry','','[]','涅槃心，差別智。',56,'全唐诗/poet.song.216000.json','["涅槃心，差別智。", "明之既難，會之不易。", "如千手異執千目異顧元同一身，似萬派爭流百川競注皆歸一水。", "差之毫釐，謬以千里。"]'),
('cdb59e66-42b8-4669-b8ce-5a73591cebc7','偈頌一百三十六首  其五二','釋惟一','宋','宋诗','song-poetry','','[]','古佛心，即如今。',46,'全唐诗/poet.song.216000.json','["古佛心，即如今。", "桂香滿院，葉墜疏林。", "水沉寒雁影，露冷夜蛩吟。", "明眼衲僧會不得，江北江南徒訪尋。"]'),
('d5268b9b-1914-4928-8b43-52daaf5491eb','偈頌一百三十六首  其五三','釋惟一','宋','宋诗','song-poetry','','[]','今日如是，明日如是。',60,'全唐诗/poet.song.216000.json','["今日如是，明日如是。", "一日復一日，一年復一年。", "百千萬億年，究竟只如是。", "月落烏啼霜滿天，紛紛黄葉飄庭際。", "善男子起，法性如是。"]'),
('40f0664c-f74d-4806-8167-eb317331f23d','偈頌一百三十六首  其五四','釋惟一','宋','宋诗','song-poetry','','[]','照而常寂，寂而常照。',36,'全唐诗/poet.song.216000.json','["照而常寂，寂而常照。", "灧澦雲開，玲瓏月皎。", "巍巍玉殿與瓊樓，已見翬飛拄杖頭。"]'),
('cb546eba-afc9-4e18-a490-3a306122dfcc','偈頌一百三十六首  其五五','釋惟一','宋','宋诗','song-poetry','','[]','人間月半，天上月圓。',60,'全唐诗/poet.song.216000.json','["人間月半，天上月圓。", "幸自一天明朗，何須萬斛金蓮。", "諸人睡眼豁開見得分曉，不起于座即超于然燈之前。", "其或未然，燈節元來是上元。"]'),
('98336fae-05b0-49d1-a00f-861b1ac29540','偈頌一百三十六首  其五六','釋惟一','宋','宋诗','song-poetry','','[]','風蕭蕭，雨蕭蕭。',71,'全唐诗/poet.song.216000.json','["風蕭蕭，雨蕭蕭。", "山雲漠漠，庭葉飄飄。", "普天匝地，祖意活鱍鱍。", "滿眼滿耳，心印何昭昭。", "便與麽去，衲僧門下，大故相遼。", "行到水窮山盡處，可中別有路通霄。"]'),
('2af2e68c-c055-4cc7-a02a-ccede9c325f6','偈頌一百三十六首  其五七','釋惟一','宋','宋诗','song-poetry','','[]','佛來不顧，祖來不顧。',26,'全唐诗/poet.song.216000.json','["佛來不顧，祖來不顧。", "有三十棒，未敢分付。", "箇中無肯路。"]'),
('b76f0705-c6dc-490b-b16e-9c5cc26a14a4','偈頌一百三十六首  其五八','釋惟一','宋','宋诗','song-poetry','','[]','一著高一著，一步闊一步，墮在平常。',60,'全唐诗/poet.song.216000.json','["一著高一著，一步闊一步，墮在平常。", "一著亞一著，一步却一步，失在巇嶮。", "二俱不涉，七達八通。", "龍袖拂開全體現，象王行處絕狐蹤。"]'),
('c57a6dc8-5154-4e64-bc0c-e5f6757c64f2','偈頌一百三十六首  其五九','釋惟一','宋','宋诗','song-poetry','','[]','經誦三千部，曹溪一句忘。',48,'全唐诗/poet.song.216000.json','["經誦三千部，曹溪一句忘。", "塵塵皆寶所，處處是家鄉。", "雲浄天如洗，潭清月愈光。", "須知遠煙浪，別有好商量。"]'),
('9aba6777-24a9-4aa9-a454-3043b39632e9','偈頌一百三十六首  其六○','釋惟一','宋','宋诗','song-poetry','','[]','直下是，直下是。',38,'全唐诗/poet.song.216000.json','["直下是，直下是。", "這邊那邊，滿眼滿耳。", "綿綿兮長存，湛湛兮不痕，擬議依前隔海門。"]'),
('9260627f-306a-4658-a1e1-d08dec13b137','偈頌一百三十六首  其六一','釋惟一','宋','宋诗','song-poetry','','[]','雨滴空階，溪流新漲。',50,'全唐诗/poet.song.216000.json','["雨滴空階，溪流新漲。", "風起天末，葉墜疏林。", "喚作物却非物，喚作心不是心。", "缺齒老胡會不得，九年面壁空沉吟。"]'),
('45ca7ba3-23fc-464b-b780-4488804b840b','偈頌一百三十六首  其六二','釋惟一','宋','宋诗','song-poetry','','[]','摩訶衍法，離四句絕百非。',39,'全唐诗/poet.song.216000.json','["摩訶衍法，離四句絕百非。", "香飯普熏，遍十方窮三際。", "我此一衆，總是諸方羅籠不住底。"]'),
('8c029f68-4a81-401a-b9c3-8a6cce3c2b3e','偈頌一百三十六首  其六三','釋惟一','宋','宋诗','song-poetry','','[]','名不得，狀不得。',40,'全唐诗/poet.song.216000.json','["名不得，狀不得。", "取不得，舍不得。", "不可得，只麽得。", "趙州東壁掛葫蘆，觀音院裏有彌勒。"]'),
('5234afc4-7dcb-4e73-bf48-6d46c2fd5e94','偈頌一百三十六首  其六四','釋惟一','宋','宋诗','song-poetry','','[]','百丈開田說大義，究竟寧免費脚手。',58,'全唐诗/poet.song.216000.json','["百丈開田說大義，究竟寧免費脚手。", "松溪修田無可說，擊皷陞堂但良久。", "知事頭首俱歡顔，見者聞者皆失笑。", "好篇大義，一字不少。"]'),
('fa807342-82d3-4b91-a41e-28a9dfbd1be0','偈頌一百三十六首  其六五','釋惟一','宋','宋诗','song-poetry','','[]','諸佛不出世，亦無有涅槃。',40,'全唐诗/poet.song.216000.json','["諸佛不出世，亦無有涅槃。", "年年二月半，枉自銜悲酸。", "此意只今誰共委，令人拍碎玉欄干。"]'),
('fddb8fae-1ea6-49e3-a3aa-6916f07ab2c7','偈頌一百三十六首  其六六','釋惟一','宋','宋诗','song-poetry','','[]','此事沒誵訛，人人不柰何。',38,'全唐诗/poet.song.216000.json','["此事沒誵訛，人人不柰何。", "柰何不得處，合眼跳黄河。", "跳得後如何，元來佛法苦無多。"]'),
('46e030a8-cb55-4b05-90ae-52bc62ecb1f4','偈頌一百三十六首  其六七','釋惟一','宋','宋诗','song-poetry','','[]','今朝結制，制如何結。',30,'全唐诗/poet.song.216000.json','["今朝結制，制如何結。", "內不放出，外不放入。", "壁立千仞，千仞壁立。"]'),
('7010c7dd-fa33-40cf-a3e3-98caf5d1d67c','偈頌一百三十六首  其六八','釋惟一','宋','宋诗','song-poetry','','[]','宗通說通，抹過西東。',30,'全唐诗/poet.song.216000.json','["宗通說通，抹過西東。", "無兩舌頭，有雙箭鋒。", "因甚如此，閩蜀同風。"]'),
('3b12f93d-2185-40c5-a9e9-2686a9ab7b8e','偈頌一百三十六首  其六九','釋惟一','宋','宋诗','song-poetry','','[]','德山推倒，雲門打殺。',20,'全唐诗/poet.song.216000.json','["德山推倒，雲門打殺。", "黄蘗燒香，殷人以柏。"]'),
('3ca6ff43-fc97-4329-8438-b5c9e81c606c','偈頌一百三十六首  其七○','釋惟一','宋','宋诗','song-poetry','','[]','這裡如大火聚，近之則燎却面門。',29,'全唐诗/poet.song.216000.json','["這裡如大火聚，近之則燎却面門。", "直饒佛祖到來，未免退身有分。"]'),
('c46ed167-cf16-45f5-a513-3a8fb6a9d1b0','偈頌一百三十六首  其七一','釋惟一','宋','宋诗','song-poetry','','[]','春雪乍晴，春光愈好。',30,'全唐诗/poet.song.216000.json','["春雪乍晴，春光愈好。", "不必遠討幽探，不用談空說有。", "村村自花柳。"]'),
('d1cc532e-5da3-485d-a40c-a8c40440ff22','偈頌一百三十六首  其七二','釋惟一','宋','宋诗','song-poetry','','[]','心不是佛，智不是道。',38,'全唐诗/poet.song.216000.json','["心不是佛，智不是道。", "拋却深村，又入荒草。", "只如以一重去一重，不知轉交涉轉料掉。"]'),
('32b101ee-ee86-413b-a824-070afd71e019','偈頌一百三十六首  其七三','釋惟一','宋','宋诗','song-poetry','','[]','一明一切明，一了一切了。',40,'全唐诗/poet.song.216000.json','["一明一切明，一了一切了。", "道無不是無，道有元非有。", "毗婆尸佛早留心，直至如今不得妙。"]'),
('eb3315cd-8740-4b5d-ad8c-15aab2753917','偈頌一百三十六首  其七四','釋惟一','宋','宋诗','song-poetry','','[]','含笑吟吟，懷毒深深。',54,'全唐诗/poet.song.216000.json','["含笑吟吟，懷毒深深。", "左搓芒繩生縛鬼子，倒拈蝎尾殃害平人。", "我雖蹉脚跨他門，幸不遭他毒氣熏。", "如何見得，只此爲憑。"]'),
('b877a3f5-8c61-46af-bd97-10b84c2915ac','偈頌一百三十六首  其七五','釋惟一','宋','宋诗','song-poetry','','[]','摩耶昔産一塊鐵，無可名之名悉達。',51,'全唐诗/poet.song.216000.json','["摩耶昔産一塊鐵，無可名之名悉達。", "擬鑄金軀鑄不成，無端鑄成一大錯。", "錯錯，至今累我東土人，年年轉洗轉埃塵。"]'),
('521856f5-0b15-4c1e-a376-b53d77f6cff1','偈頌一百三十六首  其七六','釋惟一','宋','宋诗','song-poetry','','[]','一結一切結，一解一切解。',42,'全唐诗/poet.song.216000.json','["一結一切結，一解一切解。", "結解兩忘，通身瀟灑。", "絕瀟灑，脫羅籠。", "巨魚縱大壑，一雁入高空。"]'),
('950fdc1c-c41b-4859-a0d2-d5b88227c3aa','偈頌一百三十六首  其七七','釋惟一','宋','宋诗','song-poetry','','[]','意句俱到，不入深村入荒草。',53,'全唐诗/poet.song.216000.json','["意句俱到，不入深村入荒草。", "意句不到，珊瑚樹林日杲杲。", "只如一言道盡，意況不及時如何。", "到江吳地盡，隔岸越山多。"]'),
('19184a7f-c55b-453a-8431-1a73529385e9','偈頌一百三十六首  其七八','釋惟一','宋','宋诗','song-poetry','','[]','三玄三要，五位君臣。',54,'全唐诗/poet.song.216000.json','["三玄三要，五位君臣。", "說偏說正，分主分賓。", "未免重添眼裏塵。", "盡情劃斷，空闊無垠。", "孤鴻杳杳知何處，門外蕭蕭落葉頻。"]'),
('d6789aa5-6d41-4adf-b6b8-8d002b8d23d7','偈頌一百三十六首  其七九','釋惟一','宋','宋诗','song-poetry','','[]','雅愛中秋月，多情似故人。',48,'全唐诗/poet.song.216000.json','["雅愛中秋月，多情似故人。", "在天何皎皎，照我更頻頻。", "圓影隨流水，清光絕點塵。", "孤高攀不及，覿面最相親。"]'),
('63cfaf14-e356-4c15-924d-21bbf0efc287','偈頌一百三十六首  其八○','釋惟一','宋','宋诗','song-poetry','','[]','九秋强半，不寒不暖。',34,'全唐诗/poet.song.216000.json','["九秋强半，不寒不暖。", "風細細雨霏霏，水冷冷雲淡淡。", "一棹烟波，蘆花兩岸。"]'),
('3855f07d-b6ca-4a47-ba2d-33872b007353','偈頌一百三十六首  其八一','釋惟一','宋','宋诗','song-poetry','','[]','六年雪嶺幾番雪，不是今番徹骨寒。',53,'全唐诗/poet.song.216000.json','["六年雪嶺幾番雪，不是今番徹骨寒。", "半夜三更禁不得，無端北斗面南看。", "瞿曇瞿曇，開得眼來天大曉，不知紅日已三竿。"]'),
('48766b9e-7338-4de5-8788-82d3cc218fbf','偈頌一百三十六首  其八二','釋惟一','宋','宋诗','song-poetry','','[]','琢雪雕冰，攢花簇錦。',40,'全唐诗/poet.song.216000.json','["琢雪雕冰，攢花簇錦。", "鄰義昭昭，友義烱烱。", "扶人上樹，推人下井。", "劫石可消，此恨難殞。"]'),
('ec9d0a72-f7b9-4f0e-8e54-ff8183c53349','偈頌一百三十六首  其八三','釋惟一','宋','宋诗','song-poetry','','[]','六月中夏，諸方放假。',60,'全唐诗/poet.song.216000.json','["六月中夏，諸方放假。", "大仰不然，繩頭緊把。", "常住百無一有不能掛懷，只憂兄弟不會狗子無佛性話。", "常啼菩薩賣心肝，風前狼籍誰人買。"]'),
('c4dcdc12-0175-4800-810e-55a2e36e40f8','偈頌一百三十六首  其八四','釋惟一','宋','宋诗','song-poetry','','[]','赤肉團上，有一無位真人。',75,'全唐诗/poet.song.216000.json','["赤肉團上，有一無位真人。", "眼裡耳裏，鼻裡口裡，頻頻出入，出入頻頻。", "能言能喚，能屈能伸。", "能好能惡，能喜能嗔。", "諸人若也未曾證據，便請證據，集雲今日爲汝保任。"]'),
('17d6483f-7ef4-44a5-b187-8cd887c323ef','偈頌一百三十六首  其八五','釋惟一','宋','宋诗','song-poetry','','[]','寶劍出匣，精金躍冶。',56,'全唐诗/poet.song.216000.json','["寶劍出匣，精金躍冶。", "色澤星輝，光芒斗射。", "投之重津而光愈發越，加之烈火而色無少假。", "行爲人間報不平，定應索起遼天價。"]'),
('0b3cd91c-3b76-4db9-b99f-1652c1935d6c','偈頌一百三十六首  其八六','釋惟一','宋','宋诗','song-poetry','','[]','雁入高空，蛩吟古砌。',46,'全唐诗/poet.song.216000.json','["雁入高空，蛩吟古砌。", "劇談不二門，單明第一義。", "瞎却眼，塞却耳。", "聽得分明見得親，不必龍華親授記。"]'),
('3910dbd0-289e-4455-b076-4db081cb0d56','偈頌一百三十六首  其八七','釋惟一','宋','宋诗','song-poetry','','[]','談玄談妙，將油洗皂。',46,'全唐诗/poet.song.216000.json','["談玄談妙，將油洗皂。", "行棒行喝，剜肉成瘡。", "諸方多是誇張作說，集雲只據見定商量。", "年年九日是重陽。"]'),
('ade09df9-4bbb-4766-a077-8e4506f24815','偈頌一百三十六首  其八八','釋惟一','宋','宋诗','song-poetry','','[]','今朝臘月二十五，明朝臘月二十六。',32,'全唐诗/poet.song.216000.json','["今朝臘月二十五，明朝臘月二十六。", "風前唱起仰山歌，人皆道是雲門曲。"]'),
('dee9636a-b2fc-4a8f-bcfa-78715758a6b3','偈頌一百三十六首  其八九','釋惟一','宋','宋诗','song-poetry','','[]','元正啟祚，萬物咸新。',77,'全唐诗/poet.song.216000.json','["元正啟祚，萬物咸新。", "覓一毫舊相，了不可得，千年桃核裡，元是舊時仁。", "覓一毫新相，了不可得，新舊之相既不可得，不可得亦不可得。", "道泰時清萬國寧，咸淳二年正月一。"]'),
('8a9ae461-3bee-4f04-98d3-d456cdaa01c3','偈頌一百三十六首  其九○','釋惟一','宋','宋诗','song-poetry','','[]','飛雪亭前，宜春臺上。',91,'全唐诗/poet.song.216000.json','["飛雪亭前，宜春臺上。", "物有萬殊，春無兩樣。", "住不顧去底，猶欠劈面拳。", "去不顧住底，好與攔腮掌。", "直饒去住兩忘，如龍似象。", "未免卸下衲衣，連揮痛棒。", "棒折也不放，是罰是賞。", "爲人須爲徹，殺人須見血。"]'),
('cf79ff19-4484-408b-b3aa-9e8eb219a756','偈頌一百三十六首  其九一','釋惟一','宋','宋诗','song-poetry','','[]','仰山上元令節，笙歌且靠一壁。',58,'全唐诗/poet.song.216000.json','["仰山上元令節，笙歌且靠一壁。", "雪晴山色挼藍，凍解溪流瀨石。", "滿眼看不盡，滿耳聽不徹。", "諸人若向這裏知歸，不須更授然燈記別。"]'),
('7eeb14c8-afff-48b3-be0d-f4a725182ea5','偈頌一百三十六首  其九二','釋惟一','宋','宋诗','song-poetry','','[]','佛滅二千有餘載，五逆兒孫渾不採。',32,'全唐诗/poet.song.216000.json','["佛滅二千有餘載，五逆兒孫渾不採。", "一夜雷轟雨霶霈，諸天亦爲之尀耐。"]'),
('2ab61752-2bcb-4f13-bf9e-6eb13db6e6b5','偈頌一百三十六首  其九三','釋惟一','宋','宋诗','song-poetry','','[]','八月秋，何處熱。',54,'全唐诗/poet.song.216000.json','["八月秋，何處熱。", "稻花吹香，疏林減葉。", "三點五點不時雨，一聲兩聲何處笛。", "若向這裏，聞無有聞，證入圓通，斯爲第一。"]'),
('74e0b00a-e7fb-4ff7-b532-bb5a386db452','偈頌一百三十六首  其九四','釋惟一','宋','宋诗','song-poetry','','[]','吾心似秋月，秋月似吾心。',48,'全唐诗/poet.song.216000.json','["吾心似秋月，秋月似吾心。", "雙照纖塵浄，俱清萬籟沉。", "十分明又白，一樣古猶今。", "不是寒山子，何人解此吟。"]'),
('983f02ac-98dc-49d8-b731-988abb81b517','偈頌一百三十六首  其九五','釋惟一','宋','宋诗','song-poetry','','[]','九月授衣，無衣可受。',52,'全唐诗/poet.song.216000.json','["九月授衣，無衣可受。", "衲僧門下，別有要妙。", "新糊紙被烘來暖，一覺和衣到五更。", "聞得上方鐘皷動，又添一日在浮生。"]'),
('25ef48a9-8ad5-4363-b75a-6c6eb3a8fb3a','偈頌一百三十六首  其九六','釋惟一','宋','宋诗','song-poetry','','[]','秋雨乍晴，秋天如洗。',48,'全唐诗/poet.song.216000.json','["秋雨乍晴，秋天如洗。", "九日菊花新，千林黄葉墜。", "人人只知驟步登高，往往蹉過自家穩密田地。", "切忌，切忌。"]'),
('487cedb0-1bf1-4151-af1b-c0bad3ca672d','偈頌一百三十六首  其九七','釋惟一','宋','宋诗','song-poetry','','[]','萬法本無，一心何有。',51,'全唐诗/poet.song.216000.json','["萬法本無，一心何有。", "絕慮忘緣，默默自守。", "儻能朝於斯夕於斯，自然虛而靈空而妙。", "正當恁麽時，我手何似佛手。"]'),
('a4fb9bd9-b3b7-46d3-8533-eed52f1154b0','偈頌一百三十六首  其九八','釋惟一','宋','宋诗','song-poetry','','[]','集雲不會禪，不會道。',58,'全唐诗/poet.song.216000.json','["集雲不會禪，不會道。", "橫畫不識，豎畫不曉。", "日裡三餐，夜後一覺。", "年來老且病，轉見不唧𠺕。", "裙子褊衫箇也無，袈裟形相些些有。"]'),
('9d600343-3930-47d4-973e-340186db67ad','偈頌一百三十六首  其九九','釋惟一','宋','宋诗','song-poetry','','[]','四葉紅蓮，一音宣演。',99,'全唐诗/poet.song.216000.json','["四葉紅蓮，一音宣演。", "其語巧妙，其義深遠。", "前印威音，一點不差，後證彌勒，不差一點。", "離四句，絕百非，即不無。", "只如一人恁麽，一人不恁麽，一人恁麽中不恁麽，一人不恁麽中却恁麽，又且如何。", "造作不同，一般米麫。"]'),
('ed17896f-7be1-453d-bfea-1a9a749e8b07','偈頌一百三十六首  其一○○','釋惟一','宋','宋诗','song-poetry','','[]','衲僧家，無本據。',52,'全唐诗/poet.song.216000.json','["衲僧家，無本據。", "鑑在機先，妙在轉處。", "問漚堂上半座平分，集雲峰前孤風絕侶。", "看看九萬摶扶摇，垂天之翅摩雲霄。"]'),
('1fbae90b-bdef-4913-8a57-f9ab8cf3dfcd','偈頌一百三十六首  其一○一','釋惟一','宋','宋诗','song-poetry','','[]','初二出城，歸來初五。',79,'全唐诗/poet.song.216000.json','["初二出城，歸來初五。", "十字街頭撞見張三，元是山前舊時李四。", "面目如前，語言如故。", "再三道佛法澆漓，衆生難度。", "不必按牛頭喫草，不用將針合成斧。", "甜瓜徹蒂甜，苦瓠連根苦。"]'),
('c8dc89cc-1860-44d6-a372-15a8f764d7db','偈頌一百三十六首  其一○二','釋惟一','宋','宋诗','song-poetry','','[]','二月初五，群花競吐。',62,'全唐诗/poet.song.216000.json','["二月初五，群花競吐。", "或逞夭紅，或誇雅素。", "月下精神，風前態度，明明祖意無回互。", "堪悲堪笑老靈雲，錯認桃花作眼睛，至今猶自不惺惺。"]'),
('06179aee-3356-4663-8978-3cf87bf8ddc7','偈頌一百三十六首  其一○三','釋惟一','宋','宋诗','song-poetry','','[]','薰風南來，凉生殿閣。',55,'全唐诗/poet.song.216000.json','["薰風南來，凉生殿閣。", "諸佛出身處，昭昭在心目。", "當機覿面回避無門，只要諸人披襟領略。", "其或未然，開眼也著，合眼也著。"]'),
('4223c8b2-a070-496b-9d67-cc7b8d76e461','偈頌一百三十六首  其一○四','釋惟一','宋','宋诗','song-poetry','','[]','一月復一月，此月又過五。',54,'全唐诗/poet.song.216000.json','["一月復一月，此月又過五。", "兩輪日月何奔忙，百年彈指如虛度。", "物不遷，還知否。", "不是佛，亦非祖。", "流水不腐，戶樞不蠹。"]'),
('69bfecea-f207-47d9-aa70-a727f55de84b','偈頌一百三十六首  其一○五','釋惟一','宋','宋诗','song-poetry','','[]','入理深談，語非語，默非默。',72,'全唐诗/poet.song.216000.json','["入理深談，語非語，默非默。", "量材補職，武是武，文是文。", "用舍臨時，剸裁在我。", "只如將丈六金身作一莖草用，將一莖草作丈六金身用。", "寰中天子勑，塞外將軍令。"]'),
('1304c02e-6f01-49c3-a5ab-4d0ad1b228a0','偈頌一百三十六首  其一○六','釋惟一','宋','宋诗','song-poetry','','[]','我心似秋月，道似又還別。',80,'全唐诗/poet.song.216000.json','["我心似秋月，道似又還別。", "秋月有虧盈，吾心無損益。", "人人只知登樓賞翫向天邊覓，殊不知自己衣單下有箇光明藏子十分圓滿十分皎潔。", "信得及，見得徹。", "非惟一夕歡，千古可怡悅。"]'),
('91c7735e-5e7c-42a4-b65f-1991d58f7d01','偈頌一百三十六首  其一○七','釋惟一','宋','宋诗','song-poetry','','[]','不思善，不思惡。',46,'全唐诗/poet.song.216000.json','["不思善，不思惡。", "孤迥迥，活鱍鱍。", "不用追尋，不勞捉摸，只貴諸人知著落。", "知著落，楊岐馿子三隻脚。"]'),
('39c78c31-d450-4c13-98a8-af56b8c4ee99','偈頌一百三十六首  其一○八','釋惟一','宋','宋诗','song-poetry','','[]','楊岐栗棘蓬，吞著礙喉嚨。',63,'全唐诗/poet.song.216000.json','["楊岐栗棘蓬，吞著礙喉嚨。", "東山鐵餕餡，渾崙苦磝磝。", "諸人若要省力，不如參一箇平實。", "楚王渡江得萍實。", "大如斗，赤如日，剖而食之甜如蜜。"]'),
('cbdb3ef5-2b9a-4685-8c89-6975efe87d2e','偈頌一百三十六首  其一○九','釋惟一','宋','宋诗','song-poetry','','[]','人人頭頂天，脚踏地，眼裏放光，鼻孔出氣，與他諸佛諸祖無別無異。',75,'全唐诗/poet.song.216000.json','["人人頭頂天，脚踏地，眼裏放光，鼻孔出氣，與他諸佛諸祖無別無異。", "因甚握節當胸，聽我謾你。", "莫有不被謾□麽，我且問你，雞寒上樹，鴨寒下水，畢竟是祖意是教意。"]'),
('9de69a5c-848d-4991-83aa-1c4d955e5de6','偈頌一百三十六首  其一一○','釋惟一','宋','宋诗','song-poetry','','[]','昔日不生，今日不滅。',62,'全唐诗/poet.song.216000.json','["昔日不生，今日不滅。", "出入飛鳶嶺，未曾有出入。", "洞山不曾到，投子不相識。", "若道嗣德山，未免自屈抑。", "象骨巍巍摩碧空，寒泉皎皎浸明月。"]'),
('98c495a5-76cf-40ce-ba0b-dc41f6277877','偈頌一百三十六首  其一一一','釋惟一','宋','宋诗','song-poetry','','[]','節屆中秋，凉飈四起。',48,'全唐诗/poet.song.216000.json','["節屆中秋，凉飈四起。", "萬里無雲，一天如洗。", "明皎皎月上孤峰，香拂拂桂飄庭際。", "以我爲隠乎，吾無隠乎爾。"]'),
('425f976c-df91-4a2c-abd4-ecf46d7aa553','偈頌一百三十六首  其一一二','釋惟一','宋','宋诗','song-poetry','','[]','三十年前，無交涉處有交涉。',44,'全唐诗/poet.song.216000.json','["三十年前，無交涉處有交涉。", "三十年後，有交涉處無交涉。", "須無交涉，飲恨難忘，含悲含笑一爐香。"]'),
('9a8a0a7c-8fde-44c3-a450-a6f6d0ba7372','偈頌一百三十六首  其一一三','釋惟一','宋','宋诗','song-poetry','','[]','綠水青山，紅塵閙市。',43,'全唐诗/poet.song.216000.json','["綠水青山，紅塵閙市。", "一大藏教，滿眼滿耳。", "這裏有人揀辨得出，入則箇箇歸元，出則無無不是。"]'),
('287e9e5d-a5f1-4707-a02e-7f4b6ff84afc','偈頌一百三十六首  其一一四','釋惟一','宋','宋诗','song-poetry','','[]','辛未元正有則語，大地無人知落處。',42,'全唐诗/poet.song.216000.json','["辛未元正有則語，大地無人知落處。", "屋角山禽破曉啼，爲人一一從頭舉。", "歲旦無風，甲子不雨。"]'),
('afbf3469-8816-4a84-9769-21f173a1c9b8','偈頌一百三十六首  其一一五','釋惟一','宋','宋诗','song-poetry','','[]','自夏及秋，頻頻出入。',63,'全唐诗/poet.song.216000.json','["自夏及秋，頻頻出入。", "送舊迎新，奔馳不歇。", "十字街頭忽喫攧，起來拾得胡餠隻。", "今日不辭舉似諸人，團團圓圓，皎皎潔潔，十成脫似中秋月。"]'),
('d0c41187-1fb4-4984-bc4f-92bfd5002320','偈頌一百三十六首  其一一六','釋惟一','宋','宋诗','song-poetry','','[]','一年十二月，是臘月年尾。',51,'全唐诗/poet.song.216000.json','["一年十二月，是臘月年尾。", "臘月三十日，過了三之二。", "雪峰晝裏夜裏，波波挈挈，手不釋杓，脚不離地，理會甚底。"]'),
('d669abfd-5256-47fb-b032-a2170e86c6f6','偈頌一百三十六首  其一一七','釋惟一','宋','宋诗','song-poetry','','[]','衲僧行處，孤風凜然。',42,'全唐诗/poet.song.216000.json','["衲僧行處，孤風凜然。", "動無妄動，言無妄言。", "如履薄冰，如臨深淵。", "不須明祖意，只此是單傳。"]'),
('9bec89a9-2234-4330-9bef-2c83ab5d8a1f','偈頌一百三十六首  其一一八','釋惟一','宋','宋诗','song-poetry','','[]','馬師一喝大雄峰，直得三日雙耳聾。',76,'全唐诗/poet.song.216000.json','["馬師一喝大雄峰，直得三日雙耳聾。", "今日松山聾更甚，半年不復聞鼓鍾。", "依俙鈍鐵，彷彿頑銅。", "只好投之火聚中，火餘烜爀地通紅。", "幾多錯認，鳥啼月落，煜煜曉星明向東。"]'),
('420a9523-2514-4693-8d47-e908ed9a5b87','偈頌一百三十六首  其一一九','釋惟一','宋','宋诗','song-poetry','','[]','天門一合，十方無路。',27,'全唐诗/poet.song.216000.json','["天門一合，十方無路。", "似海之深，如山之固。", "如何造入，步。"]'),
('7d4d2f95-044e-46e9-a72a-df1702df7240','偈頌一百三十六首  其一二○','釋惟一','宋','宋诗','song-poetry','','[]','函蓋乾坤句，隨波逐浪句，截斷衆流句，三句盡在此。',44,'全唐诗/poet.song.216000.json','["函蓋乾坤句，隨波逐浪句，截斷衆流句，三句盡在此。", "不多一字，不少一字。", "衆眼難瞞，分明舉似。"]'),
('87e7691c-68d4-47e3-af9f-a209e064144a','偈頌一百三十六首  其一二一','釋惟一','宋','宋诗','song-poetry','','[]','舊時日月，舊日山川。',54,'全唐诗/poet.song.216000.json','["舊時日月，舊日山川。", "東西不易，南北不遷。", "水雲雜沓，龍象駢闐，古佛家風尚儼然。", "雨過千林開翠幄，月臨雙沼浸銀蟾。"]'),
('0a8eeea2-8e5c-4e22-ae32-180757196512','偈頌一百三十六首  其一二二','釋惟一','宋','宋诗','song-poetry','','[]','走盡四天下，只在一塵中。',67,'全唐诗/poet.song.216000.json','["走盡四天下，只在一塵中。", "不離一塵中，周遍四天下。", "不是神通，亦非力假。", "有人知得著落，許你入妙喜世界，是不動如來。", "其或未然，一任鑽龜打瓦。"]'),
('0b318729-bf72-4a0e-8027-cde5ec857855','偈頌一百三十六首  其一二三','釋惟一','宋','宋诗','song-poetry','','[]','休去歇去，玲瓏巖上落花雨。',62,'全唐诗/poet.song.216000.json','["休去歇去，玲瓏巖上落花雨。", "消焉息焉，路入清關別有天。", "塵不到，暑不到，行亦禪，坐亦禪，高蹈威音未朕前。", "喫粥喫飯過，聽風聽雨眠。"]'),
('5c45ae7b-8056-43c5-88fa-7f74778e3266','偈頌一百三十六首  其一二四','釋惟一','宋','宋诗','song-poetry','','[]','鼓報四更，地摇六震。',62,'全唐诗/poet.song.216000.json','["鼓報四更，地摇六震。", "火焰爲三世諸佛說法，三世諸佛立地聽。", "虛空有盡，大道無窮。", "窮則變，變則通。", "信手拈將莖草插，瓊樓玉殿凌蒼穹。"]'),
('24c8082e-d8fc-47d8-90ec-a344e78f21e2','偈頌一百三十六首  其一二五','釋惟一','宋','宋诗','song-poetry','','[]','仲春漸暖，是處花開。',74,'全唐诗/poet.song.216000.json','["仲春漸暖，是處花開。", "夭桃烘日暈生臉，紅杏吟風笑滿腮。", "是今彌勒，是古如來，一一分身不用猜。", "有人一見便見，敢保老兄未徹。", "即色即聲求不可，離聲離色覓猶乖。"]'),
('61d7d429-fbc4-4b2a-b842-aa0b39c2fe33','偈頌一百三十六首  其一二六','釋惟一','宋','宋诗','song-poetry','','[]','去時元只空雙手，歸日依前雙手空。',42,'全唐诗/poet.song.216000.json','["去時元只空雙手，歸日依前雙手空。", "底事兩肩擔不起，打開畐塞滿玲瓏。", "姑蘇明月，苕霅清風。"]'),
('723753ce-2400-4124-8b1e-6c3d82aedc1d','偈頌一百三十六首  其一二七','釋惟一','宋','宋诗','song-poetry','','[]','泯志灰心，參禪學道。',68,'全唐诗/poet.song.216000.json','["泯志灰心，參禪學道。", "無煩惱中，自討煩惱。", "何不向老胡未來已前，試著眼看，自己分上有何欠少。", "天童恁麽道，不入深村入荒草。", "不許夜行，投明須到。"]'),
('25fbd21e-f17d-4c09-b187-1d7f860aa65c','偈頌一百三十六首  其一二八','釋惟一','宋','宋诗','song-poetry','','[]','謂吾滅度，未免落斷見。',35,'全唐诗/poet.song.216000.json','["謂吾滅度，未免落斷見。", "謂吾不滅度，未免落常見。", "二見俱遣除，十方佛皆現。"]'),
('50ffd18a-faca-47e9-9508-30fd2e4dd293','偈頌一百三十六首  其一二九','釋惟一','宋','宋诗','song-poetry','','[]','斗粟可舂，尺布可縫。',41,'全唐诗/poet.song.216000.json','["斗粟可舂，尺布可縫。", "情深義重，山包海容。", "載笑載言，喜而欲舞。", "豈無他人，不如我同父。"]'),
('b19dd67f-8598-4696-91ba-b628ba7cb307','偈頌一百三十六首  其一三○','釋惟一','宋','宋诗','song-poetry','','[]','夏令更新，春歸奏勳。',46,'全唐诗/poet.song.216000.json','["夏令更新，春歸奏勳。", "秧田鋪翠，麥隴翻雲。", "日猶舒暖，風已來熏。", "目擊道存如不委，更饒一喝主賓分。"]'),
('13468126-b3ef-45da-9dc4-de6f28d2880a','偈頌一百三十六首  其一三一','釋惟一','宋','宋诗','song-poetry','','[]','秋風清，秋月白，秋水共長天一色。',44,'全唐诗/poet.song.216000.json','["秋風清，秋月白，秋水共長天一色。", "不是心外境，亦非目前法。", "可中一見便知歸，平步廣寒攀桂枝。"]'),
('3e59d386-86ac-4a4b-b186-b8462482a15d','偈頌一百三十六首  其一三二','釋惟一','宋','宋诗','song-poetry','','[]','海山雨歇，水國雲藏。',46,'全唐诗/poet.song.216000.json','["海山雨歇，水國雲藏。", "薰風南來，殿閣生凉。", "佛出身處，昭然孔彰。", "堪笑當年奚老子，無端好肉上剜瘡。"]'),
('0501e1ca-73f8-473a-99e8-b598a541c4a0','偈頌一百三十六首  其一三三','釋惟一','宋','宋诗','song-poetry','','[]','偏中正，正中偏。',106,'全唐诗/poet.song.216000.json','["偏中正，正中偏。", "正偏不及處，別是一壺天。", "水澄澄，風細細，雲澹澹，月娟娟。", "金針兮纖纖，玉線兮綿綿。", "以此續洞脈於既微，以此大丹霞之正傳。", "作興太白，特遊戲之餘焉。", "今不在後，昔不在前。", "光明藏中，初無間然，一杯粗茗一爐煙。"]'),
('1da7f16d-f53c-4a49-bf80-abcd9099e381','偈頌一百三十六首  其一三四','釋惟一','宋','宋诗','song-poetry','','[]','故人義重，訪我巖扉。',36,'全唐诗/poet.song.216000.json','["故人義重，訪我巖扉。", "鳥啼花笑，雲淡風微。", "莫怪坐來頻勸酒，自從別後見君稀。"]'),
('cf0aa25a-681c-4b44-8e6c-944640f2b517','偈頌一百三十六首  其一三五','釋惟一','宋','宋诗','song-poetry','','[]','去秋雙峨摧，今夏芝巖墜。',40,'全唐诗/poet.song.216000.json','["去秋雙峨摧，今夏芝巖墜。", "松江松慘然，花嶼花流涕。", "惟有長空孤月圓，東西分照兩無偏。"]'),
('610a2582-a7b3-487b-9b10-b88a0e6c6331','偈頌一百三十六首  其一三六','釋惟一','宋','宋诗','song-poetry','','[]','生本不有，死亦無空。',22,'全唐诗/poet.song.216000.json','["生本不有，死亦無空。", "湖光晴瀲灧，山色雨濛瀧。"]'),
('83d0eac1-96f0-46ca-bb0c-0c0c0cfcbb52','偈頌四首  其一','釋惟一','宋','宋诗','song-poetry','','[]','臘月盡是歲除夜，明朝又是正月一。',32,'全唐诗/poet.song.216000.json','["臘月盡是歲除夜，明朝又是正月一。", "年去年來無盡期，拄杖依前烏律律。"]'),
('41919442-21be-4194-b8c6-c36a0c9371fd','偈頌四首  其二','釋惟一','宋','宋诗','song-poetry','','[]','叔季精神元似舊，慧慈面目只如新。',32,'全唐诗/poet.song.216000.json','["叔季精神元似舊，慧慈面目只如新。", "來年年是去年年，今日日同明日日。"]'),
('83e84252-4724-4bf3-8f71-5a4cb5127044','偈頌四首  其三','釋惟一','宋','宋诗','song-poetry','','[]','今歲今宵盡，日日日從東畔出。',28,'全唐诗/poet.song.216000.json','["今歲今宵盡，日日日從東畔出。", "明年明日來，朝朝雞向五更啼。"]'),
('999d4d49-2e3c-4a0f-ae13-69eb3fb15c07','偈頌四首  其四','釋惟一','宋','宋诗','song-poetry','','[]','臘月二十八九，家家戶戶盡有。',40,'全唐诗/poet.song.216000.json','["臘月二十八九，家家戶戶盡有。", "不是北禪露地牛，便是清源白家酒。", "羅列杯盤，同歡共笑。"]'),
('162c0020-6021-4b3c-a867-74620c5d87cd','頌古三十六首  其一','釋惟一','宋','宋诗','song-poetry','','[]','劫初鑄就毗盧印，古篆雕蟲尚宛然。',32,'全唐诗/poet.song.216000.json','["劫初鑄就毗盧印，古篆雕蟲尚宛然。", "堪笑堪悲人不識，却嫌字畫不完全。"]'),
('1e46bc80-44b3-48a8-acaf-30e4a570f799','頌古三十六首  其二','釋惟一','宋','宋诗','song-poetry','','["\u60dc\u65f6", "\u4e8c\u5e74\u7ea7\u4e0a\u518c", "\u5199\u666f", "\u52c9\u52b1", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','荷盡已無擎雨蓋，菊殘猶有傲霜枝。',32,'全唐诗/poet.song.216000.json','["荷盡已無擎雨蓋，菊殘猶有傲霜枝。", "一年好景君須記，正是橙黄橘綠時。"]'),
('e1ca297e-dda7-49d9-a272-b82445818bd0','頌古三十六首  其三','釋惟一','宋','宋诗','song-poetry','','[]','絕毫絕釐，日面月面。',36,'全唐诗/poet.song.216000.json','["絕毫絕釐，日面月面。", "號令四馳，風行草偃。", "拔山超海杳無蹤，風從龍兮雲從龍。"]'),
('a4a87bc1-728b-40ec-b917-0d439d9c67a0','頌古三十六首  其四','釋惟一','宋','宋诗','song-poetry','','[]','無寒暑處報君知，不離寒時與熱時。',32,'全唐诗/poet.song.216000.json','["無寒暑處報君知，不離寒時與熱時。", "熱則乘凉寒向火，不須回避不須疑。"]'),
('c3c80ff2-0644-49ea-a917-3c4b57b2b83b','頌古三十六首  其五','釋惟一','宋','宋诗','song-poetry','','[]','鷓鴣啼處百花香，劫外風光不覆藏。',32,'全唐诗/poet.song.216000.json','["鷓鴣啼處百花香，劫外風光不覆藏。", "往往遊人多蹉過，却從上苑探羣芳。"]'),
('5c0c070c-5fa7-420c-a1aa-a1b1ce6e0b07','頌古三十六首  其六','釋惟一','宋','宋诗','song-poetry','','[]','不堪提掇死貓頭，日炙風吹臭未休。',32,'全唐诗/poet.song.216000.json','["不堪提掇死貓頭，日炙風吹臭未休。", "底事罕逢人著價，只緣貴重世無儔。"]'),
('20f11f68-bf11-49a9-8c8b-e13732152597','頌古三十六首  其七','釋惟一','宋','宋诗','song-poetry','','[]','不落宮商太古音，無勞絃上發清聲。',32,'全唐诗/poet.song.216000.json','["不落宮商太古音，無勞絃上發清聲。", "高山流水有餘意，除却子期誰解聽。"]'),
('582f01b5-1d46-42cc-9310-e61475c752b8','頌古三十六首  其八','釋惟一','宋','宋诗','song-poetry','','[]','直下是，直下是。',52,'全唐诗/poet.song.216000.json','["直下是，直下是。", "上是天，下是地。", "日暖風和，花酣柳醉。", "玉笛纔轟，朱絃奏起。", "音響和同一會家，相逢彼此各天涯。"]'),
('52d4fa90-2534-4766-ac94-355a9790855c','頌古三十六首  其九','釋惟一','宋','宋诗','song-poetry','','[]','一物不爲，千聖不識。',38,'全唐诗/poet.song.216000.json','["一物不爲，千聖不識。", "靜夜霜鐘，澄潭秋月。", "清音絕聽，清影難窺，藥嶠石頭曾未知。"]'),
('43e17d41-f9dc-4361-9a72-190d7a300a91','頌古三十六首  其一○','釋惟一','宋','宋诗','song-poetry','','[]','臨濟栽松，一椎兩當。',38,'全唐诗/poet.song.216000.json','["臨濟栽松，一椎兩當。", "山門境致，後人標榜。", "鋤頭打地，滅却吾宗，陰凉大樹起清風。"]'),
('5a7bd953-911f-48e6-9d17-84df24f8899b','頌古三十六首  其一一','釋惟一','宋','宋诗','song-poetry','','[]','即心是佛，砒霜狼毒。',20,'全唐诗/poet.song.216000.json','["即心是佛，砒霜狼毒。", "起死回生，不消一服。"]'),
('775bf960-b80a-4737-8d95-2bdc366b22d7','頌古三十六首  其一二','釋惟一','宋','宋诗','song-poetry','','[]','和尚尊位如何，突出日面月面。',40,'全唐诗/poet.song.216000.json','["和尚尊位如何，突出日面月面。", "光艷爍破乾坤，五眼覷之不見。", "覷得見，何似尋常臘月扇。"]'),
('75b9e7e3-4026-4f13-957d-57b1286c2c76','頌古三十六首  其一三','釋惟一','宋','宋诗','song-poetry','','[]','自己將來更問誰，須彌還更戴須彌。',32,'全唐诗/poet.song.216000.json','["自己將來更問誰，須彌還更戴須彌。", "九峰末上能行令，免得重重涉水泥。"]'),
('3bd87c0f-6198-4499-bde7-10ffbe339aaa','頌古三十六首  其一四','釋惟一','宋','宋诗','song-poetry','','[]','白雲鼓起沒絃琴，一曲冬來意甚深。',32,'全唐诗/poet.song.216000.json','["白雲鼓起沒絃琴，一曲冬來意甚深。", "清韻至今猶未泯，江南江北少知音。"]'),
('a8e77fe6-c3b9-4ad8-a65d-a2e5980bba1b','頌古三十六首  其一五','釋惟一','宋','宋诗','song-poetry','','[]','金毛獅子奮全威，百億毛頭獅子兒。',32,'全唐诗/poet.song.216000.json','["金毛獅子奮全威，百億毛頭獅子兒。", "不是飲光槌不舉，惜伊無地可埋屍。"]'),
('3cd64e92-3f49-4f90-a3d0-e265c2876698','頌古三十六首  其一六','釋惟一','宋','宋诗','song-poetry','','[]','龐公幸是一家人，藥嶠何須禮過勤。',32,'全唐诗/poet.song.216000.json','["龐公幸是一家人，藥嶠何須禮過勤。", "只爲禮繁偏致亂，那堪雪也落紛紛。"]'),
('1fcd6377-4f37-4e80-b101-7a3c617f7842','頌古三十六首  其一七','釋惟一','宋','宋诗','song-poetry','','[]','萬法不爲侶，一口吸西江。',48,'全唐诗/poet.song.216000.json','["萬法不爲侶，一口吸西江。", "玉磬纔槌動，金鐘應手撞。", "三三元是九，兩兩不成雙。", "此意憑誰委，令人憶老龐。"]'),
('4397d026-6d3f-4007-ab33-5da0726efa16','頌古三十六首  其一八','釋惟一','宋','宋诗','song-poetry','','[]','無位真人活鱍鱍，赤肉團上爲窠窟。',66,'全唐诗/poet.song.216000.json','["無位真人活鱍鱍，赤肉團上爲窠窟。", "縱橫妙用可憐生，七出八沒難捉摸。", "推不去，挽不住，擬議尋思無覓處。", "無覓處，在這裏，握則一拳，開則五指。"]'),
('7d887bcd-820a-47a1-9a88-140816dafe86','頌古三十六首  其一九','釋惟一','宋','宋诗','song-poetry','','[]','真覺祖師展兩手，雲門一舉四十九。',32,'全唐诗/poet.song.216000.json','["真覺祖師展兩手，雲門一舉四十九。", "空王殿已峭巍巍，千古萬古猶仍舊。"]'),
('125434ae-5f50-4e30-a733-c65e7c934d11','頌古三十六首  其二○','釋惟一','宋','宋诗','song-poetry','','[]','老倒趙州無本據，翻手爲雲覆手雨，覿面當機不覆藏，往往少人知落處。',42,'全唐诗/poet.song.216000.json','["老倒趙州無本據，翻手爲雲覆手雨，覿面當機不覆藏，往往少人知落處。", "知落處，是甚閑家具。"]'),
('88a08017-7370-4afc-80fe-9f8bc223f424','頌古三十六首  其二一','釋惟一','宋','宋诗','song-poetry','','[]','烏藤約住未爲過，禪板焚來也是閑。',32,'全唐诗/poet.song.216000.json','["烏藤約住未爲過，禪板焚來也是閑。", "最苦河南與河北，雷轟一喝誑癡頑。"]'),
('462e525f-4398-48e5-9c8c-69b7800935df','頌古三十六首  其二二','釋惟一','宋','宋诗','song-poetry','','[]','武帝求僊不得僊，王喬端坐却升天。',32,'全唐诗/poet.song.216000.json','["武帝求僊不得僊，王喬端坐却升天。", "有心用處還應錯，無意求時又宛然。"]'),
('1b13ee7e-7585-4c1b-9dcd-dba62e912710','頌古三十六首  其二三','釋惟一','宋','宋诗','song-poetry','','[]','蘗山養子忒婆心，斫了摩挲不憚勤。',32,'全唐诗/poet.song.216000.json','["蘗山養子忒婆心，斫了摩挲不憚勤。", "悖逆兒郎渾不顧，钁頭掣得氣凌雲。"]'),
('0134772d-77bf-4d73-9f63-29e5331a5f99','頌古三十六首  其二四','釋惟一','宋','宋诗','song-poetry','','[]','雪裏垂絲古釣臺，錦鱗拂拂上釣來。',32,'全唐诗/poet.song.216000.json','["雪裏垂絲古釣臺，錦鱗拂拂上釣來。", "船頭撥轉歸何處，又向蘆花深處挨。"]'),
('f65a6ca3-89c4-4b6c-b8b1-8c8b6f0c76ad','頌古三十六首  其二五','釋惟一','宋','宋诗','song-poetry','','[]','曹溪門下南來燕，終日呢喃話祖翁。',32,'全唐诗/poet.song.216000.json','["曹溪門下南來燕，終日呢喃話祖翁。", "話盡離微人不會，不如養羽候秋風。"]'),
('a1753fa7-9eff-4fdd-aefc-09f083683699','頌古三十六首  其二六','釋惟一','宋','宋诗','song-poetry','','[]','雪覆千山未厭多，孤峰不白意如何。',32,'全唐诗/poet.song.216000.json','["雪覆千山未厭多，孤峰不白意如何。", "單單突出千峰外，似異還同永不麽。"]'),
('f833e0a7-840a-4923-a5fe-5852031d5178','頌古三十六首  其二七','釋惟一','宋','宋诗','song-poetry','','[]','來去客情千樣別，高低主禮一般施。',32,'全唐诗/poet.song.216000.json','["來去客情千樣別，高低主禮一般施。", "相逢不飲空歸去，明月清風也笑伊。"]'),
('6cb6fbf2-6fb0-4111-a074-4b63ab4c60c5','頌古三十六首  其二八','釋惟一','宋','宋诗','song-poetry','','[]','風性無周無不周，手中扇子等閑摇。',32,'全唐诗/poet.song.216000.json','["風性無周無不周，手中扇子等閑摇。", "風前吹起無根樹，不作桑條作柳條。"]'),
('23e345d2-1efe-423f-84aa-eb51a61940ac','頌古三十六首  其二九','釋惟一','宋','宋诗','song-poetry','','[]','縱火燒山臘月時，衲衣下事爲全提。',32,'全唐诗/poet.song.216000.json','["縱火燒山臘月時，衲衣下事爲全提。", "幾多撥草瞻風底，燎盡眉毛總不知。"]'),
('c3d6e05c-710b-4f40-81c4-f9841228c709','頌古三十六首  其三○','釋惟一','宋','宋诗','song-poetry','','[]','溈嶠冬天轟霹靂，仰山夏月降嚴霜。',32,'全唐诗/poet.song.216000.json','["溈嶠冬天轟霹靂，仰山夏月降嚴霜。", "鐵鎚兩箇都無孔，打就乾坤自廝當。"]'),
('97edfd29-fd46-475a-98c4-f7e449760127','頌古三十六首  其三一','釋惟一','宋','宋诗','song-poetry','','[]','發機外機，遣句中句。',34,'全唐诗/poet.song.216000.json','["發機外機，遣句中句。", "明眼衲僧，不知落處。", "知落處，南山起雲，北山下雨。"]'),
('43d64e1d-0afa-4115-8220-2c7112dfa082','頌古三十六首  其三二','釋惟一','宋','宋诗','song-poetry','','[]','水中鹽味渾相似，色裏膠青不較多。',44,'全唐诗/poet.song.216000.json','["水中鹽味渾相似，色裏膠青不較多。", "暗不謂無明不有，看時不見轉誵訛。", "沒誵訛，太平何必動干戈。"]'),
('ad8a85ef-4946-4433-b183-e18f3c6033d4','頌古三十六首  其三三','釋惟一','宋','宋诗','song-poetry','','[]','電光石火箭鋒機，父倒行兮子逆施。',32,'全唐诗/poet.song.216000.json','["電光石火箭鋒機，父倒行兮子逆施。", "力敵勢均難辨別，一雙無孔鐵門槌。"]'),
('a2e005a9-1721-4748-b4d8-a9c1e48140d3','頌古三十六首  其三四','釋惟一','宋','宋诗','song-poetry','','[]','烏飛兔走晝還夜，臘盡春回年復年。',32,'全唐诗/poet.song.216000.json','["烏飛兔走晝還夜，臘盡春回年復年。", "無盡無窮窮盡處，東村王老夜燒錢。"]'),
('7216a0d2-d8f5-418f-9aa8-64c67ef35e67','頌古三十六首  其三五','釋惟一','宋','宋诗','song-poetry','','[]','將鋤打地自拋屙，怎柰熏天臭氣何。',32,'全唐诗/poet.song.216000.json','["將鋤打地自拋屙，怎柰熏天臭氣何。", "老倒蘗山禁不得，却將伊頂再三摩。"]'),
('32a5ef3a-0061-4676-8945-79a127584721','頌古三十六首  其三六','釋惟一','宋','宋诗','song-poetry','','[]','問我家風，識你家風。',42,'全唐诗/poet.song.216000.json','["問我家風，識你家風。", "將謂耳背，元來耳聾。", "指南爲北，問西答東。", "阿呵呵，趙州恰恰似天童。"]'),
('9086cafd-4428-489a-9925-84ce6099ca8a','觀音贊','釋惟一','宋','宋诗','song-poetry','','[]','耳門圓照，日月兩間。',56,'全唐诗/poet.song.216000.json','["耳門圓照，日月兩間。", "悲願洪深，衣被四海。", "方便智慧，靡不圓融。", "見聞覺知，無能障礙。", "人間天上獨優游，是則名爲觀自在。"]'),
('7235d19f-8a9f-4709-af91-bdf88e92e0d6','馬郎婦贊','釋惟一','宋','宋诗','song-poetry','','[]','雲開天竺，月照金沙。',28,'全唐诗/poet.song.216000.json','["雲開天竺，月照金沙。", "心心妙法，念念蓮華。", "未必將身許馬家。"]'),
('5fab2cda-dcc7-4507-a2e9-a2b63689eec9','魚籃贊','釋惟一','宋','宋诗','song-poetry','','[]','鱍喇籃中活錦鱗，風前提起不辭頻。',32,'全唐诗/poet.song.216000.json','["鱍喇籃中活錦鱗，風前提起不辭頻。", "幾回繞盡長沙市，賣與買人無買人。"]'),
('557c4fcd-ae62-4b11-a43e-8f1dd1edfeb1','文殊贊','釋惟一','宋','宋诗','song-poetry','','[]','或草爲衣，或獅爲輿。',36,'全唐诗/poet.song.216000.json','["或草爲衣，或獅爲輿。", "千變萬化，無二文殊。", "雖然覓則不可得，五臺山色猶如如。"]'),
('934b797b-1025-4809-bcc8-2e88a6896372','布袋贊','釋惟一','宋','宋诗','song-poetry','','[]','逢人乞一文，袋裏敵國富。',24,'全唐诗/poet.song.216000.json','["逢人乞一文，袋裏敵國富。", "不是下生遲，嫌佛不肯做。"]'),
('ae6747a1-0815-40a5-bcae-c97f75b4a94e','達磨贊','釋惟一','宋','宋诗','song-poetry','','[]','西來十萬里，北渡一莖蘆。',24,'全唐诗/poet.song.216000.json','["西來十萬里，北渡一莖蘆。", "剛道來傳法，還曾傳得無。"]'),
('3cdbf203-7489-458d-a8f2-8bd3166deb1b','維摩贊','釋惟一','宋','宋诗','song-poetry','','[]','凜然夷齊之風，翛然巢許之態。',75,'全唐诗/poet.song.216000.json','["凜然夷齊之風，翛然巢許之態。", "橫作竺乾之孽，崛起釋門之害。", "口吧吧地說盡萬千，究竟不知有這一解。", "人皆謂金粟如來示現毗耶，我只道病多諳藥性底耆年婆羅門者也。"]'),
('b395baf0-3dcd-498c-b529-cbcc82fa94e8','黄蘗斷際禪師贊','釋惟一','宋','宋诗','song-poetry','','[]','大機磅礴，大用縱橫，要掌便掌。',56,'全唐诗/poet.song.216000.json','["大機磅礴，大用縱橫，要掌便掌。", "大中天子，掌中突出，要棒便棒。", "濟北大樹，棒頭挺生。", "大唐國裏只一人，千古仰之日月明。"]'),
('d8171c79-f737-476d-8ab8-0964485a20aa','裴相國贊','釋惟一','宋','宋诗','song-poetry','','[]','咄這措大，極是叵耐。',71,'全唐诗/poet.song.216000.json','["咄這措大，極是叵耐。", "操我戈矛，入我疆界。", "撲滅圓覺大光明藏，瀝乾圭峰無邊義海。", "所至皆望風退衂，末後遭蘗山和贓捉敗。", "納款投降，願爲弟子，奉事無懈。"]'),
('03c89607-9718-4c8a-90b8-43e122424925','雪峰真覺祖師贊','釋惟一','宋','宋诗','song-poetry','','[]','弄出鱉鼻蛇，彈起廣陵曲。',40,'全唐诗/poet.song.216000.json','["弄出鱉鼻蛇，彈起廣陵曲。", "清韻難可掩，毒氣不可觸。", "瞻之不足聽不足，千古萬古福城福。"]'),
('bb08e5cd-46d1-4274-80ff-9987c6ac83a3','朝陽穿破衲贊','釋惟一','宋','宋诗','song-poetry','','[]','一條屈曲無絲線，半寸攀拳穴鼻針。',32,'全唐诗/poet.song.216000.json','["一條屈曲無絲線，半寸攀拳穴鼻針。", "補得完全成一片，舉頭紅日到天心。"]'),
('7e49ec1a-b502-4cb5-8f39-0eeb9c0e267e','對月了殘經贊','釋惟一','宋','宋诗','song-poetry','','[]','古教只知遮老眼，銀蟾不覺上孤峰。',32,'全唐诗/poet.song.216000.json','["古教只知遮老眼，銀蟾不覺上孤峰。", "看來看到無看處，光境俱忘一卷終。"]'),
('22508822-e171-402e-911a-f505bc5d24b9','廛中佛事','釋惟一','宋','宋诗','song-poetry','','[]','幾回走巷復穿衢，貨賣南方鎮海珠。',32,'全唐诗/poet.song.216000.json','["幾回走巷復穿衢，貨賣南方鎮海珠。", "一栲栳都傾出了，不知酬價有人無。"]'),
('4d79646d-83e0-4b1d-8c14-5a610738a0a9','物外生涯','釋惟一','宋','宋诗','song-poetry','','[]','三十餘年海上遊，未曾容易下金鈎。',32,'全唐诗/poet.song.216000.json','["三十餘年海上遊，未曾容易下金鈎。", "等閑拋擲絲綸處，蝦蟹魚龍一網收。"]'),
('846d4e20-a73a-4d20-9c6a-42d928959b76','松風度曲','釋惟一','宋','宋诗','song-poetry','','[]','大夫噫氣撼青冥，餘韻蕭騷入戶庭。',32,'全唐诗/poet.song.216000.json','["大夫噫氣撼青冥，餘韻蕭騷入戶庭。", "遞到高山流水意，不知誰解眼中聽。"]'),
('714f00a6-e5dd-4074-ba09-f78ede37a035','荷露跳珠','釋惟一','宋','宋诗','song-poetry','','[]','優曇初現葉團團，錯落明璣走碧盤。',32,'全唐诗/poet.song.216000.json','["優曇初現葉團團，錯落明璣走碧盤。", "沆瀣莫將魚目比，看時容易覓時難。"]'),
('2177e35c-ac89-4175-8645-d0e05ecd927d','定翁','釋惟一','宋','宋诗','song-poetry','','[]','日用千差萬別中，如如不動等虛空。',32,'全唐诗/poet.song.216000.json','["日用千差萬別中，如如不動等虛空。", "春妍秋靖幾更變，此老何曾改舊容。"]'),
('4605b812-0c50-49b5-b134-87293d7e5f63','古堂','釋惟一','宋','宋诗','song-poetry','','[]','過去威音佛已前，向虛空裏架榱椽。',32,'全唐诗/poet.song.216000.json','["過去威音佛已前，向虛空裏架榱椽。", "至今景定年之二，往却門風尚儼然。"]'),
('af4b2484-2c56-437f-91ee-45af6bbb9b7d','鏡空','釋惟一','宋','宋诗','song-poetry','','[]','團團荷葉不相似，豁豁大虛難比倫。',32,'全唐诗/poet.song.216000.json','["團團荷葉不相似，豁豁大虛難比倫。", "箇裏洞然無一物，擬於何處拂埃塵。"]'),
('e2893789-756d-409a-b201-e39cffbed662','野航','釋惟一','宋','宋诗','song-poetry','','[]','遠泛飄然一葦輕，水天上下鏡無塵。',32,'全唐诗/poet.song.216000.json','["遠泛飄然一葦輕，水天上下鏡無塵。", "自從碧眼胡歸後，著脚那知是甚人。"]'),
('d08530ae-8634-4a25-a272-cf0c49ddfc21','月浦','釋惟一','宋','宋诗','song-poetry','','[]','孤明歷歷曲彎彎，色與蘆花彷彿間。',32,'全唐诗/poet.song.216000.json','["孤明歷歷曲彎彎，色與蘆花彷彿間。", "多是滿船空載去，幾人親得見珠還。"]'),
('3684f6a1-6e99-4ffb-96a4-c0e926f86fef','危峰','釋惟一','宋','宋诗','song-poetry','','[]','似側如欹杳靄間，冰稜劍刃不多爭。',32,'全唐诗/poet.song.216000.json','["似側如欹杳靄間，冰稜劍刃不多爭。", "可中不是通玄頂，切莫粗心向上行。"]'),
('7e3d2f15-2f31-43b7-b40b-182dcf18e180','懶牛','釋惟一','宋','宋诗','song-poetry','','[]','鼻繩拽脫了無拘，慵有餘兮頑有餘。',32,'全唐诗/poet.song.216000.json','["鼻繩拽脫了無拘，慵有餘兮頑有餘。", "芳草滿前渾不顧，眠雲卧月只如如。"]'),
('d07f1401-cc5a-4b4e-88d6-4478bd9d2508','南窗','釋惟一','宋','宋诗','song-poetry','','[]','百一十城煙水外，玲瓏八面自天開。',32,'全唐诗/poet.song.216000.json','["百一十城煙水外，玲瓏八面自天開。", "等閑坐斷東西北，無限薰風拂拂來。"]'),
('70cdfc57-527e-40fa-af2a-848be2572631','虛舟','釋惟一','宋','宋诗','song-poetry','','[]','內亦空兮外亦空，不施櫓棹不張蓬。',32,'全唐诗/poet.song.216000.json','["內亦空兮外亦空，不施櫓棹不張蓬。", "聽它東去又西去，誰管漫天鼓黑風。"]'),
('aa39e908-83fe-4c1b-bf0c-81f199d810d1','坦翁','釋惟一','宋','宋诗','song-poetry','','[]','山未爲高水未深，賤非泥土貴非金。',32,'全唐诗/poet.song.216000.json','["山未爲高水未深，賤非泥土貴非金。", "自來一種平懷看，到老何曾有二心。"]'),
('e0985924-f5e6-46dd-8858-4fe42f5f329e','可山','釋惟一','宋','宋诗','song-poetry','','[]','三拜起來依位立，孤高不與衆峰齊。',32,'全唐诗/poet.song.216000.json','["三拜起來依位立，孤高不與衆峰齊。", "自從得髓歸來後，便見乾坤宇宙低。"]'),
('a39608d1-80ae-4dd0-9cf3-c10d3b78ce18','寄雪竇希叟','釋惟一','宋','宋诗','song-poetry','','[]','舌本瀾翻千丈雪，眼青錦鏡一壺冰。',32,'全唐诗/poet.song.216000.json','["舌本瀾翻千丈雪，眼青錦鏡一壺冰。", "瞎馿種草有如此，滅却凌霄正續燈。"]'),
('50a0e948-ee42-4246-9ac5-4c10660b6b24','寄天寧雪庭','釋惟一','宋','宋诗','song-poetry','','[]','一本凌霄秋後瓜，遲遲九月裏開花。',32,'全唐诗/poet.song.216000.json','["一本凌霄秋後瓜，遲遲九月裏開花。", "霜前結子須彌大，壓倒東西浙五家。"]'),
('f1e1b53f-8ece-41f3-99c1-402eee4423c6','看石田語','釋惟一','宋','宋诗','song-poetry','','[]','語言硬浄如生鐵，眼目高明爍太陽。',32,'全唐诗/poet.song.216000.json','["語言硬浄如生鐵，眼目高明爍太陽。", "今日江湖無此作，令人三嘆憶平羌。"]'),
('a4f2a0cf-71ca-4dca-89df-3143cccb1336','送僧遊南嶽','釋惟一','宋','宋诗','song-poetry','','["\u8861\u5c71"]','一口盡吞三世佛，近來出世佛猶多。',32,'全唐诗/poet.song.216000.json','["一口盡吞三世佛，近來出世佛猶多。", "爲吾問訊老思大，底事不能開口何。"]'),
('452bf7e9-5b0d-4f41-9dc5-d11db69e16d8','吉州圓上人之浙','釋惟一','宋','宋诗','song-poetry','','[]','廬陵米價沒誵訛，半說低兮半說高。',32,'全唐诗/poet.song.216000.json','["廬陵米價沒誵訛，半說低兮半說高。", "此話要圓緘却口，聽他江浙閙嘈嘈。"]'),
('0d572e36-98e4-4997-a0f0-9ccb35b3e116','瓊上人之杭','釋惟一','宋','宋诗','song-poetry','','[]','懷抱瓊瑶一段奇，通身富貴少人知。',32,'全唐诗/poet.song.216000.json','["懷抱瓊瑶一段奇，通身富貴少人知。", "四藤擊碎還收拾，攤向皇都賣與誰。"]'),
('0e82fbb9-5489-47a9-be3a-72b5512a25b6','風幡亮上人游浙','釋惟一','宋','宋诗','song-poetry','','[]','動在風幡動在心，集雲棒下已分明。',32,'全唐诗/poet.song.216000.json','["動在風幡動在心，集雲棒下已分明。", "而今百越三吳去，肯聽它家熱碗鳴。"]'),
('44d5257f-fd36-4b4d-b37c-d2157b0120e8','月華崧上人之杭','釋惟一','宋','宋诗','song-poetry','','["\u897f\u6e56"]','月華如水夜沉沉，一曲簫韻韻更清。',32,'全唐诗/poet.song.216000.json','["月華如水夜沉沉，一曲簫韻韻更清。", "曲罷莫言無覓處，西湖後夜轉堪聽。"]'),
('975ed40c-5a36-4d8b-a6bf-6c95330760d4','傳上人之吳','釋惟一','宋','宋诗','song-poetry','','[]','達磨西來有底傳，賺人掘地覓青天。',32,'全唐诗/poet.song.216000.json','["達磨西來有底傳，賺人掘地覓青天。", "況今楓落吳江冷，去去休容易泊船。"]'),
('daad1853-8970-4774-888c-57a56f8a9721','暫到','釋惟一','宋','宋诗','song-poetry','','[]','騎鯨捉月莫辭勞，海角天涯打一遭。',32,'全唐诗/poet.song.216000.json','["騎鯨捉月莫辭勞，海角天涯打一遭。", "後夜再三撈摝得，碧天雲靜一輪高。"]'),
('bf362e7b-9458-455c-99a7-da0195675020','送曇知客歸感山','釋惟一','宋','宋诗','song-poetry','','[]','嬾向人前送又迎，飄然去路一身輕。',32,'全唐诗/poet.song.216000.json','["嬾向人前送又迎，飄然去路一身輕。", "到家有問到家句，雨過瀟湘秋月明。"]'),
('4bfda632-1239-4635-8c0b-98eaef3a7f04','刀鑷黄陳二生  其一','釋惟一','宋','宋诗','song-poetry','','[]','手持刀鑷謁桑門，叉手擎拳笑語溫。',32,'全唐诗/poet.song.216000.json','["手持刀鑷謁桑門，叉手擎拳笑語溫。", "且說工夫精妙處，斷然毫髮不容存。"]'),
('be2416ff-0d52-45f6-a75d-1bb5d198c620','刀鑷黄陳二生  其二','釋惟一','宋','宋诗','song-poetry','','[]','雙手乖如雙眼乖，等閑浄出頂門埃。',32,'全唐诗/poet.song.216000.json','["雙手乖如雙眼乖，等閑浄出頂門埃。", "幾多鐵額銅頭漢，總被渠儂按過來。"]'),
('b727baac-8152-4798-9ea5-bc197b068723','禮疎山塔  其一','釋惟一','宋','宋诗','song-poetry','','[]','造塔當年事，喧傳直至今。',48,'全唐诗/poet.song.216000.json','["造塔當年事，喧傳直至今。", "示人千古意，與匠兩三金。", "不得羅山語，誰知矮叔心。", "瓣香來作禮，肯顧白雲深。"]'),
('6f8dca7e-6af9-4d4c-b519-e92b9fa9f410','禮疎山塔  其二','釋惟一','宋','宋诗','song-poetry','','[]','江橫一練平，山色四時青。',48,'全唐诗/poet.song.216000.json','["江橫一練平，山色四時青。", "水足柴猶富，人多爨不停。", "無絃猶自韻，有耳幾曾聽。", "槁矣齊簷柏，頻看涕忽零。"]'),
('4b91070c-7306-4297-b681-e803c7ac8829','送孚藏主歸江西','釋惟一','宋','宋诗','song-poetry','','[]','雲卧胸中蟠萬卷，舌端筆端皆具眼。',160,'全唐诗/poet.song.216000.json','["雲卧胸中蟠萬卷，舌端筆端皆具眼。", "評今論古知幾何，寥寥百年骨不冷。", "有孫挺特尤掀騰，富有藴藉如弗能。", "韜光鏟彩事枯硬，不學乃翁牽葛藤。", "壁立萬仞出一語，佛祖應無啟口處。", "有時一默淵且深，盡大地人難指注。", "脚尖踢倒凌霄峰，揮劍活屠潭底龍。", "三條椽下四世界，破蒲團邊兜率宮。", "秋風忽起故山興，歸本無歸語何剩。", "江湖斫額應望君，莫作秤鎚落深井。"]'),
('1cc8dd95-21b7-4aef-abed-3907cc41bf97','將赴雪峰示圭上人','釋惟一','宋','宋诗','song-poetry','','[]','上人辭我去行脚，我亦早晚行脚去。',128,'全唐诗/poet.song.216000.json','["上人辭我去行脚，我亦早晚行脚去。", "天涯海角或重逢，鉢飯莖虀又相聚。", "自笑年登六十七，眼昏耳聵脚無力。", "觸事無能只面牆，百千追悔有何益。", "少壯學道宜加鞭，危亡不顧勇直前。", "如一人與萬人敵，破堅挫銳成萬全。", "放牛歸馬群務息，好是太平無事日。", "塞北歸鴻截霧飛，江南野水連天碧。"]'),
('5d12eb68-5af7-4f16-a67b-8923fb64c890','見侍者乞語爲入道蹊徑','釋惟一','宋','宋诗','song-poetry','','[]','入道蹊徑無蹊徑，日用現行何不省。',100,'全唐诗/poet.song.216000.json','["入道蹊徑無蹊徑，日用現行何不省。", "和南問訊已乖張，應對賓朋曾不隠。", "同盂共飯況三年，話破那知萬萬千。", "今日炷香重覓語，許時聚首成徒然。", "老僧更不能忉怛，痛掌寧辭當面搭。", "從教負痛走出門，呼天怨駡齒沒舌禿口未合。"]'),
('c1638e83-0e54-4e63-a416-2994f2441ea9','題群牧圖','釋惟一','宋','宋诗','song-poetry','','[]','雨過桃林草正肥，休征牧放恰相宜。',32,'全唐诗/poet.song.216000.json','["雨過桃林草正肥，休征牧放恰相宜。", "擎頭戴角群然樂，喜見太平無事時。"]'),
('d4390b94-7b7c-4711-90a7-490bbb6d8e24','題草蟲圖','釋惟一','宋','宋诗','song-poetry','','[]','長莖短莖芳草翠，東個西個秋蟲寒。',32,'全唐诗/poet.song.216000.json','["長莖短莖芳草翠，東個西個秋蟲寒。", "平白祖翁田一片，時人莫作畫圖看。"]'),
('7234bda4-2b3a-43d6-aad3-6fbf358ba1ed','小師惠林師孫法濟請贊','釋惟一','宋','宋诗','song-poetry','','[]','齒豁頭童，眼昏耳聾。',58,'全唐诗/poet.song.216000.json','["齒豁頭童，眼昏耳聾。", "不忘所嗜乾屎橛，未忍輕拋栗棘蓬。", "以此踞叢林，以此濟貧窮。", "只緣真實不脫空，故得孝子慈孫寫真而繪容。"]'),
('389ee13f-1992-497b-adb2-a736ffbc4e84','奇都管請贊','釋惟一','宋','宋诗','song-poetry','','[]','牧以卑，守以規，迅雷疾風，鐵石不移。',68,'全唐诗/poet.song.216000.json','["牧以卑，守以規，迅雷疾風，鐵石不移。", "須彌其頹，隻手力持。", "電光石火裏驅耕奪食，春風和氣中摧枯拉萎。", "極等沒意智，闔國少人知，知之梓府牛峰奇。"]'),
('9b539726-5e60-4e47-aa48-13f405175f3f','小師惠彰請贊','釋惟一','宋','宋诗','song-poetry','','[]','顧我遊世間，如雲在天上。',68,'全唐诗/poet.song.216000.json','["顧我遊世間，如雲在天上。", "任緣而去住，不作去住想。", "南北信所之，東西無定向。", "爲人少方便，動便攔腮掌。", "恁地去離泥水底本師，如何却喚作環溪和尚。"]'),
('a8383a01-9709-4f74-84a6-c37c87e381b3','雪峰化士請贊','釋惟一','宋','宋诗','song-poetry','','[]','藞藞苴苴，瀟瀟灑灑。',80,'全唐诗/poet.song.216000.json','["藞藞苴苴，瀟瀟灑灑。", "嚴冷時溫若陽春，褊急處寬踰大海。", "纔開口，平日說。", "脫空却嫌人，無事謗般若。", "有時突出一句鄉談，佛也不能覷他縫罅。", "從來閩蜀本同風，相逢自有知音者。"]'),
('e8107289-0b2b-479e-90c6-151442e1b0c8','禪人請贊','釋惟一','宋','宋诗','song-poetry','','[]','赤土畫簸箕，冬瓜作碓嘴。',41,'全唐诗/poet.song.216000.json','["赤土畫簸箕，冬瓜作碓嘴。", "舂碎鐵蒺藜，簸出長粳米。", "不須淘汰，不須炊飽，盡世人人不知。"]'),
('7ceaf7ef-501e-4b3f-a0dc-b79ba29f8feb','辭世頌','釋浄慈東叟','宋','宋诗','song-poetry','','[]','南山末後句，未舉先分付。',24,'全唐诗/poet.song.216000.json','["南山末後句，未舉先分付。", "生也何曾生，死也何曾死。"]'),
('b711deb0-16a3-4a4e-af11-efd581a7f591','詩二首  其一','施清臣','宋','宋诗','song-poetry','','[]','花裏蝶，花裏休。',32,'全唐诗/poet.song.216000.json','["花裏蝶，花裏休。", "蓼中蟲，蓼中死。", "人生甜苦皆是緣，法只可隨順應之。"]'),
('f067b668-b4ef-4aad-92ce-4358bb00cb2e','詩二首  其二','施清臣','宋','宋诗','song-poetry','','[]','一蓑一笠一孤舟，萬里江山獨自遊。',32,'全唐诗/poet.song.216000.json','["一蓑一笠一孤舟，萬里江山獨自遊。", "有人問我紅塵事，笑入蘆花不點頭。"]'),
('52d7b4b7-5f59-40d6-853e-dfca9c25aefc','緋桃','施清臣','宋','宋诗','song-poetry','','[]','衣裁緗纈態纖穠，猶在瑶池半醉中。',32,'全唐诗/poet.song.216000.json','["衣裁緗纈態纖穠，猶在瑶池半醉中。", "嫌近清明時節冷，趁渠新火一番紅。"]'),
('4d9a3566-23ed-440d-ba11-8feb6905d68f','湖景','施清臣','宋','宋诗','song-poetry','','[]','一曲新腔紫玉簫，護晴簷幙窣蘭橈。',32,'全唐诗/poet.song.216000.json','["一曲新腔紫玉簫，護晴簷幙窣蘭橈。", "柳迷遠近花張錦，小泊危紅第六橋。"]'),
('58ab75df-8952-4104-b42a-a6fcf4a31a1d','牽牛花','施清臣','宋','宋诗','song-poetry','','[]','一泓天水染朱衣，生怕紅埃透日飛。',32,'全唐诗/poet.song.216000.json','["一泓天水染朱衣，生怕紅埃透日飛。", "急整離離蒼玉佩，曉雲光裏渡河歸。"]'),
('48694d59-88ad-4827-bccd-d1a045ae7753','夜蛾兒','施清臣','宋','宋诗','song-poetry','','[]','碧服銀鬚粉撲衣，又隨雪柳趁燈輝。',32,'全唐诗/poet.song.216000.json','["碧服銀鬚粉撲衣，又隨雪柳趁燈輝。", "怕寒還戀南華夢，凝佇釵頭未肯飛。"]'),
('52f194b2-3211-4e08-bf83-0cb4f9f9734f','題資福院平綠軒','陸德輿','宋','宋诗','song-poetry','','[]','带市人煙遠，連村野色幽。',48,'全唐诗/poet.song.216000.json','["带市人煙遠，連村野色幽。", "山從天際出，水向檻前流。", "茅屋無端礙，松醪有意留。", "因懷陵谷感，無語對歸鷗。"]'),
('3c672df7-cb32-4f39-bf67-ac48db671cc0','遊九鎖','趙崇纘','宋','宋诗','song-poetry','','[]','九峯元不鎖，俗駕自來稀。',48,'全唐诗/poet.song.216000.json','["九峯元不鎖，俗駕自來稀。", "水石藏仙窟，煙霞護羽衣。", "夜猿窺月叫，曉鶴出松飛。", "擬結巢由伴，眠雲隠翠微。"]'),
('c05664df-e921-4f00-9e25-e041ba5e4613','題半月巖','吳文震','宋','宋诗','song-poetry','','[]','□靈通一竅，如月未全盈。',48,'全唐诗/poet.song.216000.json','["□靈通一竅，如月未全盈。", "外□山河界，中涵蚌蛤精。", "銀潢斜□斷，玉斧半修成。", "莫訝平分破，難虧半體明。"]'),
('63e8e897-24b9-4bce-b9a8-fa5081d5b9ec','題浯溪','吳文震','宋','宋诗','song-poetry','','[]','景定初元汛虜氛，掀天功業掩前聞。',64,'全唐诗/poet.song.216000.json','["景定初元汛虜氛，掀天功業掩前聞。", "扶唐社稷郭中令，造漢乾坤賈冠軍。", "好激浯溪湔舊案，重磨崖石紀元勳。", "僕今已辦湘山刻，未遜聱翁星斗文。"]'),
('6c1dd94b-9ecf-40a7-bc19-ab57eed3dcd0','元石','吳文震','宋','宋诗','song-poetry','','[]','卷石之中有道存，巖巖氣象峻于天。',64,'全唐诗/poet.song.216000.json','["卷石之中有道存，巖巖氣象峻于天。", "巍乎近取舜爲法，卓爾如羣孔在前。", "跨六鼇頭觀戴極，出羣龍首要承乾。", "聖門所重非科第，向上工夫合勉旃。"]'),
('fc519757-749d-4a3d-9d43-d175e50c83e5','高齋桂窟','洪揚祖','宋','宋诗','song-poetry','','[]','植桂不在多，種德如種樹。',108,'全唐诗/poet.song.216000.json','["植桂不在多，種德如種樹。", "前人能種後人傳，自有清陰滿庭戶。", "高枝凌雲低覆欄，晴光翠色生晝寒。", "人家多愛種桃李，幾日春風紅滿地。", "何如此花開獨遲，蟾宮窟外秋香細。", "課兒讀書書滿牀，更將幽興引壺觴。", "半酣獨卧高齋下，啼鳥數聲清晝長。"]'),
('b251c8e5-aa5f-4956-9d47-ec275512d63f','含笑花','蕭崱','宋','宋诗','song-poetry','','[]','肥樣凋成玉色仙，碧瑶幢裏粲嬋娟。',32,'全唐诗/poet.song.216000.json','["肥樣凋成玉色仙，碧瑶幢裏粲嬋娟。", "道渠解笑何曾笑，只合更名小白蓮。"]'),
('9f7a7c28-7b47-4252-bc0a-302fe3995fa5','龍眼','蕭崱','宋','宋诗','song-poetry','','[]','選荔過於選士難，味佳能有幾登盤。',32,'全唐诗/poet.song.216000.json','["選荔過於選士難，味佳能有幾登盤。", "林家新出金釵子，合入君謨譜後刊。"]'),
('ca90664b-5273-4d1b-a230-97156f9ea251','蘆','蕭崱','宋','宋诗','song-poetry','','[]','江客因貧識荻芽，一清鏖退雜魚蝦。',64,'全唐诗/poet.song.216000.json','["江客因貧識荻芽，一清鏖退雜魚蝦。", "燒來味挾蠔邊雨，掘得身離雁外沙。", "春饌且供行釜菜，秋粧莫管釣舡花。", "食根思到蕭騷葉，痛感邊聲咽戍笳。"]'),
('1dd1ed4a-396b-4408-84bd-bf2ab5f6a0c1','漆','蕭崱','宋','宋诗','song-poetry','','[]','天以晶華累爾形，千夫歛鍔可曾停。',64,'全唐诗/poet.song.216000.json','["天以晶華累爾形，千夫歛鍔可曾停。", "世間有器蒙鮮飾，林下無辜受割刑。", "斫壞孫枝難老大，摧殘去榦易凋零。", "退思禹貢周征日，未必如今稅不征。"]'),
('644ed280-a486-46b8-99cd-af752f8faaeb','贈陸冰','蕭崱','宋','宋诗','song-poetry','','[]','標格真清挾雪霜，每聽新詠覺神傷。',64,'全唐诗/poet.song.216000.json','["標格真清挾雪霜，每聽新詠覺神傷。", "茶分鴻漸經中味，菊愛龜蒙賦裏香。", "圃積玉多知學飽，囊裝金少爲貪忙。", "向來笑疾難醫在，老筆空鈔十卷方。"]'),
('e5a691d9-3f75-4263-861d-4afd659f1f04','送弟赴省','蕭崱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','河南蕭氏粲文物，鶴在九臯無數鳴。',192,'全唐诗/poet.song.216000.json','["河南蕭氏粲文物，鶴在九臯無數鳴。", "小山羽翮日絢練，膽氣也作虹霓橫。", "掛冠亭後冷如水，舊氈半是蛛絲縈。", "恩袍謾官直齋老，書院誤身吟院兄。", "鳳樓好手乃有弟，鐵聲錚錚亦妙器。", "鄉里浪傳輕薄名，兒曹豈知渠大意。", "惠子五車稷下困，仲連一箭聊城至。", "博懸於投呼得盧，莫以蔡齊故第二。", "聖朝新數中興年，進士蛻骨秋風蟬。", "梅花魁春導人去，竹葉鏖寒澆客眠。", "天方坐我茅三椽，留眼送爾宜鴻前。", "因行西湖叫和靖，爲言詩苦剩狂顛。"]'),
('0c330af1-ef5a-4dfe-a684-995395ea736e','句  其一','蕭崱','宋','宋诗','song-poetry','','[]','粗花染春日曬紅，細綿披夏雪輥風。',32,'全唐诗/poet.song.216000.json','["粗花染春日曬紅，細綿披夏雪輥風。", "赤皇世界嶺皆熱，敕旨徵綿底癡絕。"]'),
('bab626d3-543d-43fe-b46a-90cd3065ada4','句  其二','蕭崱','宋','宋诗','song-poetry','','[]','得謗何須囊薏苡，工騷且自製芙蓉。',16,'全唐诗/poet.song.216000.json','["得謗何須囊薏苡，工騷且自製芙蓉。"]'),
('235a89e9-7409-4290-acaf-f8d0867e10a4','句  其三','蕭崱','宋','宋诗','song-poetry','','[]','此去三千歲，應逢八字蟾。',12,'全唐诗/poet.song.216000.json','["此去三千歲，應逢八字蟾。"]'),
('f720d157-a805-4c35-a6ea-a268479b7cd1','亭坐','蕭泰來','宋','宋诗','song-poetry','','[]','公餘終日坐閒亭，看得梅開梅葉青。',32,'全唐诗/poet.song.216000.json','["公餘終日坐閒亭，看得梅開梅葉青。", "可是近來疎酒盞，酒瓶今已作花瓶。"]'),
('f81a949c-53c6-4650-9450-9bbc77bd1a93','題梅壇毛慶甫雲悅樓二首  其一','蕭泰來','宋','宋诗','song-poetry','','[]','樓立梅峯最上頭，日隨元氣與浮游。',32,'全唐诗/poet.song.216000.json','["樓立梅峯最上頭，日隨元氣與浮游。", "道心快活雲心似，飛去飛來得自由。"]'),
('8a3d3efd-aab0-49aa-85b6-21a9fb7133da','題梅壇毛慶甫雲悅樓二首  其二','蕭泰來','宋','宋诗','song-poetry','','[]','一收二百里間雲，詩几琴窗總向君。',32,'全唐诗/poet.song.216000.json','["一收二百里間雲，詩几琴窗總向君。", "獨樂何如同樂好，闌子欠著老夫分。"]'),
('241e346d-7654-4574-9069-180bebc33bfe','贈星學張月臺','蕭泰來','宋','宋诗','song-poetry','','[]','富與貴在天，君子不謂性。',48,'全唐诗/poet.song.216000.json','["富與貴在天，君子不謂性。", "賢不肖在人，君子不謂命。", "是以張月臺，可疑亦可信。", "修身以俟之，人定天亦定。"]'),
('76a62536-0b68-4afe-aa2c-811e0d629928','臘祭謁告','蕭泰來','宋','宋诗','song-poetry','','[]','祠臘紛紛受誓忙，病夫藥鼎對書床。',64,'全唐诗/poet.song.216000.json','["祠臘紛紛受誓忙，病夫藥鼎對書床。", "官卑豈願乘肥馬，食儉惟知取瘦羊。", "貧見客來偏快活，老逢歲盡却悲傷。", "雪寒一事關心切，癡女奔波道路長。"]'),
('9b5d7184-f833-4965-98a1-bdeb4b537f95','覓竹栽謝','蕭泰來','宋','宋诗','song-poetry','','[]','一日非君不可無，當鄰乞得種魚都。',64,'全唐诗/poet.song.216000.json','["一日非君不可無，當鄰乞得種魚都。", "珠連呈舍排成次，玉立雲臺畫出圖。", "淇奧每思文事業，渭川肯作富規模。", "自鋤月地分行列，準擬清風十萬夫。"]'),
('907bf02f-3cbb-4234-a849-e0a17e49ed54','壽友人','蕭泰來','宋','宋诗','song-poetry','','[]','休運珍符應半千，崧高維嶽再生賢。',64,'全唐诗/poet.song.216000.json','["休運珍符應半千，崧高維嶽再生賢。", "子孫已見鍾三秀，富貴端應擅兩全。", "日月休驚雙轉轂，甲庚從喜一周天。", "不須更把莊椿祝，鎮作蓬壺不老仙。"]'),
('d5ae5eb1-2167-4937-a445-4c4b844410a6','題淵明祠','蕭泰來','宋','宋诗','song-poetry','','[]','地號古柴桑，荒祠驛道傍。',48,'全唐诗/poet.song.216000.json','["地號古柴桑，荒祠驛道傍。", "松含義熙節，菊带晉時香。", "拂石看碑記，斟泉當酒觴。", "無由歸未得，稽首意皇皇。"]');
